# ── Logging ───────────────────────────────────────────────────────────────────
# Fehler werden geloggt: Windows: neben der stock_monitor.exe
#                        Linux:   neben stock_monitor.py
# Es werden KEINE persönlichen Daten, Portfolio-Inhalte oder Passwörter geloggt —
# ausschliesslich technische Fehlermeldungen (Tracebacks) und App-Ereignisse.
import logging as _logging
import logging.handlers as _logging_handlers

def _setup_logging():
    # Logdatei immer neben der App-Datei – auf beiden Plattformen konsistent:
    # Windows (EXE): neben der stock_monitor.exe (portabel, egal wo der Ordner liegt)
    # Linux:         neben stock_monitor.py
    if sys.platform == "win32":
        _log_dir = os.path.dirname(sys.executable)
    elif os.environ.get("FLATPAK_ID"):
        # Im Flatpak-Sandbox ist /app schreibgeschützt → XDG_CACHE_HOME nutzen
        _log_dir = os.path.join(
            os.environ.get("XDG_CACHE_HOME", os.path.expanduser("~/.cache")),
            "stock-monitor"
        )
    else:
        _log_dir = os.path.dirname(os.path.abspath(__file__))
    os.makedirs(_log_dir, exist_ok=True)
    _log_path = os.path.join(_log_dir, "stock_monitor.log")
    _logger = _logging.getLogger("StockMonitor")
    _logger.setLevel(_logging.DEBUG)
    if not _logger.handlers:
        # RotatingFileHandler: max 2 MB, 3 Backup-Dateien → nie mehr als ~8 MB
        _fh = _logging_handlers.RotatingFileHandler(
            _log_path, maxBytes=2*1024*1024, backupCount=3, encoding="utf-8"
        )
        _fh.setLevel(_logging.DEBUG)
        _fh.setFormatter(_logging.Formatter(
            "%(asctime)s  %(levelname)-8s  %(message)s",
            datefmt="%Y-%m-%d %H:%M:%S"
        ))
        _logger.addHandler(_fh)
    return _logger, _log_path

_log, _LOG_PATH = _setup_logging()
_log.info(f"Stock Monitor gestartet  |  Python {sys.version.split()[0]}  |  PID {os.getpid()}")
_LOG_ERROR_SHOWN = False  # Flag: Hinweis auf Logdatei nur einmal pro Session zeigen

# ── Globaler Exception-Handler ─────────────────────────────────────────────
# PyQt6 (>= 6.x) ruft QMessageLogger::fatal() wenn eine Python-Exception
# aus einem Slot propagiert – das führt zu SIGABRT.
# Dieser Handler fängt ALLE unbehandelten Exceptions ab und zeigt sie
# als Dialog, anstatt die App zu crashen.

def _show_error_in_main_thread(title, text, detail):
    """Zeigt einen Fehler-Dialog sicher im Hauptthread (auch wenn aus einem QThread aufgerufen)."""
    try:
        from PyQt6.QtWidgets import QApplication, QMessageBox
        from PyQt6.QtCore import QThread, Qt
        app = QApplication.instance()
        if app is None:
            return
        # Prüfen ob wir im Hauptthread sind
        if QThread.currentThread() is app.thread():
            # Direkt zeigen – wir sind im Hauptthread
            msg = QMessageBox()
            msg.setIcon(QMessageBox.Icon.Critical)
            msg.setWindowTitle(title)
            msg.setText(text)
            if detail:
                msg.setDetailedText(detail)
            msg.setStandardButtons(QMessageBox.StandardButton.Ok)
            msg.exec()
        else:
            # Aus einem Background-Thread: nur auf stderr loggen.
            # QMessageBox aus Threads ist der Crash-Grund (SIGSEGV in Wayland-Backend).
            print(f"[THREAD ERROR] {title}: {text}\n{detail}", file=sys.stderr)
    except Exception:
        pass


def _global_exception_handler(exc_type, exc_value, exc_tb):
    """Zeigt unbehandelte Exceptions als Dialog statt Crash."""
    if issubclass(exc_type, KeyboardInterrupt):
        sys.__excepthook__(exc_type, exc_value, exc_tb)
        return
    tb_str = "".join(traceback.format_exception(exc_type, exc_value, exc_tb))
    print(f"[UNHANDLED EXCEPTION]\n{tb_str}", file=sys.stderr)
    _log.error(f"Unbehandelte Exception: {exc_type.__name__}: {exc_value}\n{tb_str}")
    _show_error_in_main_thread(
        "Fehler – Unbehandelte Exception",
        f"<b>{exc_type.__name__}:</b> {exc_value}",
        tb_str
    )
    _show_log_hint()

sys.excepthook = _global_exception_handler

def _show_log_hint():
    """Zeigt nach einem Fehler einmalig pro Session einen dezenten Hinweis auf die Logdatei."""
    global _LOG_ERROR_SHOWN
    if _LOG_ERROR_SHOWN:
        return
    _LOG_ERROR_SHOWN = True
    try:
        from PyQt6.QtWidgets import QApplication, QMessageBox
        app = QApplication.instance()
        if app is None:
            return
        msg = QMessageBox()
        msg.setWindowTitle("📋 Fehler protokolliert")
        msg.setIcon(QMessageBox.Icon.Information)
        msg.setText("Der Fehler wurde automatisch protokolliert.")
        msg.setInformativeText(
            "Falls du den Fehler melden möchtest, schicke einfach die Logdatei mit:<br><br>"
            f"<code>{_LOG_PATH}</code>"
        )
        open_btn = msg.addButton("Ordner öffnen", QMessageBox.ButtonRole.ActionRole)
        msg.addButton(QMessageBox.StandardButton.Ok)
        msg.exec()
        if msg.clickedButton() == open_btn:
            import subprocess
            subprocess.Popen(["xdg-open", os.path.dirname(_LOG_PATH)])
    except Exception:
        pass

# Für PyQt6: Exception-Hook auch in Qt-Slots aktiv machen
# PyQt6 ignoriert sys.excepthook in Slots – stattdessen müssen wir
# QApplication.notify() überschreiben (geschieht in StockMonitorApp.__init__)


def safe_slot(func):
    """Decorator: Fängt alle Exceptions in Qt-Slots auf und zeigt sie als Dialog.
    
    Schluckt das optionale bool-Argument das Qt bei clicked()-Signalen mitsendet.
    """
    import functools
    import inspect
    _nparams = len(inspect.signature(func).parameters)  # inkl. 'self'
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Qt clicked() sendet ein bool als extra Argument – wegwerfen wenn Methode
        # nur 'self' erwartet (nparams == 1)
        if _nparams == 1 and len(args) > 1:
            args = args[:1]
        try:
            return func(*args, **kwargs)
        except Exception as e:
            tb_str = traceback.format_exc()
            print(f"[SLOT ERROR] {func.__name__}: {e}\n{tb_str}", file=sys.stderr)
            _log.error(f"Slot-Fehler in {func.__name__}: {type(e).__name__}: {e}\n{tb_str}")
            _show_error_in_main_thread(
                f"Fehler in {func.__name__}",
                f"<b>{type(e).__name__}:</b> {e}",
                tb_str
            )
            _show_log_hint()
    return wrapper


