# Schnelle Lookup: sector-string (wie Yahoo ihn liefert) → kanonischer Name
_SECTOR_ALIASES = {
    'Energy': 'Energy',
    'Materials': 'Materials', 'Basic Materials': 'Materials',
    'Industrials': 'Industrials',
    'Consumer Discretionary': 'Consumer Cyclical', 'Consumer Cyclical': 'Consumer Cyclical',
    'Consumer Staples': 'Consumer Defensive', 'Consumer Defensive': 'Consumer Defensive',
    'Health Care': 'Healthcare', 'Healthcare': 'Healthcare',
    'Financials': 'Financial Services', 'Financial Services': 'Financial Services',
    'Information Technology': 'Technology', 'Technology': 'Technology',
    'Communication Services': 'Communication Services',
    'Utilities': 'Utilities',
    'Real Estate': 'Real Estate',
}

def _gics_lookup(sector: str, industry: str) -> tuple:
    """Gibt (sector, industry_group, sub_industry) zurück – alle englisch, offizielle GICS-Namen."""
    canonical_sector = _SECTOR_ALIASES.get(sector, sector) if sector else ''
    if industry and industry in _GICS_HIERARCHY:
        s, ig, si = _GICS_HIERARCHY[industry]
        return (canonical_sector or s, ig, industry, si)
    # Fallback: nur Sektor bekannt
    return (canonical_sector, '', industry, '')

def _gics(text):
    """Legacy-Kompatibilität – gibt englischen Sektornamen zurück."""
    if not text:
        return '–'
    return _SECTOR_ALIASES.get(text, text)


# ── Zahlenformat-Einstellung (global, umschaltbar) ───────────────────────
# "CH" = Schweizer Apostroph  35'969.57
# "DE" = Deutsch Punkt+Komma  35.969,57
# "US" = US Komma+Punkt       35,969.57
try:
    from config import get_number_format as _get_nf
    _NUMBER_FORMAT = _get_nf()
except Exception:
    _NUMBER_FORMAT = "CH"

def _fmt(value, decimals=2):
    """Zahlenformatierung – richtet sich nach _NUMBER_FORMAT (CH/DE/US)."""
    fmt = globals().get('_NUMBER_FORMAT', 'CH')
    formatted = f"{abs(value):,.{decimals}f}"   # US-Basis: 35,969.57
    if fmt == "CH":
        formatted = formatted.replace(',', "'")             # 35'969.57
    elif fmt == "DE":
        formatted = formatted.replace(',', 'X').replace('.', ',').replace('X', '.')  # 35.969,57
    # US: unverändert                                         # 35,969.57
    return f"-{formatted}" if value < 0 else formatted

# Rohstoff-Symbole (XAU = Gold, XAG = Silber, XPT = Platin, XPD = Palladium, XCU = Kupfer)
_COMMODITY_SYMBOLS = {'XAU', 'XAG', 'XPT', 'XPD', 'XCU'}

def _is_commodity(sym: str) -> bool:
    """Gibt True zurück wenn Symbol ein Rohstoff (Edelmetall/Kupfer) ist."""
    return sym.upper() in _COMMODITY_SYMBOLS

# Yahoo Finance Ticker-Map für Rohstoffe (Spot-Kurs via Forex-Feed, Fallback Futures)
_COMMODITY_YAHOO = {
    'XAU': ('XAUUSD=X', 'GC=F'),   # Gold Spot, Fallback Gold Futures
    'XAG': ('XAGUSD=X', 'SI=F'),   # Silber Spot, Fallback Silber Futures
    'XPT': ('XPTUSD=X', 'PL=F'),   # Platin Spot, Fallback Platin Futures
    'XPD': ('XPDUSD=X', 'PA=F'),   # Palladium Spot, Fallback Palladium Futures
    'XCU': ('HG=F',     'HG=F'),   # Kupfer Futures (kein Spot-Feed verfügbar)
}

# ── Dividend Kings / Aristocrats – aus dividend_lists.json laden ──────────────
# Die JSON-Datei liegt neben stock_monitor.py und kann ohne Code-Änderung
# aktualisiert werden. Fallback auf leere Sets falls Datei fehlt.
def _load_dividend_lists():
    import json as _json
    try:
        _here = os.path.dirname(os.path.abspath(__file__))
        _path = os.path.join(_here, 'dividend_lists.json')
        with open(_path, 'r', encoding='utf-8') as _f:
            _data = _json.load(_f)
        _kings = set(_data.get('kings', []))
        _arist = set(_data.get('aristocrats', [])) | _kings
        return _kings, _arist
    except Exception:
        return set(), set()

_DIVIDEND_KINGS, _DIVIDEND_ARISTOCRATS = _load_dividend_lists()

def _get_dividend_category(symbol: str, max_consec: int):
    """
    Gibt (label_key, farbe) zurück.
    Prüft zuerst die Listen aus dividend_lists.json, dann den gemessenen
    max_consec-Wert aus den verfügbaren Yahoo-Daten als Fallback.
    Symbol kann Exchange-Suffix haben (z.B. NESN.SW) – wird entfernt.
    """
    base = symbol.split('.')[0].upper()
    if base in _DIVIDEND_KINGS:
        return ('div_king_50',        '#8B6914')
    if base in _DIVIDEND_ARISTOCRATS:
        return ('div_aristocrat_king', '#1a6b99')
    if max_consec >= 25: return ('div_aristocrat_king', '#1a6b99')
    if max_consec >= 10: return ('div_aristocrat_10',   '#1a7a3c')
    if max_consec >=  5: return ('div_aristocrat_5',    '#27ae60')
    return ('div_no_growth', '#7f8c8d')


