class PortfolioWorker(QThread):
    """Lädt alle Portfolio-Kurse + FX-Rates im Hintergrund"""
    progress   = pyqtSignal(int, int, str)
    # {symbol: (price, currency, price_usd)}  price_usd = in USD umgerechnet
    data_ready = pyqtSignal(dict)

    # FX-Paare für Yahoo Finance + ob der Kurs invertiert werden muss
    # Yahoo XXX=X  → gibt USD/XXX  → braucht 1/rate  (JPY=X, KRW=X, HKD=X...)
    # Yahoo XXXUSD=X → gibt XXX/USD → direkt nutzbar  (EURUSD=X, CHFUSD=X...)
    _FX_PAIRS = {
        'JPY': ('JPY=X',    True),   # USD/JPY → invert
        'KRW': ('KRW=X',    True),   # USD/KRW → invert
        'HKD': ('HKD=X',    True),   # USD/HKD → invert
        'EUR': ('EURUSD=X', False),  # EUR/USD → direkt
        'CHF': ('CHFUSD=X', False),  # CHF/USD → direkt
        'GBP': ('GBPUSD=X', False),  # GBP/USD → direkt
        'GBp': ('GBPUSD=X', False),  # Pence   → direkt (÷100 später)
        'CAD': ('CADUSD=X', False),
        'AUD': ('AUDUSD=X', False),
        'SEK': ('SEKUSD=X', False),
        'NOK': ('NOKUSD=X', False),
        'DKK': ('DKKUSD=X', False),
        'SGD': ('SGDUSD=X', False),
        'TWD': ('TWD=X', True),
        'CNY': ('CNYUSD=X', False),
    }

    def __init__(self, portfolio_data, parent=None):
        super().__init__(parent)
        self._symbols   = list(portfolio_data.keys())
        self._port_data = portfolio_data

    def _get_fx_to_usd(self, currency, fx_cache):
        """Gibt den Faktor currency→USD zurück (cached). Korrekte Yahoo-Logik."""
        if currency in ('USD', ''):
            return 1.0
        if currency in fx_cache:
            return fx_cache[currency]
        entry = self._FX_PAIRS.get(currency)
        if not entry:
            fx_cache[currency] = 1.0
            return 1.0
        pair, invert = entry
        try:
            rate = float(yf.Ticker(pair).fast_info.last_price)
            if invert:
                rate = 1.0 / rate if rate > 0 else 1.0  # USD/XXX → XXX/USD
            if currency == 'GBp':
                rate = rate / 100  # Pence → Pounds
            fx_cache[currency] = rate
        except Exception:
            fx_cache[currency] = 1.0
        return fx_cache[currency]

    def run(self):
        import yfinance as yf
        results  = {}
        fx_cache = {}

        # Symbole aufteilen: echte Aktien vs FX-Paare vs Rohstoffe
        real_syms      = [s for s in self._symbols if '=' not in s and not _is_commodity(s)]
        commodity_syms = [s for s in self._symbols if _is_commodity(s)]
        for s in self._symbols:
            if '=' in s:
                results[s] = {'price': None, 'cur': 'FX', 'price_usd': None,
                              'qty': 0, 'cost_usd': 0, 'value_usd': 0}

        # ── Rohstoff-Kurse (XAU/XAG) via Spot-Feed, Fallback Futures ────
        for sym in commodity_syms:
            primary, fallback = _COMMODITY_YAHOO.get(sym.upper(), ('XAUUSD=X', 'GC=F'))
            positions = self._port_data.get(sym, [])
            total_qty = sum(p['quantity'] for p in positions)
            price = None
            for ticker_sym in (primary, fallback):
                try:
                    t = yf.Ticker(ticker_sym)
                    fi = t.fast_info
                    # Forex-Tickers (=X) liefern last_price, Futures (=F) auch
                    for attr in ('last_price', 'lastPrice', 'regularMarketPrice'):
                        v = getattr(fi, attr, None)
                        if v is None and hasattr(fi, 'get'):
                            v = fi.get(attr)
                        if v and float(v) > 0:
                            price = float(v); break
                    if price and price > 0:
                        break
                    # Fallback: history
                    h = t.history(period='2d')
                    if not h.empty:
                        price = float(h['Close'].iloc[-1]); break
                except Exception:
                    continue
            if price and price > 0:
                cost_usd  = sum(p['buy_price'] * p['quantity'] for p in positions)
                value_usd = price * total_qty
                results[sym] = {
                    'price': price, 'cur': 'USD', 'price_usd': price,
                    'qty': total_qty, 'cost_usd': cost_usd, 'value_usd': value_usd,
                }
            else:
                results[sym] = {
                    'price': None, 'cur': 'USD', 'price_usd': None,
                    'qty': total_qty, 'cost_usd': 0, 'value_usd': 0,
                }

        # ── Batch-Download: alle Kurse in EINEM Request ──────────────
        # Deutlich schneller als einzelne fast_info-Calls pro Symbol
        price_map = {}
        if real_syms:
            try:
                self.progress.emit(0, len(real_syms), "Batch-Download…")
                dl = yf.download(
                    real_syms,
                    period='2d',
                    auto_adjust=True,
                    progress=False,
                    threads=True,
                )
                # dl.Close: MultiIndex wenn mehrere Symbole, Series wenn einer
                import pandas as pd
                closes = dl['Close'] if 'Close' in dl.columns else dl
                if isinstance(closes, pd.Series):
                    closes = closes.to_frame(name=real_syms[0])
                for sym in real_syms:
                    if sym in closes.columns:
                        col = closes[sym].dropna()
                        if not col.empty:
                            price_map[sym] = float(col.iloc[-1])
            except Exception:
                pass  # Fallback: einzelne Calls unten

        # ── Währung pro Symbol (fast_info, nur wenn Batch fehlschlug) ─
        cur_cache = {}
        for sym in real_syms:
            try:
                fi = yf.Ticker(sym).fast_info
                cur_cache[sym] = getattr(fi, 'currency', 'USD') or 'USD'
                # Wenn Batch keinen Preis lieferte: Fallback auf fast_info
                if sym not in price_map:
                    price_map[sym] = float(fi.last_price)
            except Exception:
                cur_cache[sym] = 'USD'

        # ── Ergebnisse zusammenbauen ──────────────────────────────────
        total = len(real_syms)
        for i, symbol in enumerate(real_syms):
            self.progress.emit(i + 1, total, symbol)
            positions  = self._port_data.get(symbol, [])
            total_qty  = sum(p['quantity'] for p in positions)
            price      = price_map.get(symbol)
            cur        = cur_cache.get(symbol, 'USD')
            if price is not None:
                fx        = self._get_fx_to_usd(cur, fx_cache)
                price_usd = price * fx
                cost_local = sum(p['buy_price'] * p['quantity'] for p in positions)
                cost_usd   = cost_local * fx
                value_usd  = price_usd * total_qty
                results[symbol] = {
                    'price': price, 'cur': cur, 'price_usd': price_usd,
                    'qty': total_qty, 'cost_usd': cost_usd, 'value_usd': value_usd,
                }
            else:
                results[symbol] = {
                    'price': None, 'cur': cur, 'price_usd': None,
                    'qty': total_qty, 'cost_usd': 0, 'value_usd': 0,
                }
        self.data_ready.emit(results)

