class UrlFinderThread(QThread):
    """Prüft Finment-URLs per HTTP und meldet die erste funktionierende"""
    url_found = pyqtSignal(str)

    def __init__(self, urls):
        super().__init__()
        self.urls = urls

    def run(self):
        import urllib.request, urllib.error
        for url in self.urls[:-1]:
            try:
                req = urllib.request.Request(url, method='HEAD')
                req.add_header('User-Agent', 'Mozilla/5.0')
                with urllib.request.urlopen(req, timeout=3) as resp:
                    if resp.status == 200:
                        self.url_found.emit(url)
                        return
            except Exception:
                continue
        self.url_found.emit(self.urls[-1])


class AnalysisWindow(QDialog):
    """Fenster zur Anzeige von Aktienanalysen"""

    def __init__(self, symbol, company_name, analysis_type, parent=None):
        super().__init__(parent)
        self.symbol = symbol
        self.company_name = company_name
        self.analysis_type = "Finment"
        self._url_thread = None
        self.current_url = None
        self.remaining_urls = []

        self.setWindowTitle(f"Finment Analyse - {symbol}")

        if _WEBENGINE_AVAILABLE:
            self.setMinimumSize(1200, 800)
            self._setup_webengine_ui()
        else:
            self.setFixedSize(500, 200)
            self._setup_browser_ui()

        self.load_analysis()

    def _setup_webengine_ui(self):
        layout = QVBoxLayout()
        header = QHBoxLayout()
        info_label = QLabel(f"<b>{self.symbol}</b> {self.company_name}")
        info_label.setFont(QFont("Arial", 12))
        header.addWidget(info_label)
        header.addStretch()
        refresh_btn = QPushButton(TR("btn_reload"))
        refresh_btn.clicked.connect(self.load_analysis)
        header.addWidget(refresh_btn)
        browser_btn = QPushButton(TR("btn_open_browser"))
        browser_btn.clicked.connect(self.open_in_browser)
        header.addWidget(browser_btn)
        close_btn = QPushButton(TR("btn_close"))
        close_btn.setAutoDefault(False)
        close_btn.clicked.connect(self.close)
        header.addWidget(close_btn)
        layout.addLayout(header)
        self.status_label = QLabel(TR("status_finment_search"))
        layout.addWidget(self.status_label)
        self.web_view = QWebEngineView()
        self.web_page = CustomWebPage(self.web_view)
        self.web_view.setPage(self.web_page)
        self.web_page.page_loaded.connect(self.on_page_loaded)
        layout.addWidget(self.web_view)
        self.setLayout(layout)

    def _setup_browser_ui(self):
        layout = QVBoxLayout()
        layout.setSpacing(12)
        layout.setContentsMargins(24, 20, 24, 20)
        title = QLabel(f"<b>Finment Analyse</b> – {self.symbol} {self.company_name}")
        title.setFont(QFont("Arial", 11))
        layout.addWidget(title)
        self.status_label = QLabel("🔍 " + TR("status_finment_search"))
        self.status_label.setStyleSheet("color: #555; font-size: 12px;")
        layout.addWidget(self.status_label)
        layout.addStretch()
        btn_row = QHBoxLayout()
        btn_row.addStretch()
        close_btn = QPushButton(TR("btn_close"))
        close_btn.setAutoDefault(False)
        close_btn.clicked.connect(self.close)
        btn_row.addWidget(close_btn)
        layout.addLayout(btn_row)
        self.setLayout(layout)

    def get_analysis_urls(self):
        urls = []
        categories = ['tech-aktien', 'us-aktien', 'deutsche-aktien', 'schweizer-aktien', 'europaische-aktien']
        name_variants = []
        symbol_clean = self.symbol.lower().replace('.sw', '').replace('.de', '').replace('.f', '')
        name_variants.append(symbol_clean)
        if self.company_name:
            clean_name = self.company_name.lower()
            for suffix in [' inc.', ' inc', ' corp.', ' corp', ' corporation',
                           ' ag', ' plc', ' ltd', ' limited']:
                clean_name = clean_name.replace(suffix, '')
            clean_name = clean_name.replace(',', '').replace('.', '').strip()
            name_variants.append(clean_name.replace(' ', '-'))
            first_word = clean_name.split()[0] if clean_name.split() else clean_name
            if first_word and first_word != clean_name:
                name_variants.append(first_word)
        for category in categories:
            for name in name_variants:
                urls.append(f"https://finment.com/boerse-aktien/{category}/{name}-aktie-prognose/")
        urls.append(f"https://finment.com/?s={urllib.parse.quote(self.symbol)}")
        return urls

    def load_analysis(self):
        self.status_label.setText(TR("status_finment_search"))
        urls = self.get_analysis_urls()
        if not urls:
            self.status_label.setText(TR("lbl_no_data"))
            return
        if _WEBENGINE_AVAILABLE:
            self.current_url = urls[0]
            self.remaining_urls = urls[1:]
            self.web_view.setUrl(QUrl(self.current_url))
        else:
            self.status_label.setText("🔍 " + TR("status_finment_search"))
            self._url_thread = UrlFinderThread(urls)
            self._url_thread.url_found.connect(self._on_url_found)
            self._url_thread.start()

    def _on_url_found(self, url):
        self.current_url = url
        self.status_label.setText("✅ " + TR("lbl_finment_opening_browser"))
        self.open_in_browser()
        QTimer.singleShot(1500, self.close)

    def on_page_loaded(self, success):
        if not _WEBENGINE_AVAILABLE:
            return
        if success:
            self.status_label.setText(TR("status_finment_loaded"))
        else:
            if self.remaining_urls:
                self.current_url = self.remaining_urls.pop(0)
                self.status_label.setText(TR("status_finment_retry"))
                self.web_view.setUrl(QUrl(self.current_url))
            else:
                self.status_label.setText(TR("status_finment_none", symbol=self.symbol))
                error_html = f"""
                <html>
                <body style="font-family: Arial; padding: 40px; text-align: center;">
                    <h1>❌ Analyse nicht gefunden</h1>
                    <p>Für <b>{self.symbol}</b> ({self.company_name}) konnte keine Finment-Analyse gefunden werden.</p>
                    <p style="margin-top: 30px;">
                        <a href="https://www.google.com/search?q={urllib.parse.quote(f'{self.symbol} Finment Analyse')}"
                           target="_blank" style="font-size: 18px;">🔍 Bei Google suchen</a>
                    </p>
                </body>
                </html>
                """
                self.web_view.setHtml(error_html)

    def open_in_browser(self):
        if self.current_url:
            import os, subprocess
            if os.path.exists('/.flatpak-info'):
                subprocess.Popen(['flatpak-spawn', '--host', 'xdg-open', self.current_url])
            else:
                webbrowser.open(self.current_url)


class AnalystInfoDialog(QDialog):
    """Dialog mit Analysten-Ampel, AI-Einschätzung und Fundamentaldaten"""
    
    def __init__(self, symbol, company_name, num_analysts, recommendation, target_price, current_price, 
                 pe_ratio=None, forward_pe=None, week_52_high=None, week_52_low=None, avg_volume=None, currency='USD', parent=None):
        super().__init__(parent)
        self.symbol = symbol
        self.company_name = company_name
        self.num_analysts = num_analysts
        self.recommendation = recommendation
        self.target_price = target_price
        self.current_price = current_price
        self.pe_ratio = pe_ratio
        self.forward_pe = forward_pe
        self.week_52_high = week_52_high
        self.week_52_low = week_52_low
        self.avg_volume = avg_volume
        
        # Währungssymbol
        self.currency_symbol = {
            'USD': '$', 'EUR': '€', 'CHF': 'CHF ', 'GBP': '£', 
            'JPY': '¥', 'CNY': '¥', 'CAD': 'C$', 'AUD': 'A$',
            'KRW': '₩'  # Koreanische Won!
        }.get(currency, currency + ' ')
        
        self.setWindowTitle(f"📊 {TR('title_analyst_info')} - {symbol}")
        
        # Passe Größe an Bildschirm an
        screen = QApplication.primaryScreen().geometry()
        screen_height = screen.height()
        
        if screen_height <= 1080:  # Full HD oder kleiner
            self.setMinimumSize(600, 650)  # Kompakt für Full HD
            self.setMaximumHeight(screen_height - 100)  # Nie größer als Bildschirm
            self.use_scroll = True  # ScrollArea aktivieren
        else:  # 4K oder größer
            self.setMinimumSize(650, 900)  # Größer für 4K - kein Scroll nötig
            self.use_scroll = False  # Kein Scroll bei 4K
        
        self.setup_ui()
    
    def setup_ui(self):
        main_layout = QVBoxLayout()
        
        # Header (immer außerhalb)
        header = QLabel(f"<h2>{self.symbol}</h2><p>{self.company_name}</p>")
        header.setAlignment(Qt.AlignmentFlag.AlignCenter)
        main_layout.addWidget(header)
        
        # Content Widget (mit oder ohne ScrollArea je nach Auflösung)
        if self.use_scroll:  # Full HD - mit ScrollArea
            scroll = QScrollArea()
            scroll.setWidgetResizable(True)
            scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
            
            content_widget = QWidget()
            layout = QVBoxLayout(content_widget)
        else:  # 4K - direkt im Layout
            layout = QVBoxLayout()
        
        # Analysten-Info
        if self.num_analysts > 0:
            analyst_label = QLabel(f"<b>{self.num_analysts} {TR('lbl_analysts_watching')}</b>")
        else:
            analyst_label = QLabel(TR("lbl_no_analyst_data"))
        analyst_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        analyst_label.setFont(QFont("Arial", 12))
        layout.addWidget(analyst_label)
        
        layout.addSpacing(20)
        
        # AMPEL mit 5 Lichtern
        ampel_widget = QWidget()
        ampel_layout = QVBoxLayout()
        ampel_layout.setSpacing(12)
        ampel_layout.setContentsMargins(30, 20, 30, 20)
        
        # Mapping: recommendation -> Licht-Index (0=unten rot, 4=oben hellgrün)
        rec_to_light = {
            'strong_buy': 4,
            'buy': 3,
            'hold': 2,
            'sell': 1,
            'strong_sell': 0,
            'none': 2  # Default: hold
        }
        
        active_light = rec_to_light.get(self.recommendation, 2)
        
        # 5 Lichter von oben nach unten
        lights = [
            (4, '#00FF00', TR('rating_strong_buy')),  # Hellgrün
            (3, '#00AA00', TR('rating_buy')),        # Grün
            (2, '#FFAA00', TR('rating_hold')),        # Gelb
            (1, '#FF0000', TR('rating_sell')),     # Rot
            (0, '#AA0000', TR('rating_strong_sell')) # Dunkelrot
        ]
        
        for idx, color, text in lights:
            light_container = QWidget()
            light_container.setMinimumHeight(60)  # Genug Platz für Kreis
            light_layout = QHBoxLayout(light_container)
            light_layout.setContentsMargins(0, 0, 0, 0)
            
            # Licht (Kreis)
            light_label = QLabel("●")
            light_label.setMinimumSize(60, 60)  # Mindestgröße für runde Darstellung
            if idx == active_light:
                light_label.setStyleSheet(f"font-size: 42px; color: {color};")
            else:
                light_label.setStyleSheet("font-size: 42px; color: #333333;")
            light_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            light_layout.addWidget(light_label)
            
            # Text
            text_label = QLabel(text)
            text_label.setFont(QFont("Arial", 11, QFont.Weight.Bold))
            if idx == active_light:
                text_label.setStyleSheet(f"color: {color};")
            else:
                text_label.setStyleSheet("color: #888888;")
            text_label.setAlignment(Qt.AlignmentFlag.AlignVCenter)
            light_layout.addWidget(text_label)
            
            light_layout.addStretch()
            ampel_layout.addWidget(light_container)
        
        ampel_widget.setLayout(ampel_layout)
        layout.addWidget(ampel_widget)
        
        layout.addSpacing(20)
        
        # Zielkurs-Info mit richtiger Währung
        if self.target_price and self.current_price:
            potential = ((self.target_price - self.current_price) / self.current_price) * 100
            target_label = QLabel(f"<b>{TR('lbl_target_price_colon')}</b> {self.currency_symbol}{self.target_price:.2f} ({potential:+.1f}%)")
            target_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            layout.addWidget(target_label)
        
        layout.addSpacing(15)
        
        # Fundamentaldaten-Box
        fundamentals_box = QFrame()
        fundamentals_box.setFrameStyle(QFrame.Shape.Box)
        fundamentals_box.setStyleSheet("background-color: #e8f4f8; border: 1px solid #3498db;")  # KEIN padding hier!
        fund_layout = QVBoxLayout()
        fund_layout.setSpacing(5)
        fund_layout.setContentsMargins(15, 15, 15, 15)  # Padding im Layout statt Stylesheet
        
        fund_title = QLabel(f"<b>📈 {TR('lbl_fundamentals')}</b>")
        fund_title.setFont(QFont("Arial", 12, QFont.Weight.Bold))
        fund_title.setAlignment(Qt.AlignmentFlag.AlignCenter)
        fund_layout.addWidget(fund_title)
        
        fund_layout.addSpacing(10)
        
        # Einfache Zeilen statt Grid
        # KGV (P/E Ratio)
        if self.pe_ratio:
            row_layout = QHBoxLayout()
            
            label = QLabel(f"<b>{TR('lbl_pe_ratio')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            
            pe_color = "green" if self.pe_ratio < 20 else "orange" if self.pe_ratio < 30 else "red"
            value = QLabel(f"<span style='color:{pe_color}'>{self.pe_ratio:.2f}</span>")
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        else:
            # KGV fehlt - Hinweis geben (oft bei Verlust)
            row_layout = QHBoxLayout()
            label = QLabel(f"<b>{TR('lbl_pe_ratio')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            value = QLabel(TR("lbl_na_negative_earnings"))
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            fund_layout.addLayout(row_layout)
        
        # Forward KGV
        if self.forward_pe:
            row_layout = QHBoxLayout()
            
            label = QLabel(f"<b>{TR('lbl_forward_pe')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            
            fpe_color = "green" if self.forward_pe < 20 else "orange" if self.forward_pe < 30 else "red"
            value = QLabel(f"<span style='color:{fpe_color}'>{self.forward_pe:.2f}</span>")
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        else:
            # Forward KGV fehlt - Hinweis
            row_layout = QHBoxLayout()
            label = QLabel(f"<b>{TR('lbl_forward_pe')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            value = QLabel("<span style='color:gray'><i>N/A</i></span>")
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        
        # 52-Wochen-Hoch
        if self.week_52_high and self.current_price:
            row_layout = QHBoxLayout()
            
            label = QLabel(f"<b>{TR('col_w52h')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            
            distance_high = ((self.current_price - self.week_52_high) / self.week_52_high) * 100
            high_text = f"{self.currency_symbol}{self.week_52_high:.2f} ({distance_high:+.1f}% {TR('lbl_from_high')})"
            value = QLabel(high_text)
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        
        # 52-Wochen-Tief
        if self.week_52_low and self.current_price:
            row_layout = QHBoxLayout()
            
            label = QLabel(f"<b>{TR('col_w52l')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            
            distance_low = ((self.current_price - self.week_52_low) / self.week_52_low) * 100
            low_text = f"{self.currency_symbol}{self.week_52_low:.2f} ({distance_low:+.1f}% {TR('lbl_from_low')})"
            value = QLabel(low_text)
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        
        # Durchschnittliches Volumen
        if self.avg_volume:
            row_layout = QHBoxLayout()
            
            label = QLabel(f"<b>{TR('lbl_avg_volume')}</b>")
            label.setFont(QFont("Arial", 10))
            label.setMinimumWidth(120)
            row_layout.addWidget(label)
            
            if self.avg_volume >= 1000000:
                vol_text = f"{self.avg_volume / 1000000:.1f}M"
            elif self.avg_volume >= 1000:
                vol_text = f"{self.avg_volume / 1000:.1f}K"
            else:
                vol_text = f"{self.avg_volume:,.0f}"
            value = QLabel(vol_text)
            value.setFont(QFont("Arial", 10))
            row_layout.addWidget(value)
            row_layout.addStretch()
            
            fund_layout.addLayout(row_layout)
        
        fundamentals_box.setLayout(fund_layout)
        layout.addWidget(fundamentals_box)
        
        layout.addSpacing(10)
        
        # AI-Einschätzung (Claude's Meinung)
        ai_box = QFrame()
        ai_box.setFrameStyle(QFrame.Shape.Box)
        ai_box.setStyleSheet("background-color: #f0f0f0; padding: 10px;")
        ai_layout = QVBoxLayout()
        
        ai_title = QLabel(f"<b>🤖 {TR('lbl_claude_assessment')}</b>")
        ai_title.setFont(QFont("Arial", 11, QFont.Weight.Bold))
        ai_layout.addWidget(ai_title)
        
        ai_text = QLabel(self.get_ai_assessment())
        ai_text.setWordWrap(True)
        ai_text.setFont(QFont("Arial", 10))
        ai_layout.addWidget(ai_text)
        
        ai_disclaimer = QLabel(f"<i>{TR('lbl_disclaimer')}</i>")
        ai_disclaimer.setFont(QFont("Arial", 8))
        ai_disclaimer.setStyleSheet("color: #666666;")
        ai_layout.addWidget(ai_disclaimer)
        
        ai_box.setLayout(ai_layout)
        layout.addWidget(ai_box)
        
        layout.addStretch()
        
        # Buttons-Zeile (außerhalb ScrollArea - bleibt fixiert)
        button_layout = QHBoxLayout()
        
        # Emoji-Font für Buttons
        from PyQt6.QtGui import QFontDatabase
        _af = QFontDatabase.families()
        _ef = next((QFont(f, 10) for f in ['Segoe UI Emoji', 'Noto Color Emoji', 'Apple Color Emoji'] if f in _af), None)

        def _abtn(text, plain):
            b = QPushButton(text if _ef else plain)
            if _ef: b.setFont(_ef)
            return b

        # Firmeninfo Button
        company_btn = _abtn(f"🏢 {TR('btn_company_info')}", "Firmeninfo")
        company_btn.clicked.connect(self.show_company_info)
        button_layout.addWidget(company_btn)
        
        # Finanzdaten Button
        financial_btn = _abtn(f"📊 {TR('btn_financials')}", "Finanzdaten")
        financial_btn.clicked.connect(self.show_financial_data)
        button_layout.addWidget(financial_btn)

        # Dividenden Button
        div_btn = _abtn(f"💰 {TR('btn_dividend_history')}", TR("btn_dividend_history_plain"))
        div_btn.clicked.connect(self.show_dividend_history)
        button_layout.addWidget(div_btn)
        
        button_layout.addStretch()
        
        # Close Button
        close_btn = _abtn(TR("btn_close"), TR("btn_close_plain"))
        close_btn.clicked.connect(self.close)
        button_layout.addWidget(close_btn)
        
        # Layout zusammensetzen (unterschiedlich je nach use_scroll)
        if self.use_scroll:  # Full HD - mit ScrollArea
            scroll.setWidget(content_widget)
            main_layout.addWidget(scroll)
        else:  # 4K - direkt
            main_layout.addLayout(layout)
        
        # Buttons (immer außerhalb)
        main_layout.addLayout(button_layout)
        
        self.setLayout(main_layout)
    
    def show_financial_data(self):
        """Zeige detaillierte Finanzdaten in separatem Dialog"""
        dialog = FinancialDataDialog(self.symbol, self.company_name, self)
        dialog.exec()
    
    def show_company_info(self):
        """Zeige Firmeninformationen in separatem Dialog"""
        dialog = CompanyInfoDialog(self.symbol, self.company_name, self)
        dialog.exec()

    def show_dividend_history(self):
        """Zeige Dividendenhistorie der Aktie (10 Jahre + Prognose)"""
        import yfinance as yf
        import pandas as pd
        import numpy as np
        from matplotlib.figure import Figure
        from matplotlib.backends.backend_qtagg import FigureCanvasQTAgg

        sym          = self.symbol
        company_name = self.company_name or sym

        h_dlg = QDialog(self)
        h_dlg.setWindowModality(Qt.WindowModality.ApplicationModal)
        h_dlg.setWindowFlag(Qt.WindowType.Window, True)
        h_dlg.setWindowTitle(TR("title_div_history", company=company_name, sym=sym))
        screen = QApplication.primaryScreen().availableGeometry()
        _is_fhd1 = screen.width() <= 1920
        hw = int(screen.width()  * (0.88 if _is_fhd1 else 0.72))
        hh = int(screen.height() * (0.90 if _is_fhd1 else 0.80))
        h_dlg.resize(hw, hh)
        h_dlg.move(screen.x() + (screen.width()  - hw) // 2,
                   screen.y() + (screen.height() - hh) // 2)

        h_outer = QVBoxLayout(h_dlg)
        h_outer.setContentsMargins(14, 10, 14, 10)
        h_outer.setSpacing(8)

        # Toolbar
        h_ctrl = QHBoxLayout()
        h_title_lbl = QLabel(f"<b>📈 {company_name} ({sym})</b>")
        h_title_lbl.setStyleSheet("font-size:13px;")
        h_ctrl.addWidget(h_title_lbl, stretch=1)
        _export_data = [{}]

        # Export-Button – eigenständig, ohne Abhängigkeit von _make_export_btn
        def _div_export():
            data = _export_data[0]
            if not data:
                QMessageBox.information(h_dlg, TR("msg_title_info"), "Keine Daten zum Exportieren.")
                return
            from PyQt6.QtWidgets import QFileDialog, QButtonGroup, QRadioButton
            from datetime import datetime as _dt
            import os as _os

            fmt_dlg = QDialog(h_dlg)
            fmt_dlg.setWindowTitle(TR("title_export2"))
            fmt_dlg.setFixedWidth(300)
            _lay = QVBoxLayout(fmt_dlg)
            _lay.setSpacing(8); _lay.setContentsMargins(16, 12, 16, 12)
            _lay.addWidget(QLabel(f"<b>{TR('lbl_export_colon')} {data.get('title','')}</b>"))
            _lay.addWidget(QLabel(TR("lbl_format_choose")))
            _grp = QButtonGroup(fmt_dlg)
            _rb_pdf  = QRadioButton("📄  PDF")
            _rb_xlsx = QRadioButton("📊  Excel (.xlsx)")
            _rb_ods  = QRadioButton("📋  OpenDocument (.ods)")
            _rb_pdf.setChecked(True)
            for _rb in (_rb_pdf, _rb_xlsx, _rb_ods):
                _grp.addButton(_rb); _lay.addWidget(_rb)
            _br = QHBoxLayout()
            _ok = QPushButton(TR("btn_ok")); _cc = QPushButton(TR("btn_cancel"))
            _ok.clicked.connect(fmt_dlg.accept); _cc.clicked.connect(fmt_dlg.reject)
            _br.addStretch(); _br.addWidget(_ok); _br.addWidget(_cc)
            _lay.addLayout(_br)
            if fmt_dlg.exec() != QDialog.DialogCode.Accepted:
                return

            _ts   = _dt.now().strftime('%Y%m%d_%H%M%S')
            _base = f"{TR('export_btn_div_history')}_{sym}_{_ts}".replace(' ','_').replace('/','_')
            _home = _os.path.expanduser("~")
            _ext, _flt = ((".pdf","PDF (*.pdf)") if _rb_pdf.isChecked() else
                          (".xlsx","Excel (*.xlsx)") if _rb_xlsx.isChecked() else
                          (".ods","OpenDocument (*.ods)"))
            _fn, _ = QFileDialog.getSaveFileName(
                h_dlg, TR("title_export2"), _os.path.join(_home, _base + _ext), _flt)
            if not _fn:
                return
            if not _fn.endswith(_ext):
                _fn += _ext

            try:
                headers = data.get('headers', [])
                rows    = data.get('rows', [])
                title   = data.get('title', sym)
                fig     = data.get('fig')

                if _rb_pdf.isChecked():
                    # Reportlab: Chart oben + Tabelle unten — identisch zum Portfolio-Export
                    from reportlab.lib.pagesizes import A4
                    from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer,
                                                    Table, TableStyle, Image as RLImage)
                    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
                    from reportlab.lib import colors
                    from reportlab.lib.units import cm
                    import io as _io

                    _doc_rl = SimpleDocTemplate(_fn, pagesize=A4,
                                               leftMargin=1.5*cm, rightMargin=1.5*cm,
                                               topMargin=1.5*cm, bottomMargin=1.5*cm)
                    _styles = getSampleStyleSheet()
                    _story  = []
                    _story.append(Paragraph(title, _styles['Title']))
                    _story.append(Spacer(1, 0.3*cm))

                    # Chart einbetten
                    if fig is not None:
                        try:
                            _buf = _io.BytesIO()
                            fig.savefig(_buf, format='png', dpi=150, bbox_inches='tight')
                            _buf.seek(0)
                            from PIL import Image as _PILImg
                            _pil = _PILImg.open(_buf); _pw2, _ph2 = _pil.size; _buf.seek(0)
                            _max_w = A4[0] - 3*cm; _max_h = A4[1] * 0.55
                            _asp = _ph2 / _pw2 if _pw2 > 0 else 0.6
                            _iw = _max_w; _ih = _iw * _asp
                            if _ih > _max_h: _ih = _max_h; _iw = _ih / _asp
                            _story.append(RLImage(_buf, width=_iw, height=_ih))
                            _story.append(Spacer(1, 0.4*cm))
                        except Exception:
                            pass

                    # Tabelle
                    if headers and rows:
                        _story.append(Paragraph(TR("lbl_data"), _styles["Heading2"]))
                        _story.append(Spacer(1, 0.2*cm))
                        _pw_tbl = A4[0] - 3*cm
                        _cs2 = ParagraphStyle('c2', parent=_styles['Normal'], fontSize=9, leading=11)
                        _hs2 = ParagraphStyle('h2', parent=_styles['Normal'], fontSize=9, leading=11,
                                              textColor=colors.white, fontName='Helvetica-Bold')
                        _cw2 = [_pw_tbl * 0.35, _pw_tbl * 0.65]
                        _tdata2 = [[Paragraph(str(h), _hs2) for h in headers]] + \
                                  [[Paragraph(str(v), _cs2) for v in row] for row in rows]
                        _t2 = Table(_tdata2, colWidths=_cw2, repeatRows=1)
                        _t2.setStyle(TableStyle([
                            ('BACKGROUND',    (0,0), (-1,0),  colors.HexColor('#2c3e50')),
                            ('TEXTCOLOR',     (0,0), (-1,0),  colors.white),
                            ('FONTSIZE',      (0,0), (-1,-1), 9),
                            ('ALIGN',         (0,0), (-1,-1), 'LEFT'),
                            ('ROWBACKGROUNDS',(0,1), (-1,-1),
                             [colors.HexColor('#f8f9fa'), colors.white]),
                            ('GRID',          (0,0), (-1,-1), 0.4, colors.HexColor('#dee2e6')),
                            ('TOPPADDING',    (0,0), (-1,-1), 3),
                            ('BOTTOMPADDING', (0,0), (-1,-1), 3),
                        ]))
                        _story.append(_t2)

                    _story.append(Spacer(1, 0.5*cm))
                    from datetime import datetime as _dtnow2
                    _story.append(Paragraph(
                        TR("export_footer_long", dt=_dtnow2.now().strftime("%d.%m.%Y %H:%M")),
                        ParagraphStyle('footer2', parent=_styles['Normal'],
                                       fontSize=7, textColor=colors.grey)))
                    _doc_rl.build(_story)

                elif _rb_xlsx.isChecked():
                    import openpyxl
                    from openpyxl.styles import Font
                    _wb = openpyxl.Workbook(); _ws = _wb.active
                    _ws.title = sym[:31]
                    _ws.merge_cells(f"A1:{chr(64+max(len(headers),1))}1")
                    _ws["A1"] = title; _ws["A1"].font = Font(bold=True, size=13)
                    for _ci, _h in enumerate(headers, 1):
                        _ws.cell(row=2, column=_ci, value=_h).font = Font(bold=True)
                    for _ri, _row in enumerate(rows, 3):
                        for _ci, _v in enumerate(_row, 1):
                            _ws.cell(row=_ri, column=_ci, value=_v)
                    _ws.column_dimensions["A"].width = 14
                    _ws.column_dimensions["B"].width = 18
                    _wb.save(_fn)

                else:  # ODS
                    from odf.opendocument import OpenDocumentSpreadsheet
                    from odf.text import P
                    from odf.table import Table, TableRow, TableCell
                    _doc2 = OpenDocumentSpreadsheet()
                    _tbl = Table(name=sym[:31])
                    def _c(t=""): _tc=TableCell(); _tc.addElement(P(text=str(t))); return _tc
                    _tr = TableRow()
                    for _h in headers: _tr.addElement(_c(_h))
                    _tbl.addElement(_tr)
                    for _row in rows:
                        _tr = TableRow()
                        for _v in _row: _tr.addElement(_c(_v))
                        _tbl.addElement(_tr)
                    _doc2.spreadsheet.addElement(_tbl)
                    _doc2.save(_fn)

                QMessageBox.information(h_dlg, TR("msg_title_success"),
                                        TR("msg_pdf_saved", filename=_fn))
            except Exception as _ex:
                QMessageBox.critical(h_dlg, TR("msg_title_error"),
                                     TR("msg_pdf_failed", e=str(_ex)))

        exp_btn = QPushButton(TR("btn_export"))
        exp_btn.setMinimumHeight(28)
        exp_btn.setStyleSheet("padding:2px 12px;")
        exp_btn.setFont(QFont("Segoe UI Emoji", 10))
        exp_btn.clicked.connect(_div_export)
        h_ctrl.addWidget(exp_btn)

        h_close = QPushButton(TR("btn_close"))
        h_close.setMaximumWidth(115)
        h_close.clicked.connect(h_dlg.close)
        h_ctrl.addWidget(h_close)
        h_outer.addLayout(h_ctrl)


        h_info = QLabel(TR("status_loading_div_data"))
        h_info.setWordWrap(True)
        h_info.setStyleSheet("background:#EBF5FB; border-radius:8px; padding:10px 14px; font-size:11px;")
        h_outer.addWidget(h_info)

        h_fig   = Figure(figsize=(max(7, hw/96), max(5, (hh-180)/96)))
        h_fig.patch.set_facecolor('#ffffff')
        h_canvas = FigureCanvasQTAgg(h_fig)
        h_outer.addWidget(h_canvas, stretch=1)

        def _fetch():
            try:
                tk   = yf.Ticker(sym)
                info = tk.info or {}
                currency    = info.get('currency', 'USD')
                cur_sym_str = {'USD':'$','EUR':'€','CHF':'CHF ','GBP':'£',
                               'JPY':'¥','CAD':'C$','AUD':'A$'}.get(currency, currency+' ')

                today    = pd.Timestamp.today().normalize()
                start_13 = today - pd.Timedelta(days=365 * 13)
                hist_raw = tk.history(start=start_13.strftime("%Y-%m-%d"),
                                      auto_adjust=True, actions=True)
                if hist_raw.empty or 'Dividends' not in hist_raw.columns:
                    h_info.setText(TR("lbl_no_div_data", sym=sym)); return
                divs_raw = hist_raw['Dividends'][hist_raw['Dividends'] > 0].copy()
                if divs_raw.empty:
                    h_info.setText(TR("msg_no_dividends", sym=sym)); return

                divs_raw.index = divs_raw.index.tz_localize(None) if divs_raw.index.tz else divs_raw.index
                annual   = divs_raw.groupby(divs_raw.index.year).sum()
                cur_year = today.year

                # Alle vollen Jahre für Kennzahlen
                all_years_sorted = sorted(y for y in annual.index if y < cur_year)
                all_full_vals    = [float(annual[y]) for y in all_years_sorted]
                # Chart: max 11 vergangene Jahre + cur_year = max 12 Balken total
                years_full       = all_years_sorted[-11:]

                # Sonderdividenden-Erkennung deaktiviert (zu viele false-positives ohne Quelldaten)
                _special_div_years = set()
                _median_div = 0

                # Laufendes Jahr hochgerechnet
                annual_show = {y: float(annual[y]) for y in years_full}
                if cur_year in annual.index:
                    ytd = divs_raw[divs_raw.index.year == cur_year]
                    n_ytd = len(ytd)
                    if n_ytd > 0:
                        prev_yr = divs_raw[divs_raw.index.year == cur_year - 1]
                        freq = max(len(prev_yr) if not prev_yr.empty else 4, n_ytd)
                        annual_show[cur_year] = float(ytd.sum()) / n_ytd * freq
                else:
                    # Noch keine Daten für cur_year → Vorjahreswert als Schätzung
                    prev_divs = divs_raw[divs_raw.index.year == cur_year - 1]
                    if not prev_divs.empty:
                        annual_show[cur_year] = float(prev_divs.sum())

                def cagr(vals, n):
                    # Punkt-zu-Punkt CAGR mit Ausreisser-Trim:
                    # Wenn Startwert >25% ueber Median der restlichen Jahre (Sonderdividende),
                    # aeltestes Jahr weglassen und n_eff um 1 reduzieren
                    if len(vals) < n + 1: return None
                    window = list(vals[-(n+1):])
                    rest = sorted(window[1:])
                    if rest:
                        median_rest = rest[len(rest)//2]
                        if median_rest > 0 and window[0] > median_rest * 1.25:
                            window = window[1:]
                    n_eff = len(window) - 1
                    if n_eff < 1 or window[0] <= 0: return None
                    return ((window[-1] / window[0]) ** (1/n_eff) - 1) * 100
                cagr5  = cagr(all_full_vals, 5)
                cagr10 = cagr(all_full_vals, 10)

                # Prognose
                last_full = all_full_vals[-1] if all_full_vals else 0
                if cagr5:   forecast = last_full * (1 + cagr5  / 100)
                elif cagr10: forecast = last_full * (1 + cagr10 / 100)
                else:        forecast = last_full * 1.03
                next_year = cur_year + 1

                # Stabilität + Aristokrat
                consec = 0; max_c = 0; yg = 0; prev = None; cur_streak = 0
                for v in all_full_vals:
                    if prev is not None:
                        if v >= prev: yg += 1; consec += 1; max_c = max(max_c, consec); cur_streak += 1
                        else: consec = 0; cur_streak = 0
                    prev = v
                stability = yg / (len(all_full_vals) - 1) * 100 if len(all_full_vals) > 1 else 0

                _ari_key, ari_col = _get_dividend_category(sym, cur_streak)
                ari_lbl = TR(_ari_key)

                # Ex-Div / Zahldatum
                ex_dates = []; pay_dates = []
                try:
                    cal = tk.calendar
                    if isinstance(cal, dict):
                        ex_d  = cal.get('Ex-Dividend Date') or cal.get('exDividendDate')
                        pay_d = cal.get('Dividend Date')    or cal.get('dividendDate')
                        # Ex-Div: nur aktuelles Jahr anzeigen
                        if ex_d:
                            ts = pd.Timestamp(ex_d, unit='s') if isinstance(ex_d, (int,float)) else pd.Timestamp(ex_d)
                            if ts.year == cur_year: ex_dates.append(_app_config.fmt_date(ts))
                        # Zahldatum: kein Jahresfilter – auch Folgejahr-Daten anzeigen
                        if pay_d:
                            ts = pd.Timestamp(pay_d, unit='s') if isinstance(pay_d, (int,float)) else pd.Timestamp(pay_d)
                            pay_dates.append(_app_config.fmt_date(ts))
                except Exception: pass
                if not ex_dates:
                    try:
                        for dt in divs_raw[divs_raw.index.year == cur_year].index:
                            ex_dates.append(_app_config.fmt_date(pd.Timestamp(dt)))
                    except Exception: pass
                # Fallback Ex-Div: letztes historisches Datum + 1 Jahr
                if not ex_dates:
                    try:
                        last_ex = divs_raw.index[-1]
                        est_ex  = last_ex + pd.DateOffset(years=1)
                        ex_dates.append(_app_config.fmt_date(est_ex) + ' (ca.)')
                    except Exception: pass
                # Fallback fuer pay_dates: letztes historisches Zahldatum + 1 Jahr (z.B. SREN.SW)
                if not pay_dates:
                    try:
                        last_dt = divs_raw.index[-1]
                        est_pay = last_dt + pd.DateOffset(years=1)
                        pay_dates.append(_app_config.fmt_date(est_pay) + ' (ca.)')
                    except Exception: pass

                # Voraussichtlicher Dividendenbetrag (laufendes Jahr hochgerechnet oder letztes volles Jahr)
                _exp_amt = annual_show.get(cur_year) or (all_full_vals[-1] if all_full_vals else None)
                _pay_amt_str = f" ({cur_sym_str}{_exp_amt:.2f})" if _exp_amt else ""

                def _fc(c):
                    return (f"<b style='color:{'#27ae60' if c and c>0 else '#e74c3c'}'>{c:+.1f}%{TR('lbl_per_year')}</b>"
                            if c is not None else "<i>n/a</i>")
                stab_col = '#27ae60' if stability >= 80 else '#e67e22' if stability >= 50 else '#e74c3c'
                n_avail  = len(all_full_vals)
                # CAGR-Label: max 10J, immer auf verfügbare Daten angepasst
                _cagr_n = min(10, n_avail - 1)
                lbl_10j  = f"{_cagr_n}{TR('lbl_year_abbr')}:" if _cagr_n > 0 else f"10{TR('lbl_year_abbr')}:"
                cagr10   = cagr(all_full_vals, _cagr_n) if _cagr_n >= 5 else None
                h_info.setText(
                    f"<table cellspacing='6'><tr>"
                    f"<td><b>{TR('div_growth_5y')}:</b> {_fc(cagr5)}</td>"
                    f"<td style='padding-left:20px'><b>{lbl_10j}</b> {_fc(cagr10)}</td>"
                    f"<td style='padding-left:20px'><b>{TR('div_stability')}:</b> "
                    f"<b style='color:{stab_col}'>{stability:.0f}%</b>"
                    f" <span style='color:#888;font-size:10px'>({n_avail} {TR('lbl_years')})</span></td>"
                    f"<td style='padding-left:20px'><b style='color:{ari_col}'>{ari_lbl}</b></td>"
                    f"</tr><tr>"
                    f"<td><b>Ex-Div {cur_year}:</b> {', '.join(ex_dates) or '–'}</td>"
                    f"<td style='padding-left:20px' colspan='3'><b>{TR('div_next_payment')}:</b> "
                    f"{', '.join(pay_dates) or '–'}{_pay_amt_str}</td>"
                    f"</tr></table>"
                )

                # Chart – gestapelte Balken: regulär (grün) + Sonderdividende (orange)
                h_fig.clear()
                h_ax = h_fig.add_subplot(111)
                h_ax.set_facecolor('#ffffff')
                plot_years = list(annual_show.keys()) + [next_year]
                plot_vals  = list(annual_show.values()) + [forecast]
                x_arr = np.arange(len(plot_years))

                # Reguläre Basis-Dividende: Median der normalen Jahre
                _reg_base = _median_div  # aus Sonderdividenden-Erkennung
                # Für Sonderdividenden-Jahre: regulärer Teil = _reg_base, Extra-Teil = rest
                _reg_vals  = []
                _extra_vals = []
                for y, v in zip(plot_years, plot_vals):
                    if y in _special_div_years:
                        _reg_vals.append(min(v, _reg_base))
                        _extra_vals.append(max(0, v - _reg_base))
                    else:
                        _reg_vals.append(v)
                        _extra_vals.append(0)

                bc_base = ['#aab7d4' if y == next_year
                           else '#3498db' if y == cur_year
                           else '#27ae60'
                           for y in plot_years]
                bars_h = h_ax.bar(x_arr, _reg_vals, width=0.6, color=bc_base,
                                  zorder=3, edgecolor='white', linewidth=1.2)
                bars_h[-1].set_hatch('//'); bars_h[-1].set_edgecolor('#6e85b0')
                # cur_year Balken: Schraffur als Hinweis auf Schätzung
                for _bi, _by in enumerate(plot_years):
                    if _by == cur_year:
                        bars_h[_bi].set_hatch('///')
                        bars_h[_bi].set_edgecolor('#1a6ea8')
                        break
                # Sonderdividende obendrauf (orange)
                _has_special_bar = any(v > 0 for v in _extra_vals)
                if _has_special_bar:
                    bars_extra = h_ax.bar(x_arr, _extra_vals, width=0.6,
                                          bottom=_reg_vals, color='#e67e22',
                                          zorder=3, edgecolor='white', linewidth=1.2,
                                          label='Sonderdividende')
                    for i, (bar, ev) in enumerate(zip(bars_extra, _extra_vals)):
                        if ev > 0:
                            bar.set_hatch('xx')
                h_ax.set_xticks(x_arr)
                h_ax.set_xticklabels([str(y) for y in plot_years[:-1]] + [f"{next_year}\n{TR("chart_legend_forecast")}"],
                                      fontsize=10)
                h_ax.set_ylabel(TR("chart_ylabel_dividend", currency=currency), fontsize=11)
                h_ax.set_title(TR("chart_title_div_history", company=company_name, sym=sym, currency=currency),
                                fontsize=13, fontweight='bold', pad=14)
                h_ax.grid(axis='y', alpha=0.15, linestyle='--')
                h_ax.spines['top'].set_visible(False); h_ax.spines['right'].set_visible(False)
                from matplotlib.patches import Patch
                _legend_handles = [
                    Patch(facecolor='#27ae60', label=TR('chart_legend_past_years')),
                    Patch(facecolor='#3498db', hatch='///', label=f"{cur_year} {TR('chart_legend_expected')}"),
                    Patch(facecolor='#aab7d4', hatch='//', label=f"{next_year} {TR('chart_legend_forecast')}"),
                ]
                if _special_div_years:
                    _legend_handles.append(Patch(facecolor='#e67e22', hatch='xx', label='Sonderdividende (†)'))
                h_ax.legend(handles=_legend_handles, fontsize=9, loc='upper left')
                ymax_h = max(plot_vals) if plot_vals else 1
                marg_h = ymax_h * 0.18
                h_ax.set_ylim(0, ymax_h + marg_h)
                for i, (bar, val, yr) in enumerate(zip(bars_h, plot_vals, plot_years)):
                    if val > 0:
                        total_h = bar.get_height() + (_extra_vals[i] if i < len(_extra_vals) else 0)
                        suffix = "*" if yr == cur_year else ("†" if yr in _special_div_years else "")
                        lbl = f"{cur_sym_str}{plot_vals[i]:.2f}{suffix}"
                        h_ax.text(bar.get_x() + bar.get_width()/2,
                                   total_h + marg_h * 0.08,
                                   lbl, ha='center', va='bottom',
                                   fontsize=9, fontweight='bold', color='#333')
                # Fussnoten UNTER dem Diagramm (figure-Koordinaten, nicht axes)
                _fn_lines = []
                if cur_year in annual_show: _fn_lines.append("* " + TR("chart_footnote_annualized"))
                if _special_div_years:      _fn_lines.append("† inkl. Sonderdividende")
                if _fn_lines:
                    h_fig.text(0.01, 0.01, "  ".join(_fn_lines),
                               fontsize=8, color='#888', style='italic',
                               transform=h_fig.transFigure, va='bottom')

                # Hover-Tooltip: zwei Objekte – regulär (grün) + Sonderdividende (orange)
                _tip_kw = dict(textcoords="offset points", fontsize=10, zorder=10,
                               arrowprops=dict(arrowstyle="->", color="#555"))
                _annot = h_ax.annotate("", xy=(0,0), xytext=(10,18),
                    bbox=dict(boxstyle="round,pad=0.45", fc="#fffbe6", ec="#e67e22", lw=1.2, alpha=0.95),
                    **_tip_kw)
                _annot.set_visible(False)
                _annot_sp = h_ax.annotate("", xy=(0,0), xytext=(10,18),
                    bbox=dict(boxstyle="round,pad=0.45", fc="#fff3e0", ec="#e67e22", lw=1.5, alpha=0.97),
                    **_tip_kw)
                _annot_sp.set_visible(False)
                _n_bars = len(plot_years)

                def _on_hover(event):
                    if event.inaxes is not h_ax:
                        changed = False
                        if _annot.get_visible():    _annot.set_visible(False);    changed = True
                        if _annot_sp.get_visible(): _annot_sp.set_visible(False); changed = True
                        if changed: h_canvas.draw_idle()
                        return
                    hit = False
                    for i, bar in enumerate(bars_h):
                        bx = bar.get_x(); bw = bar.get_width()
                        ex = event.xdata or -1
                        if not (bx <= ex <= bx + bw): continue
                        hit = True
                        yr = plot_years[i]; val = plot_vals[i]
                        reg_v = _reg_vals[i]; extra_v = _extra_vals[i]
                        yoy = (f"  {(val-plot_vals[i-1])/plot_vals[i-1]*100:+.1f}% {TR('chart_yoy_label')}"
                               if i > 0 and plot_vals[i-1] > 0 else "")
                        lbl_yr = (TR("chart_legend_forecast") if yr == next_year
                                  else (f"{cur_year} ({TR('chart_legend_annualized')})" if yr == cur_year else str(yr)))
                        _off = (-130, 18) if i >= _n_bars // 2 else (10, 18)
                        fc = "#e8f8e8" if (i > 0 and plot_vals[i-1] > 0 and val >= plot_vals[i-1]) else "#fdf0e0"

                        if extra_v > 0 and event.ydata is not None:
                            # Cursor auf Sonderdividenden-Teil (oberer Bereich)?
                            if event.ydata >= reg_v:
                                _annot.set_visible(False)
                                _annot_sp.set_text(f"{lbl_yr} ⚡ Sonderdividende: {cur_sym_str}{extra_v:.2f}")
                                _annot_sp.xy = (bx + bw/2, bar.get_height() + extra_v)
                                _annot_sp.set_position(_off)
                                _annot_sp.set_visible(True)
                                h_canvas.draw_idle(); return
                            else:
                                _annot_sp.set_visible(False)

                        _annot_sp.set_visible(False)
                        _annot.set_text(f"{lbl_yr}: {cur_sym_str}{reg_v:.2f}{yoy}")
                        _annot.xy = (bx + bw/2, bar.get_height())
                        _annot.set_position(_off)
                        _annot.get_bbox_patch().set_facecolor(fc)
                        _annot.set_visible(True); h_canvas.draw_idle(); return
                    if not hit:
                        changed = False
                        if _annot.get_visible():    _annot.set_visible(False);    changed = True
                        if _annot_sp.get_visible(): _annot_sp.set_visible(False); changed = True
                        if changed: h_canvas.draw_idle()

                h_canvas.mpl_connect('motion_notify_event', _on_hover)
                h_fig.tight_layout(pad=2.0)
                h_fig.subplots_adjust(bottom=0.10)
                h_canvas.draw()

                _export_data[0] = {
                    'title': TR("export_title_div_history", sym=sym),
                    'headers': [TR("col_year"), TR("col_div_annual", cur=currency)],
                    'rows': [(str(y), f"{cur_sym_str}{v:.4f}") for y, v in zip(plot_years[:-1], list(annual_show.values()))]
                          + [(f"{next_year} ({TR('chart_legend_forecast')})", f"{cur_sym_str}{forecast:.4f}")],
                    'fig': h_fig,
                }
            except Exception as ex:
                h_info.setText(TR("lbl_error_generic", e=ex))

        QTimer.singleShot(80, _fetch)
        h_dlg.exec()
    
    def get_ai_assessment(self):
        """Generiere AI-Einschätzung basierend auf den Daten"""
        if self.num_analysts == 0:
            return TR("ki_no_analyst_data")
        
        # Basierend auf Empfehlung
        n = self.num_analysts
        assessments = {
            'strong_buy': TR("ki_assessment_strong_buy", n=n),
            'buy':        TR("ki_assessment_buy",        n=n),
            'hold':       TR("ki_assessment_none"),
            'sell':       TR("ki_assessment_sell",       n=n),
            'strong_sell':TR("ki_assessment_strong_sell",n=n),
            'none':       TR("ki_assessment_none"),
        }
        
        base_text = assessments.get(self.recommendation, TR("ki_assessment_none"))
        
        # Ergänze mit Zielkurs-Info
        if self.target_price and self.current_price:
            potential = ((self.target_price - self.current_price) / self.current_price) * 100
            if potential > 20:
                base_text += " " + TR("ki_target_upside",   pct=potential)
            elif potential < -10:
                base_text += " " + TR("ki_target_downside", pct=abs(potential))
        
        return base_text


class CompanyInfoDialog(QDialog):
    """Dialog mit detaillierten Firmeninformationen"""
    
    def __init__(self, symbol, company_name, parent=None):
        super().__init__(parent)
        self.symbol = symbol
        self.company_name = company_name
        
        self.setWindowTitle(f"🏢 {TR('title_company_info')} - {symbol}")
        self.setMinimumSize(600, 500)
        
        # Lade Daten und zeige Dialog
        self.load_and_show()
    
    def load_and_show(self):
        """Lade Firmendaten von Yahoo Finance"""
        layout = QVBoxLayout()
        
        try:
            ticker = yf.Ticker(self.symbol)
            info = ticker.info
            
            # Header
            header = QLabel(f"<h2>{self.company_name or self.symbol}</h2>")
            header.setAlignment(Qt.AlignmentFlag.AlignCenter)
            layout.addWidget(header)
            
            layout.addSpacing(15)
            
            # Firmen-Basisdaten Box
            basics_box = QFrame()
            basics_box.setFrameStyle(QFrame.Shape.Box)
            basics_box.setStyleSheet("background-color: #f5f5f5; border: 1px solid #cccccc;")
            basics_layout = QVBoxLayout()
            basics_layout.setContentsMargins(15, 15, 15, 15)
            basics_layout.setSpacing(8)
            
            # Daten sammeln
            data_items = []
            
            # Hauptsitz
            city = info.get('city', '')
            country = info.get('country', '')
            if city and country:
                data_items.append((f"🏙️ {TR('lbl_headquarters')}:", f"{city}, {country}"))
            elif city or country:
                data_items.append((f"🏙️ {TR('lbl_headquarters')}:", city or country))
            
            # CEO / Vorsitzender
            ceo = info.get('companyOfficers', [])
            if ceo and len(ceo) > 0:
                ceo_name = ceo[0].get('name', 'N/A')
                ceo_title = ceo[0].get('title', 'CEO')
                data_items.append((f"👔 {ceo_title}:", ceo_name))
            
            # Mitarbeiter - IMMER als ganze Zahl (Menschen sind keine Bauklötze!)
            employees = info.get('fullTimeEmployees')
            if employees:
                emp_text = f"{employees:,}".replace(',', "'")  # Schweizer Format mit '
                data_items.append((f"👥 {TR('lbl_employees')}:", emp_text))
            
            # Hole Währung der Firma
            currency = info.get('currency', 'USD')
            currency_symbol = {
                'USD': '$', 'EUR': '€', 'CHF': 'CHF ', 'GBP': '£', 
                'JPY': '¥', 'CNY': '¥', 'CAD': 'C$', 'AUD': 'A$'
            }.get(currency, currency + ' ')
            
            # Marktkapitalisierung mit Original-Währung und deutschen Abkürzungen
            market_cap = info.get('marketCap')
            if market_cap:
                if market_cap >= 1000000000000:  # Billion (deutsch)
                    cap_text = f"{currency_symbol}{market_cap / 1000000000000:.2f} Bio."
                elif market_cap >= 1000000000:  # Milliarde
                    cap_text = f"{currency_symbol}{market_cap / 1000000000:.2f} Mrd."
                elif market_cap >= 1000000:  # Million
                    cap_text = f"{currency_symbol}{market_cap / 1000000:.2f} Mio."
                else:
                    cap_text = f"{currency_symbol}{market_cap:,.0f}".replace(',', "'")
                data_items.append((f"💰 {TR('lbl_market_cap')}:", cap_text))
            
            # Umsatz mit Original-Währung UND Billionen-Check
            revenue = info.get('totalRevenue')
            if revenue:
                if revenue >= 1000000000000:  # Billion (über 1000 Milliarden!)
                    rev_text = f"{currency_symbol}{revenue / 1000000000000:.2f} Bio."
                elif revenue >= 1000000000:  # Milliarde
                    rev_text = f"{currency_symbol}{revenue / 1000000000:.2f} Mrd."
                elif revenue >= 1000000:  # Million
                    rev_text = f"{currency_symbol}{revenue / 1000000:.2f} Mio."
                else:
                    rev_text = f"{currency_symbol}{revenue:,.0f}".replace(',', "'")
                data_items.append((f"📊 {TR('lbl_revenue_ttm')}:", rev_text))
            
            # Gewinn mit Original-Währung UND Billionen-Check
            profit = info.get('netIncomeToCommon')
            if profit:
                abs_profit = abs(profit)
                if abs_profit >= 1000000000000:  # Billion
                    profit_text = f"{currency_symbol}{profit / 1000000000000:.2f} Bio."
                elif abs_profit >= 1000000000:  # Milliarde
                    profit_text = f"{currency_symbol}{profit / 1000000000:.2f} Mrd."
                elif abs_profit >= 1000000:  # Million
                    profit_text = f"{currency_symbol}{profit / 1000000:.2f} Mio."
                else:
                    profit_text = f"{currency_symbol}{profit:,.0f}".replace(',', "'")
                profit_color = "green" if profit > 0 else "red"
                data_items.append((f"💵 {TR('lbl_net_income')}:", f"<span style='color:{profit_color}'>{profit_text}</span>"))
            
            # Instanzvariablen für Export speichern
            self._export_data_items = data_items

            # Zeige alle Daten
            for label_text, value_text in data_items:
                row_layout = QHBoxLayout()

                label = QLabel(label_text)
                label.setFont(QFont("Arial", 10, QFont.Weight.Bold))
                label.setMinimumWidth(200)
                row_layout.addWidget(label)

                value = QLabel(value_text)
                value.setFont(QFont("Arial", 10))
                row_layout.addWidget(value)
                row_layout.addStretch()

                basics_layout.addLayout(row_layout)

            basics_box.setLayout(basics_layout)
            layout.addWidget(basics_box)

            layout.addSpacing(15)

            # Firmenbeschreibung
            description = info.get('longBusinessSummary', '')
            self._export_description = description
            if description:
                desc_box = QFrame()
                desc_box.setFrameStyle(QFrame.Shape.Box)
                desc_box.setStyleSheet("background-color: #f9f9f9; border: 1px solid #cccccc;")
                desc_layout = QVBoxLayout()
                desc_layout.setContentsMargins(10, 10, 10, 10)

                desc_title = QLabel(f"<b>📄 {TR('lbl_company_desc')}</b>")
                desc_title.setFont(QFont("Arial", 11, QFont.Weight.Bold))
                desc_layout.addWidget(desc_title)

                desc_layout.addSpacing(8)

                # QTextBrowser: vollständiger Text, scrollbar, kopierbar
                from PyQt6.QtWidgets import QTextBrowser as _QTB_ci
                desc_browser = _QTB_ci()
                desc_browser.setPlainText(description)
                desc_browser.setFont(QFont("Arial", 11))
                desc_browser.setReadOnly(True)
                desc_browser.setFrameShape(QFrame.Shape.NoFrame)
                desc_browser.setMinimumHeight(200)
                desc_browser.setStyleSheet("background: transparent; border: none;")
                desc_layout.addWidget(desc_browser)

                desc_box.setLayout(desc_layout)
                layout.addWidget(desc_box)

            layout.addStretch()

        except Exception as e:
            self._export_data_items = []
            self._export_description = ""
            error_label = QLabel(TR("lbl_error_load_company", e=e))
            error_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            layout.addWidget(error_label)

        # ── Button-Zeile ─────────────────────────────────────────────────
        self.button_container = QWidget()
        button_layout = QHBoxLayout(self.button_container)
        button_layout.setContentsMargins(0, 10, 0, 0)

        from PyQt6.QtGui import QFontDatabase as _QFD_ci
        _ef_ci = next((QFont(f, 10) for f in ['Noto Color Emoji','Segoe UI Emoji','Apple Color Emoji']
                       if f in _QFD_ci.families()), None)

        export_btn_ci = QPushButton(TR("btn_export"))
        export_btn_ci.setMinimumHeight(28)
        export_btn_ci.setStyleSheet("padding:2px 12px;")
        if _ef_ci:
            export_btn_ci.setFont(_ef_ci)
        export_btn_ci.clicked.connect(self.export_company_data)
        button_layout.addWidget(export_btn_ci)

        button_layout.addStretch()

        close_btn = QPushButton(TR("btn_close") if _ef_ci else TR("btn_close_plain"))
        if _ef_ci:
            close_btn.setFont(_ef_ci)
        close_btn.clicked.connect(self.close)
        button_layout.addWidget(close_btn)

        layout.addWidget(self.button_container)

        # Sticky-Footer: Inhalt scrollbar, Buttons immer unten
        from PyQt6.QtWidgets import QScrollArea as _QSA2
        layout.removeWidget(self.button_container)

        scroll_widget = QWidget()
        scroll_widget.setLayout(layout)
        scroll_area = _QSA2()
        scroll_area.setWidget(scroll_widget)
        scroll_area.setWidgetResizable(True)
        scroll_area.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        scroll_area.setFrameShape(QFrame.Shape.NoFrame)

        outer_layout = QVBoxLayout(self)
        outer_layout.setContentsMargins(8, 8, 8, 8)
        outer_layout.setSpacing(4)
        outer_layout.addWidget(scroll_area, stretch=1)
        outer_layout.addWidget(self.button_container)

    def translate_to_german(self, text):
        """Lasse Text auf Englisch - keine schlechte Übersetzung!"""
