    def export_company_data(self):
        """Export Firmeninfo als PDF/XLSX/ODS — vollständiger Text, kein Screenshot."""
        from PyQt6.QtWidgets import QFileDialog, QButtonGroup, QRadioButton
        from datetime import datetime
        import os

        fmt_dlg = QDialog(self)
        fmt_dlg.setWindowTitle(TR("title_export2"))
        fmt_dlg.setFixedWidth(320)
        lay = QVBoxLayout(fmt_dlg)
        lay.setSpacing(10); lay.setContentsMargins(18, 14, 18, 14)
        lay.addWidget(QLabel(f"<b>{TR('lbl_export_colon')} {self.company_name or self.symbol}</b>"))
        lay.addWidget(QLabel(TR("lbl_format_choose")))
        grp = QButtonGroup(fmt_dlg)
        rb_pdf  = QRadioButton("📄  PDF")
        rb_xlsx = QRadioButton("📊  Excel (.xlsx)")
        rb_ods  = QRadioButton("📋  OpenDocument (.ods)")
        rb_pdf.setChecked(True)
        for rb in (rb_pdf, rb_xlsx, rb_ods):
            grp.addButton(rb); lay.addWidget(rb)
        br = QHBoxLayout()
        ok = QPushButton(TR("btn_ok")); cc = QPushButton(TR("btn_cancel"))
        ok.clicked.connect(fmt_dlg.accept); cc.clicked.connect(fmt_dlg.reject)
        br.addStretch(); br.addWidget(ok); br.addWidget(cc)
        lay.addLayout(br)
        if fmt_dlg.exec() != QDialog.DialogCode.Accepted:
            return

        ts       = datetime.now().strftime('%Y%m%d_%H%M%S')
        safe_sym = self.symbol.replace('.', '_')
        # Dateiname in der aktiven App-Sprache
        prefix   = TR("title_company_info").replace(' ', '_').replace('/', '_')
        base     = f"{prefix}_{safe_sym}_{ts}"
        home_dir = os.path.expanduser("~")

        if rb_pdf.isChecked():
            ext, flt = ".pdf", "PDF (*.pdf)"
        elif rb_xlsx.isChecked():
            ext, flt = ".xlsx", "Excel (*.xlsx)"
        else:
            ext, flt = ".ods", "OpenDocument (*.ods)"

        filename, _ = QFileDialog.getSaveFileName(
            self, TR("title_export2"), os.path.join(home_dir, base + ext), flt)
        if not filename:
            return
        if not filename.endswith(ext):
            filename += ext

        try:
            if rb_pdf.isChecked():
                self._ci_export_pdf(filename)
            elif rb_xlsx.isChecked():
                self._ci_export_xlsx(filename)
            else:
                self._ci_export_ods(filename)
            QMessageBox.information(self, TR("msg_title_success"),
                                    TR("msg_pdf_saved", filename=filename))
        except Exception as e:
            QMessageBox.critical(self, TR("msg_title_error"),
                                 TR("msg_pdf_failed", e=str(e)))

    def _ci_export_pdf(self, filename):
        """PDF via reportlab — Titel, Basisdaten-Tabelle, vollständige Beschreibung."""
        from reportlab.lib.pagesizes import A4
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle)
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib import colors
        from reportlab.lib.units import cm
        from datetime import datetime
        import re

        doc = SimpleDocTemplate(filename, pagesize=A4,
                                leftMargin=1.5*cm, rightMargin=1.5*cm,
                                topMargin=1.5*cm, bottomMargin=1.5*cm)
        styles = getSampleStyleSheet()
        story  = []

        story.append(Paragraph(self.company_name or self.symbol, styles['Title']))
        story.append(Paragraph(self.symbol,
                               ParagraphStyle('sub', parent=styles['Normal'],
                                              fontSize=10, textColor=colors.grey, alignment=1)))
        story.append(Spacer(1, 0.5*cm))

        if hasattr(self, '_export_data_items') and self._export_data_items:
            _cs = ParagraphStyle('cv', parent=styles['Normal'], fontSize=10, leading=13)
            _ks = ParagraphStyle('ck', parent=styles['Normal'], fontSize=10, leading=13,
                                 fontName='Helvetica-Bold')
            _pw = A4[0] - 3*cm
            _tdata = []
            for lbl, val in self._export_data_items:
                lc = re.sub(r'[^\x00-\x7F\u00C0-\u024F ]', '', lbl).strip()
                vc = re.sub(r'<[^>]+>', '', val)
                _tdata.append([Paragraph(lc, _ks), Paragraph(vc, _cs)])
            _t = Table(_tdata, colWidths=[_pw*0.42, _pw*0.58])
            _t.setStyle(TableStyle([
                ('ROWBACKGROUNDS', (0,0), (-1,-1),
                 [colors.HexColor('#f8f9fa'), colors.white]),
                ('GRID',    (0,0), (-1,-1), 0.4, colors.HexColor('#dee2e6')),
                ('TOPPADDING',    (0,0), (-1,-1), 5),
                ('BOTTOMPADDING', (0,0), (-1,-1), 5),
                ('LEFTPADDING',   (0,0), (-1,-1), 8),
            ]))
            story.append(_t)
            story.append(Spacer(1, 0.6*cm))

        if hasattr(self, '_export_description') and self._export_description:
            story.append(Paragraph(TR('lbl_company_desc'),
                                   ParagraphStyle('dh', parent=styles['Heading2'], fontSize=12)))
            story.append(Spacer(1, 0.2*cm))
            story.append(Paragraph(
                self._export_description.replace('\n', '<br/>'),
                ParagraphStyle('desc', parent=styles['Normal'],
                               fontSize=10, leading=14, alignment=4)))
            story.append(Spacer(1, 0.5*cm))

        story.append(Paragraph(
            TR("export_footer_long", dt=datetime.now().strftime("%d.%m.%Y %H:%M")),
            ParagraphStyle('footer', parent=styles['Normal'],
                           fontSize=7, textColor=colors.grey)))
        doc.build(story)

    def _ci_export_xlsx(self, filename):
        import openpyxl, re
        from openpyxl.styles import Font, Alignment
        wb = openpyxl.Workbook(); ws = wb.active
        ws.title = self.symbol[:31]
        ws.merge_cells("A1:B1")
        ws["A1"] = self.company_name or self.symbol
        ws["A1"].font = Font(bold=True, size=14)
        ws["A1"].alignment = Alignment(horizontal="center")
        row = 3
        if hasattr(self, '_export_data_items'):
            for lbl, val in self._export_data_items:
                lc = re.sub(r'[^\x00-\x7F\u00C0-\u024F ]', '', lbl).strip()
                vc = re.sub(r'<[^>]+>', '', val)
                ws.cell(row=row, column=1, value=lc).font = Font(bold=True)
                ws.cell(row=row, column=2, value=vc); row += 1
        if hasattr(self, '_export_description') and self._export_description:
            row += 1
            ws.cell(row=row, column=1, value=TR("lbl_company_desc")).font = Font(bold=True)
            row += 1
            ws.merge_cells(f"A{row}:B{row}")
            ws.cell(row=row, column=1, value=self._export_description)
            ws.cell(row=row, column=1).alignment = Alignment(wrap_text=True)
            ws.row_dimensions[row].height = 200
        ws.column_dimensions["A"].width = 28
        ws.column_dimensions["B"].width = 42
        wb.save(filename)

    def _ci_export_ods(self, filename):
        import re
        try:
            from odf.opendocument import OpenDocumentSpreadsheet
            from odf.text import P
            from odf.table import Table, TableRow, TableCell
            doc = OpenDocumentSpreadsheet()
            table = Table(name=self.symbol[:31])
            def _c(t=""): tc = TableCell(); tc.addElement(P(text=str(t))); return tc
            if hasattr(self, '_export_data_items'):
                for lbl, val in self._export_data_items:
                    lc = re.sub(r'[^\x00-\x7F\u00C0-\u024F ]', '', lbl).strip()
                    vc = re.sub(r'<[^>]+>', '', val)
                    tr = TableRow(); tr.addElement(_c(lc)); tr.addElement(_c(vc))
                    table.addElement(tr)
            if hasattr(self, '_export_description') and self._export_description:
                table.addElement(TableRow())
                tr = TableRow(); tr.addElement(_c(TR("lbl_company_desc")))
                table.addElement(tr)
                tr = TableRow(); tr.addElement(_c(self._export_description))
                table.addElement(tr)
            doc.spreadsheet.addElement(table)
            doc.save(filename)
        except ImportError:
            raise RuntimeError("odfpy nicht installiert: pip install odfpy")


