    def _show_html_table(self, parent_layout, html):
        """Zeigt HTML-Inhalt in einer ScrollArea (Hilfsmethode)."""
        scroll = QScrollArea()
        scroll.setObjectName("data_table")
        scroll.setWidgetResizable(True)
        lbl = QLabel(html)
        lbl.setWordWrap(True)
