    def _load_sector(self):
        """Branche von Yahoo Finance laden – in Background-Thread um UI nicht zu blockieren"""
        if not self.sector_label or not self.symbol:
            return

        sym       = self.symbol
        lbl_ref   = self.sector_label
        cname_ref = self.company_name

        class _SectorWorker(QThread):
            done = pyqtSignal(str)   # fertiges HTML oder ''
            def __init__(self, s, cn):
                super().__init__()
                self._sym   = s
                self._cname = cn
            def run(self):
                try:
                    info         = yf.Ticker(self._sym).info
                    sector       = info.get('sector',   '')
                    industry     = info.get('industry', '')
                    company      = (info.get('longName') or info.get('shortName')
                                    or self._cname or '')
                    sector_canon, ind_group, industry_disp, sub_industry = \
                        _gics_lookup(sector, industry)
                    if not sector_canon:
                        self.done.emit('')
                        return
                    lines = []
                    if company:
                        lines.append(f"<b>{company}</b>")
                    lines.append(f"Sector:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {sector_canon}")
                    if ind_group:
                        lines.append(f"Industry Group:  {ind_group}")
                    if industry_disp:
                        lines.append(f"Industry:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {industry_disp}")
                    if sub_industry and sub_industry != industry_disp:
                        lines.append(f"Sub-Industry:&nbsp;&nbsp;&nbsp; {sub_industry}")
                    self.done.emit("<br>".join(lines))
                except Exception:
                    self.done.emit('')

        def _apply(html):
            try:
                if html:
                    lbl_ref.setText(html)
                    lbl_ref.setTextFormat(Qt.TextFormat.RichText)
                else:
                    lbl_ref.setText(TR("status_sector_no_data"))
            except RuntimeError:
                pass  # Widget bereits gelöscht

        w = _SectorWorker(sym, cname_ref)
        if not hasattr(self, '_sector_workers'):
            self._sector_workers = []
        self._sector_workers.append(w)
        w.done.connect(_apply)
        w.done.connect(lambda _: self._sector_workers.remove(w)
                       if w in self._sector_workers else None)
        w.start()

    def open_name_search(self):
        """Namenssuche-Dialog öffnen"""
        dialog = NameSearchDialog(self)
        if dialog.exec() == QDialog.DialogCode.Accepted and dialog.result_symbol:
            self.symbol = dialog.result_symbol
            self.symbol_input.setText(self.symbol)
            self.company_name = ""
            self.update_chart()
    
    def save_chart(self):
        """Chart exportieren – PDF, XLSX oder ODS (wie überall in der App)."""
        from PyQt6.QtWidgets import QFileDialog, QButtonGroup, QRadioButton
        from datetime import datetime
        import os, io

        fmt_dlg = QDialog(self)
        fmt_dlg.setWindowTitle(TR("title_export2"))
        fmt_dlg.setFixedWidth(300)
        lay = QVBoxLayout(fmt_dlg)
        lay.setSpacing(10); lay.setContentsMargins(18, 14, 18, 14)

        title_str = self.symbol
        if self.company_name:
            title_str += f" – {self.company_name}"
        lay.addWidget(QLabel(f"<b>{TR('lbl_export_colon')} {title_str}</b>"))
        lay.addWidget(QLabel(TR("lbl_format_choose")))

        grp = QButtonGroup(fmt_dlg)
        rb_pdf  = QRadioButton("📄  PDF")
        rb_xlsx = QRadioButton("📊  Excel (XLSX)")
        rb_ods  = QRadioButton("📊  Calc (ODS)")
        rb_pdf.setChecked(True)
        for rb in (rb_pdf, rb_xlsx, rb_ods):
            grp.addButton(rb); lay.addWidget(rb)

        btn_row = QHBoxLayout()
        ok_btn  = QPushButton(TR("btn_ok"))
        cnc_btn = QPushButton(TR("btn_cancel"))
        ok_btn.clicked.connect(fmt_dlg.accept)
        cnc_btn.clicked.connect(fmt_dlg.reject)
        btn_row.addStretch(); btn_row.addWidget(ok_btn); btn_row.addWidget(cnc_btn)
        lay.addLayout(btn_row)

        if fmt_dlg.exec() != QDialog.DialogCode.Accepted:
            return

        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        tf = self.timeframe_combo.currentText().replace(' ', '_')
        base = f"{self.symbol}_{tf}_{timestamp}"
        home_dir = os.path.expanduser("~")

        if rb_pdf.isChecked():
            ext, flt = ".pdf", "PDF (*.pdf)"
        elif rb_xlsx.isChecked():
            ext, flt = ".xlsx", "Excel (*.xlsx)"
        else:
            ext, flt = ".ods", "ODS (*.ods)"

        filename, _ = QFileDialog.getSaveFileName(
            self, TR("title_export2"), os.path.join(home_dir, base + ext), flt)
        if not filename:
            return
        if not filename.endswith(ext):
            filename += ext

        # Chart als PNG-Bytes via pyqtgraph PlotWidget.grab()
        def _grab_png_bytes() -> bytes:
            from PyQt6.QtCore import QByteArray, QBuffer, QIODevice
            pixmap = self.plot_widget.grab()
            ba = QByteArray()
            qbuf = QBuffer(ba)
            qbuf.open(QIODevice.OpenModeFlag.WriteOnly)
            pixmap.save(qbuf, 'PNG')
            qbuf.close()
            return bytes(ba)

        try:
            png_bytes = _grab_png_bytes()

            if rb_pdf.isChecked():
                from PyQt6.QtGui import QPdfWriter, QPainter, QImage, QPageLayout, QPageSize
                from PyQt6.QtCore import QMarginsF, QByteArray, Qt
                writer = QPdfWriter(filename)
                writer.setPageSize(QPageSize(QPageSize.PageSizeId.A4))
                writer.setPageOrientation(QPageLayout.Orientation.Landscape)
                writer.setPageMargins(QMarginsF(10, 10, 10, 10),
                                      QPageLayout.Unit.Millimeter)
                painter = QPainter(writer)
                img = QImage()
                img.loadFromData(QByteArray(png_bytes))
                rect = painter.viewport()
                scaled = img.scaled(rect.width(), rect.height(),
                                    Qt.AspectRatioMode.KeepAspectRatio,
                                    Qt.TransformationMode.SmoothTransformation)
                x = (rect.width()  - scaled.width())  // 2
                y = (rect.height() - scaled.height()) // 2
                painter.drawImage(x, y, scaled)
                painter.end()

            elif rb_xlsx.isChecked():
                from openpyxl import Workbook
                from openpyxl.styles import Font, PatternFill, Alignment
                from openpyxl.drawing.image import Image as XLImg
                wb = Workbook(); ws = wb.active
                ws.title = self.symbol[:31]
                ws.merge_cells('A1:J1')
                ws['A1'] = title_str
                ws['A1'].font = Font(bold=True, size=13, color='FFFFFF')
                ws['A1'].fill = PatternFill('solid', start_color='2C3E50')
                ws['A1'].alignment = Alignment(horizontal='center')
                ws.row_dimensions[1].height = 22
                img_io = io.BytesIO(png_bytes)
                xl_img = XLImg(img_io)
                pw = self.plot_widget.width(); ph = self.plot_widget.height()
                ratio = ph / pw if pw > 0 else 0.6
                xl_img.width = 900; xl_img.height = int(900 * ratio)
                ws.add_image(xl_img, 'A3')
                disc_row = 3 + int(900 * ratio) // 15 + 5
                ws.cell(row=disc_row, column=1,
                        value=TR("export_footer_short",
                                 dt=_app_config.fmt_date(datetime.now(), include_time=True)))
                ws.cell(row=disc_row, column=1).font = Font(size=7, italic=True, color='999999')
                wb.save(filename)

            else:  # ODS
                try:
                    from odf.opendocument import OpenDocumentSpreadsheet
                    from odf.style import Style, TextProperties, TableCellProperties
                    from odf.text import P
                    from odf.table import Table, TableRow, TableCell
                    from odf.draw import Frame, Image as OdfImage
                except ImportError:
                    QMessageBox.warning(self, TR("msg_title_ods_missing"),
                        TR("msg_ods_missing") + TR("msg_ods_install") + TR("msg_excel_hint"))
                    return
                doc = OpenDocumentSpreadsheet()
                table = Table(name=self.symbol[:31])
                img_path = "Pictures/chart_export.png"
                doc.addPicture(img_path, "image/png", png_bytes)
                pw = self.plot_widget.width(); ph = self.plot_widget.height()
                w_cm = 18.0; h_cm = w_cm * (ph / pw) if pw > 0 else 11.0
                h_row = TableRow(); h_tc = TableCell(valuetype="string")
                h_tc.addElement(P(text=title_str))
                h_row.addElement(h_tc); table.addElement(h_row)
                img_row = TableRow(); img_cell = TableCell(valuetype="string")
                frame = Frame(width=f"{w_cm:.1f}cm", height=f"{h_cm:.1f}cm",
                              anchortype="as-char")
                frame.addElement(OdfImage(href=img_path, type="simple",
                                          show="embed", actuate="onLoad"))
                img_cell.addElement(frame); img_row.addElement(img_cell)
                table.addElement(img_row)
                doc.spreadsheet.addElement(table)
                doc.save(filename)

            QMessageBox.information(self, TR("title_success_saved"),
                                    TR("msg_pdf_saved", filename=filename))
        except Exception as e:
            QMessageBox.critical(self, TR("title_error"),
                                 TR("lbl_error_save") + f"\n{e}")


    def update_symbol(self):
        """Symbol aktualisieren"""
        self.symbol = self.symbol_input.text().strip().upper()
        self.company_name = ""  # Name wird beim Chart-Update geholt
        self.update_chart()
        if self.zoom_mode:
            if self.sector_label:
                self.sector_label.setText(TR("status_sector_loading"))
            QTimer.singleShot(500, self._load_sector)
    
    def set_timeframe(self, timeframe_text):
        """Zeitraum von außen setzen (für globale Steuerung) – öffnet nie den Custom-Dialog."""
        self.timeframe_combo.blockSignals(True)
        self.timeframe_combo.setCurrentText(timeframe_text)
        self.timeframe_combo.blockSignals(False)
        # Direkt laden – custom_start/end muss vorher gesetzt sein wenn 'Eigener Zeitraum'
        self.update_chart()
    
    def update_favorites_list(self, favorites):
        """Aktualisiere die Favoriten-Liste im Dropdown - ALPHABETISCH SORTIERT"""
        self.favorites_combo.clear()
        self.favorites_combo.addItem(self._fav_placeholder)
        # Alphabetisch sortieren
        sorted_favs = sorted(favorites)
        for fav in sorted_favs:
            self.favorites_combo.addItem(fav)
    
    def select_from_favorites(self, symbol):
        """Wähle Aktie aus Favoriten aus"""
        if symbol and symbol != self._fav_placeholder:
            self.symbol_input.setText(symbol)
            self.update_symbol()
            # Reset Dropdown
            self.favorites_combo.setCurrentIndex(0)
    
    def get_state(self):
        """Aktuellen Zustand zurückgeben"""
        # Zoom-Only-Checkboxen: im normalen Grid-Modus als versteckter Attribut-State
        # gespeichert (zoom_candle, zoom_rsi, zoom_bb, zoom_dd, zoom_w52)
        def _zoom_val(cb_attr, store_attr):
            if self.zoom_mode and hasattr(self, cb_attr):
                return getattr(self, cb_attr).isChecked()
            return getattr(self, store_attr, False)

        state = {
            'symbol': self.symbol,
            # Zeitraum als sprachunabhängigen internen Wert speichern
            'timeframe': StockChartWidget.TIMEFRAMES.get(
                self.timeframe_combo.currentText(),
                (self.timeframe_combo.currentText(), '1d')
            )[0],
            'company_name': self.company_name,
            'ma20': self.ma20_checkbox.isChecked(),
            'ma50': self.ma50_checkbox.isChecked(),
            'ma200': self.ma200_checkbox.isChecked(),
            'trend': self.trend_checkbox.isChecked(),
            'beta': self.beta_checkbox.isChecked(),
            'alpha': self.alpha_checkbox.isChecked(),
            'sharpe': self.sharpe_checkbox.isChecked(),
            'target': self.target_checkbox.isChecked(),
            'rsi': _zoom_val('rsi_checkbox', 'zoom_rsi'),
            'w52': _zoom_val('w52_checkbox', 'zoom_w52'),
            'bb':  _zoom_val('bb_checkbox',  'zoom_bb'),
            'dd':  _zoom_val('dd_checkbox',  'zoom_dd'),
            'candle': _zoom_val('candle_checkbox', 'zoom_candle'),
        }
        # Custom-Zeitraum Daten mitschreiben
        if self.custom_start:
            state['custom_start'] = self.custom_start.strftime('%Y-%m-%d')
        if self.custom_end:
            state['custom_end'] = self.custom_end.strftime('%Y-%m-%d')
        return state
    
    def set_state(self, state):
        """Zustand wiederherstellen - Signals blockieren um doppelte update_chart() Aufrufe zu vermeiden"""
        # Alle Widgets kurz stumm schalten
        self._ready = False
        self.symbol = state['symbol']
        self.company_name = state.get('company_name', '')
        self.symbol_input.setText(self.symbol)
        self.timeframe_combo.blockSignals(True)
        saved_tf = state['timeframe']
        # Internen Wert (z.B. "1mo") auf aktuellen Label-String mappen
        # damit Sprachwechsel den gespeicherten Zeitraum nicht bricht
        def _tf_key_to_label(internal_val):
            for label, (val, _) in StockChartWidget.TIMEFRAMES.items():
                if val == internal_val:
                    return label
            return TR('period_1y')  # Fallback
        # Eigener Zeitraum nur wiederherstellen wenn custom_start/end im State vorhanden
        custom_start_str = state.get('custom_start')
        custom_end_str   = state.get('custom_end')
        if saved_tf == 'custom' and custom_start_str and custom_end_str:
            try:
                from datetime import datetime as _ddt
                self.custom_start = _ddt.strptime(custom_start_str, '%Y-%m-%d')
                self.custom_end   = _ddt.strptime(custom_end_str,   '%Y-%m-%d')
                self.timeframe_combo.setCurrentText(TR('lbl_custom_period_entry'))
            except Exception:
                self.timeframe_combo.setCurrentText(TR('period_1y'))
                self.custom_start = None; self.custom_end = None
        elif saved_tf == 'custom':
            # Kein Datum gespeichert → auf 1 Jahr zurückfallen, kein Dialog
            self.timeframe_combo.setCurrentText(TR('period_1y'))
            self.custom_start = None; self.custom_end = None
        else:
            self.timeframe_combo.setCurrentText(_tf_key_to_label(saved_tf))
        self.timeframe_combo.blockSignals(False)
        self.ma20_checkbox.blockSignals(True)
        self.ma20_checkbox.setChecked(state.get('ma20', False))
        self.ma20_checkbox.blockSignals(False)
        self.ma50_checkbox.blockSignals(True)
        self.ma50_checkbox.setChecked(state.get('ma50', False))
        self.ma50_checkbox.blockSignals(False)
        self.ma200_checkbox.blockSignals(True)
        self.ma200_checkbox.setChecked(state.get('ma200', False))
        self.ma200_checkbox.blockSignals(False)
        self.trend_checkbox.blockSignals(True)
        self.trend_checkbox.setChecked(state.get('trend', False))
        self.trend_checkbox.blockSignals(False)
        self.beta_checkbox.blockSignals(True)
        self.beta_checkbox.setChecked(state.get('beta', False))
        self.beta_checkbox.blockSignals(False)
        self.alpha_checkbox.blockSignals(True)
        self.alpha_checkbox.setChecked(state.get('alpha', False))
        self.alpha_checkbox.blockSignals(False)
        self.sharpe_checkbox.blockSignals(True)
        self.sharpe_checkbox.setChecked(state.get('sharpe', False))
        self.sharpe_checkbox.blockSignals(False)
        self.target_checkbox.blockSignals(True)
        self.target_checkbox.setChecked(state.get('target', False))
        self.target_checkbox.blockSignals(False)
        # Zoom-Only-State: im zoom_mode Checkboxen setzen, sonst nur Attribute speichern
        # (verhindert dass BB/DD/RSI/Candles in der Grid-Übersicht angezeigt werden)
        self.zoom_rsi    = state.get('rsi',    False)
        self.zoom_w52    = state.get('w52',    False)
        self.zoom_bb     = state.get('bb',     False)
        self.zoom_dd     = state.get('dd',     False)
        self.zoom_candle = state.get('candle', False)
        if self.zoom_mode:
            for cb_attr, key in [
                ('rsi_checkbox',    'rsi'),
                ('w52_checkbox',    'w52'),
                ('bb_checkbox',     'bb'),
                ('dd_checkbox',     'dd'),
                ('candle_checkbox', 'candle'),
            ]:
                cb = getattr(self, cb_attr, None)
                if cb is not None:
                    cb.blockSignals(True)
                    cb.setChecked(state.get(key, False))
                    cb.blockSignals(False)
        else:
            # Im Grid-Modus: Checkboxen auf False halten (sind sowieso versteckt,
            # aber sicher ist sicher – verhindert versehentliche Anzeige)
            for cb_attr in ('rsi_checkbox', 'w52_checkbox', 'bb_checkbox',
                            'dd_checkbox', 'candle_checkbox'):
                cb = getattr(self, cb_attr, None)
                if cb is not None:
                    cb.blockSignals(True)
                    cb.setChecked(False)
                    cb.blockSignals(False)
        self._ready = True
        # Einmalig updaten nach vollständigem State-Restore
        self.update_chart()

