        refresh_btn = _make_portfolio_btn(TR("btn_refresh_prices"), TR("btn_refresh_prices_plain"), TR("tip_ov_refresh"))
        refresh_btn.clicked.connect(lambda: (self._invalidate_cache(), self._master_load()))
        btn_layout.addWidget(refresh_btn)

        btn_layout.addWidget(QLabel("  |  "))

        import_btn = _make_portfolio_btn(TR("btn_swissquote"), TR("btn_swissquote_plain"), TR("tip_swissquote"))
        import_btn.setStyleSheet("padding: 2px 10px;")
        import_btn.clicked.connect(self.import_swissquote_csv)
        btn_layout.addWidget(import_btn)

        generic_csv_btn = _make_portfolio_btn(TR("btn_generic_csv"), TR("btn_generic_csv_plain"), TR("tip_generic_csv"))
        generic_csv_btn.setStyleSheet("padding: 2px 10px;")
        generic_csv_btn.clicked.connect(self.import_generic_csv)
        btn_layout.addWidget(generic_csv_btn)

        btn_layout.addWidget(QLabel("  |  "))

        save_btn = _make_portfolio_btn(TR("btn_save_as"), TR("btn_save_as_plain"), TR("tip_save_as"))
        save_btn.setStyleSheet("padding: 2px 10px;")
        save_btn.clicked.connect(self.portfolio_save_as)
        btn_layout.addWidget(save_btn)

        load_btn = _make_portfolio_btn(TR("btn_load"), TR("btn_load"), TR("tip_load_portfolio"))
        load_btn.setStyleSheet("padding: 2px 10px;")
        load_btn.clicked.connect(self.portfolio_load)
        btn_layout.addWidget(load_btn)

        clear_btn = _make_portfolio_btn(TR("btn_portfolio_delete"), TR("btn_portfolio_delete_plain"), TR("tip_portfolio_delete"))
        clear_btn.setStyleSheet("padding: 2px 10px;")
        clear_btn.clicked.connect(self.portfolio_clear)
        btn_layout.addWidget(clear_btn)

        cleanup_btn = _make_portfolio_btn(TR("btn_cleanup"), TR("btn_cleanup_plain"), TR("tip_cleanup"))
        cleanup_btn.clicked.connect(self.portfolio_cleanup)
        btn_layout.addWidget(cleanup_btn)

        db_btn = _make_portfolio_btn(TR("btn_database"), TR("btn_database_plain"), TR("tip_database"))
        db_btn.clicked.connect(self.show_db_dialog)
        btn_layout.addWidget(db_btn)

        # ── Steuern-Button ─────────────────────────────────────────────────────
        tax_btn = _make_portfolio_btn(TR("btn_taxes"), TR("btn_taxes_plain"), TR("tip_taxes"))
        tax_btn.setStyleSheet("padding: 2px 10px 2px 22px;")
