    @safe_slot
    def show_overview(self):
        """Portfolio-Übersicht als Seite im StackedWidget"""
        embed_cb = getattr(self, '_embed_callback', None)

        if not self.portfolio_data:
            if embed_cb:
                wrapper = QWidget()
                wrapper_layout = QVBoxLayout(wrapper)
                wrapper_layout.setContentsMargins(0, 0, 0, 0)
                info = QLabel(
                    TR("lbl_portfolio_empty_html")
                )
                info.setAlignment(Qt.AlignmentFlag.AlignCenter)
                wrapper_layout.addWidget(info)
                embed_cb(wrapper)
                # Admin-Fenster als normales nicht-modales Fenster zeigen
                self.setWindowModality(Qt.WindowModality.NonModal)
                self.resize(1500, 700)
                _scr = QApplication.primaryScreen().availableGeometry()
                self.move(
                    _scr.x() + (_scr.width()  - self.width())  // 2,
                    _scr.y() + (_scr.height() - self.height()) // 2
                )
                self.show()
                self.raise_()
                self.activateWindow()
            else:
                QMessageBox.information(self, TR("msg_title_info"),
                    TR("lbl_no_portfolio_data"))
                self._stack.setCurrentWidget(self._admin_widget)
            return

        # Altes Übersichts-Widget aufräumen
        if self._overview_widget is not None:
            try:
                self._overview_widget.deleteLater()
            except RuntimeError:
                pass
            self._overview_widget = None

        # ov_widget gehört zum Hauptfenster (embed_cb setzt Parent korrekt)
        # NICHT in self._stack einfügen — das würde den Parent auf Windows falsch setzen
        ov_widget = QWidget()
        self._overview_widget = ov_widget

        # ── Währung früh initialisieren (wird für Button-Aufbau benötigt) ──
        if not hasattr(self, '_ov_currency'):
            try:
                _early_cur = _app_config.get_global_chart_settings().get('portfolio_currency', 'USD')
                if _early_cur not in ('USD', 'CHF', 'EUR', 'GBP'):
                    _early_cur = 'USD'
            except Exception:
                _early_cur = 'USD'
            self._ov_currency = _early_cur
        if not hasattr(self, '_ov_fx'):
            self._ov_fx = {'USD': 1.0, 'CHF': 1.0, 'EUR': 1.0, 'GBP': 1.0}
        self.setWindowTitle(TR("title_portfolio_admin"))

        # Zuerst in Hauptfenster einbetten — damit Parent korrekt gesetzt wird
        if embed_cb:
            embed_cb(ov_widget)
            QTimer.singleShot(0, self.hide)
        else:
            # Fallback: in eigenem Stack anzeigen
            self._stack.addWidget(ov_widget)
            self._stack.setCurrentWidget(ov_widget)

        dlg = ov_widget
