        # ── Steuern-Button ────────────────────────────────────────────────────
        def _make_tax_popup(anchor_ref):
            def _show():
                from PyQt6.QtWidgets import QDialog, QVBoxLayout
                from PyQt6.QtGui import QPixmap, QIcon
                from PyQt6.QtCore import QByteArray, QSize
                import base64 as _b64
                popup = QDialog(self)
                popup.setWindowFlags(Qt.WindowType.Popup)
                popup.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose)
                lay = QVBoxLayout(popup)
                lay.setContentsMargins(5, 5, 5, 5)
                lay.setSpacing(3)
                for code, b64, tip in [
                    ("CH", _CH_FLAG_B64, "Schweiz"),
                    ("DE", _DE_FLAG_B64, "Deutschland"),
                    ("AT", _AT_FLAG_B64, "Österreich"),
                    ("UK", _UK_FLAG_B64, "Grossbritannien"),
                    ("US", _US_FLAG_B64, "USA"),
                ]:
                    pb = QPushButton()
                    px = QPixmap()
                    px.loadFromData(QByteArray(_b64.b64decode(b64)))
                    pb.setIcon(QIcon(px))
                    pb.setIconSize(QSize(48, 29))
                    pb.setFixedSize(60, 36)
                    pb.setToolTip(tip)
                    pb.setStyleSheet(
                        "QPushButton{border:1px solid #aaa;border-radius:3px;background:#f8f8f8;}"
                        "QPushButton:hover{background:#e0e8ff;border-color:#6688cc;}"
                    )
                    def _cb(checked=False, c=code): popup.accept(); self.show_tax_dialog(c)
                    pb.clicked.connect(_cb)
                    lay.addWidget(pb)
                popup.adjustSize()
                btn = anchor_ref[0]
                pos = btn.mapToGlobal(btn.rect().bottomLeft())
                popup.move(pos)
                popup.exec()
            return _show

        tax_btn_ov = _make_ov_btn(TR("btn_taxes"), TR("tip_taxes_ov"), 115)
        tax_btn_ov.setStyleSheet("padding: 2px 10px;")
        # Schmales Leerzeichen vorne für optische Zentrierung (Text kürzer als Schliessen)
        tax_btn_ov.setText("\u2004\u2004\u2004" + tax_btn_ov.text())
        _tax_btn_ref = [tax_btn_ov]
        tax_btn_ov.clicked.connect(_make_tax_popup(_tax_btn_ref))
        # Full HD: per _add_btn in Zeile 2 eingefügt (Platzhalter oben gesetzt)
        # → Steuern erscheint zwischen Sharpe und AI-Balance = visuell unter Dividenden
        if _ov_is_fullhd:
            # Full HD: direkt unter Dividenden (gleiche Spalte, Zeile 1 des Grids)
            btn_grid.addWidget(tax_btn_ov, 1, _div_col_idx[0])
        # 4K: Steuern wird weiter unten in einer eigenen Zeile unter Exportieren platziert
