        # 4K: wird unten in _tax_row_4k neben Steuern platziert


        def _get_overview_export_data():
            ov = self._ov_data or {}
            if not ov:
                return _get_overview_export_data_simple()

            fx_map = self._ov_fx if hasattr(self, '_ov_fx') else {'USD':1.0}
            cur    = self._ov_currency if hasattr(self, '_ov_currency') else 'USD'
            fx     = fx_map.get(cur, 1.0)

            def _is_crypto(s):
                return s.endswith('-USD') or s.endswith('-EUR') or \
                       s.endswith('-CHF') or s.endswith('-BTC')

            data = [(sym, d) for sym, d in ov.items()
                    if sym != '__fx__' and d.get('price_usd') and not d.get('skip')]
            if not data:
                return _get_overview_export_data_simple()

            total_val_usd  = sum(d['value_usd'] for _, d in data)
            total_cost_usd = sum(d['cost_usd']  for _, d in data)
            total_val_chf  = sum(d.get('value_chf', 0) for _, d in data)
            total_cost_chf = sum(d.get('cost_chf', 0)  for _, d in data)

            def _n(v, dec=2):
                """Zahl mit globalem Zahlenformat (CH/DE/US) formatieren."""
                if v is None: return '–'
                try:
                    return _fmt(float(v), dec)
                except Exception:
                    return '–'

            rows = []
            stocks    = [(s, d) for s, d in data if not _is_crypto(s) and not _is_commodity(s)]
            cryptos   = [(s, d) for s, d in data if _is_crypto(s) or _is_commodity(s)]
            stocks.sort(key=lambda x: x[1]['value_usd'], reverse=True)
            cryptos.sort(key=lambda x: x[1]['value_usd'], reverse=True)

            for sym, d in stocks + cryptos:
                qty       = d['qty']
                cost_usd  = d['cost_usd']
                val_usd   = d['value_usd']
                price_usd = d['price_usd']

                cost_chf = d.get('cost_chf', 0)
                val_chf  = d.get('value_chf', 0)
                if cost_chf > 0 and val_chf > 0:
                    pnl_val  = val_chf - cost_chf
                    pnl_pct  = pnl_val / cost_chf * 100
                    cost_disp = cost_chf * fx
                    val_disp  = val_chf  * fx
                    avg_disp  = cost_chf / qty * fx if qty > 0 else 0
                    pnl_disp  = pnl_val * fx
                else:
                    pnl_val  = val_usd - cost_usd
                    pnl_pct  = pnl_val / cost_usd * 100 if cost_usd > 0 else 0
                    cost_disp = cost_usd * fx
                    val_disp  = val_usd  * fx
                    avg_disp  = (cost_usd / qty * fx) if qty > 0 else 0
                    pnl_disp  = pnl_val  * fx

                share        = val_usd / total_val_usd * 100 if total_val_usd else 0
                perf_contrib = pnl_val / total_cost_usd * 100 if total_cost_usd else 0

                w52h = d.get('w52_high')
                w52l = d.get('w52_low')

                _rs = (self._sector_cache or {}).get(sym, '')
                _ri = (self._industry_cache or {}).get(sym, '')
                if _rs and _rs not in ('Unknown', ''):
                    _sc, _, _, _si = _gics_lookup(_rs, _ri)
                    sector_str = f"{_sc}  ›  {_si}" if _si else _sc
                else:
                    sector_str = '–'

                # Stückzahl: keine Tausender-Trennung bei kleinen Zahlen
                qty_str = _n(qty, 4).rstrip('0').rstrip('.') if qty != int(qty) else _n(qty, 0)

                rows.append((
                    sym,
                    qty_str,
                    _n(avg_disp,  2),
                    _n(cost_disp, 0),
                    _n(price_usd * fx, 2),
                    _n(val_disp,  0),
                    f"{'+' if pnl_disp >= 0 else ''}{_n(pnl_disp, 0)}",
                    f"{pnl_pct:+.2f}%",
                    f"{share:.1f}%",
                    f"{perf_contrib:+.2f}%",
                    _n(w52h * fx, 2) if w52h else '–',
                    _n(w52l * fx, 2) if w52l else '–',
                    sector_str,
                ))

            if not rows:
                return _get_overview_export_data_simple()

            # Summenzeile
            tv  = total_val_chf  * fx if total_val_chf  else total_val_usd  * fx
            tc  = total_cost_chf * fx if total_cost_chf else total_cost_usd * fx
            tp  = tv - tc
            tpp = tp / tc * 100 if tc > 0 else 0
            rows.append(('', '', '', '', '', '', '', '', '', '', '', '', ''))
            rows.append((
                'GESAMT', '', '', '',
                '', _n(tv, 0),
                f"{'+' if tp >= 0 else ''}{_n(tp, 0)}",
                f"{tpp:+.2f}%",
                '100%', '', '', '', '',
            ))

            return {
                'title':   TR('lbl_portfolio_overview_title'),
                # Header-Namen so gewählt dass Zeilenumbruch an sinnvoller Stelle erfolgt
                'headers': [TR("col_symbol"), TR("col_qty"), TR("col_avg_buy"), TR("col_buy_value"),
                            TR("col_price"), TR("col_cur_value"), TR("col_pnl"), TR("col_pnl_pct"),
                            TR("col_share"), TR("col_perf_contrib"),
                            TR("col_w52h"), TR("col_w52l"), TR("col_sector")],
                'rows':    rows,
                'fig':     None,
                'summary': _get_summary_rows(),
            }

        def _get_summary_rows():
            """Baut die Zusammenfassungszeilen (Total / Aktien / Krypto / Rohstoffe)
            analog zur Statusleiste in der Übersicht."""
            ov = self._ov_data or {}
            if not ov:
                return []
            fx_map = self._ov_fx if hasattr(self, '_ov_fx') else {'USD': 1.0}
            cur    = self._ov_currency if hasattr(self, '_ov_currency') else 'USD'
            fx     = fx_map.get(cur, 1.0)
            cur_sym = {"USD": "$", "CHF": "Fr.", "EUR": "€", "GBP": "£"}.get(cur, cur)

            def _is_crypto(s):
                return s.endswith('-USD') or s.endswith('-EUR') or \
                       s.endswith('-CHF') or s.endswith('-BTC')

            data = [(s, d) for s, d in ov.items()
                    if s != '__fx__' and d.get('price_usd') and not d.get('skip')]

            def _group(items):
                v = sum(d['value_usd'] for _, d in items)
                c = sum(d['cost_usd']  for _, d in items)
                p = v - c
                pct = p / c * 100 if c > 0 else 0
                return v, c, p, pct

            stocks    = [(s, d) for s, d in data if not _is_crypto(s) and not _is_commodity(s)]
            cryptos   = [(s, d) for s, d in data if _is_crypto(s)]
            commodities = [(s, d) for s, d in data if _is_commodity(s)]

            tv, tc, tp, tpct = _group(data)
            rows = []

            def _line(label, v, c, p, pct):
                sgn = '+' if p >= 0 else ''
                return (
                    label,
                    f"Inv: {cur_sym} {_fmt(c * fx, 0)}",
                    f"Akt: {cur_sym} {_fmt(v * fx, 0)}",
                    f"G&V: {sgn}{cur_sym} {_fmt(abs(p * fx), 0)} ({sgn}{pct:.1f}%)",
                )

            rows.append(_line(f"Total ({cur})", tv, tc, tp, tpct))
            if stocks:
                sv, sc, sp, spct = _group(stocks)
                rows.append(_line(TR("lbl_stocks_etf_section"), sv, sc, sp, spct))
            if cryptos:
                cv, cc, cp, cpct = _group(cryptos)
                rows.append(_line(TR("lbl_krypto_row"), cv, cc, cp, cpct))
            if commodities:
                mv, mc, mp, mpct = _group(commodities)
                rows.append(_line("Rohstoffe", mv, mc, mp, mpct))
            return rows

        def _get_overview_export_data_simple():
            """Fallback: einfache Übersicht aus price_cache."""
            price_cache = self._price_cache or {}
            rows = []
            total_val = total_cost = 0.0
            for sym, positions in sorted(self.portfolio_data.items()):
                d = price_cache.get(sym, {}) if isinstance(price_cache.get(sym), dict) else {}
                cost_from_pos = sum(p.get('quantity',0)*p.get('buy_price',0) for p in positions)
                qty_from_pos  = sum(p.get('quantity',0) for p in positions)
                val   = d.get('value_usd',  0)
                cost  = d.get('cost_usd',   cost_from_pos)
                qty   = d.get('qty',        qty_from_pos)
                price = d.get('price_usd',  0)
                pct   = (val-cost)/cost*100 if cost>0 and val>0 else 0.0
                pnl   = val-cost if val>0 else 0.0
                sector = (self._sector_cache or {}).get(sym, '–')
                rows.append((
                    sym, sector,
                    f"{qty:,.4f}".rstrip('0').rstrip('.') if '.' in f"{qty:,.4f}" else f"{qty:,.0f}",
                    f"${price:,.2f}" if price else '–',
                    f"${val:,.0f}"   if val   else '–',
                    f"${cost:,.0f}"  if cost  else '–',
                    f"${pnl:+,.0f}"  if val   else '–',
                    f"{pct:+.2f}%"   if val   else '–',
                ))
                total_val += val; total_cost += cost
            if not rows: return None
            total_pnl = total_val - total_cost
            total_pct = total_pnl/total_cost*100 if total_cost>0 and total_val>0 else 0.0
            rows.append(('','','','','','','',''))
            rows.append(('GESAMT','','','',
                f"${total_val:,.0f}" if total_val else '–',
                f"${total_cost:,.0f}" if total_cost else '–',
                f"${total_pnl:+,.0f}" if total_val else '–',
                f"{total_pct:+.2f}%" if total_val else '–'))
            return {'title':TR("lbl_portfolio_overview_title"),
                    'headers':[TR("col_symbol"),TR("col_sector"),TR("col_qty3"),TR("col_price"),TR("col_cur_value"),TR("col_cost"),TR("col_pnl"),TR("col_pnl_pct")],
                    'rows':rows,'fig':None}

