        # (Schließen-Button wurde in die Admin-Zeile oben verschoben)

        # ── Zustand ─────────────────────────────────────────────────────────
        self._ov_data      = None
        try:
            _saved_cur = _app_config.get_global_chart_settings().get('portfolio_currency', 'USD')
            if _saved_cur not in ('USD', 'CHF', 'EUR', 'GBP'):
                _saved_cur = 'USD'
        except Exception:
            _saved_cur = 'USD'
        self._ov_currency  = _saved_cur
        self._ov_fx        = {'USD': 1.0, 'CHF': 1.0, 'EUR': 1.0, 'GBP': 1.0}

        # ── Tabellenzeilen aufbauen ─────────────────────────────────────────
        def build_rows():
            self._ov_build_rows = build_rows  # Referenz für Refresh
            # Guard: rows_layout kann bereits gelöscht sein wenn schnell navigiert wird
            try:
                _ = rows_layout.count()
            except RuntimeError:
                return
            if self._ov_data is None:
                return
            cur  = self._ov_currency
            fx   = self._ov_fx.get(cur, 1.0)
            data = [(sym, d) for sym, d in self._ov_data.items()
                    if sym != '__fx__' and d.get('price_usd') and not d.get('skip')]

            total_value_usd  = sum(d['value_usd'] for _, d in data)
            total_cost_usd   = sum(d['cost_usd']  for _, d in data)
            total_pnl_usd    = total_value_usd - total_cost_usd  # Gesamt-G&V für Beitrags-Berechnung
            total_value_chf  = sum(d.get('value_chf', 0) for _, d in data)
            total_cost_chf   = sum(d.get('cost_chf', 0)  for _, d in data)

            # Krypto-Erkennung
            def _is_crypto(sym):
                return sym.endswith('-USD') or sym.endswith('-EUR') or \
                       sym.endswith('-CHF') or sym.endswith('-BTC')

            stocks_data    = [(s, d) for s, d in data if not _is_crypto(s) and not _is_commodity(s)]
            crypto_data    = [(s, d) for s, d in data if     _is_crypto(s)]
            commodity_data = [(s, d) for s, d in data if     _is_commodity(s)]

            # Sortieren
            col = sort_state['col']
            rev = not sort_state['asc']

            # Kumulierten Sektor-Beitrag vorberechnen
            _sector_totals = {}  # sector_canon → summe perf_contrib %
            for sym, d in data:
                if _is_crypto(sym) or _is_commodity(sym): continue
                _rs = getattr(self, '_sector_cache', {}).get(sym, '')
                _ri = getattr(self, '_industry_cache', {}).get(sym, '')
                if not _rs or _rs in ('Unknown', ''): continue
                _sc, _, _, _ = _gics_lookup(_rs, _ri)
                _contrib = (d['value_usd'] - d['cost_usd']) / total_cost_usd * 100 if total_cost_usd else 0
                _sector_totals[_sc] = _sector_totals.get(_sc, 0) + _contrib

            def _get_sector_canon(sym):
                _rs = getattr(self, '_sector_cache', {}).get(sym, '')
                _ri = getattr(self, '_industry_cache', {}).get(sym, '')
                if not _rs or _rs in ('Unknown', ''): return ''
                # Direkt den Cache-Wert normalisieren ohne _gics_lookup Umweg
                # damit _sector_totals und _get_sector_canon denselben Key verwenden
                _sc, _, _, _ = _gics_lookup(_rs, _ri)
                return _sc if _sc else _SECTOR_ALIASES.get(_rs, _rs)

            def sort_key(item):
                sym, d = item
                if col == 'sym':      return sym
                if col == 'qty':      return d.get('qty', 0)
                if col == 'avg_buy':  return d['cost_usd'] / d['qty'] if d['qty'] else 0
                if col == 'cost':     return d['cost_usd']
                if col == 'price':    return d['price_usd']
                if col == 'value':    return d['value_usd']
                if col == 'pnl':      return d['value_usd'] - d['cost_usd']
                if col == 'pnl_pct':
                    cc = d.get('cost_chf', 0); vc = d.get('value_chf', 0)
                    if cc > 0 and vc > 0:
                        return (vc - cc) / cc
                    c = d['cost_usd']
                    return (d['value_usd'] - c) / c if c > 0 else 0
                if col == 'share':    return d['value_usd'] / total_value_usd if total_value_usd else 0
                if col == 'perf_contrib': return (d['value_usd'] - d['cost_usd']) / total_cost_usd if total_cost_usd else 0
                if col == 'sector_contrib':
                    _sc = _get_sector_canon(sym)
                    _total = _sector_totals.get(_sc, -999)
                    # Sekundärsortierung nach Sektorname damit gleiche Werte gruppiert bleiben
                    return (_total, _sc)
                if col == 'sector':
                    _rs = getattr(self, '_sector_cache', {}).get(sym, '')
                    _ri = getattr(self, '_industry_cache', {}).get(sym, '')
                    if not _rs or _rs in ('Unknown', ''): return 'zzz'
                    _sc, _, _, _si = _gics_lookup(_rs, _ri)
                    return (_sc + '  ' + _si).lower()
                return 0

            stocks_data.sort(key=sort_key, reverse=(rev if col != 'sym' else not rev))
            crypto_data.sort(key=sort_key, reverse=(rev if col != 'sym' else not rev))

            # Header-Pfeile aktualisieren
            for key, (b, name) in hdr_btns.items():
                try:
                    if b is None or not b.isVisible(): continue
                except RuntimeError:
                    continue
                if key == col:
                    arrow = " ▼" if rev else " ▲"
                    b.setText(name + arrow)
                    b.setStyleSheet("color:#e67e22; font-weight:bold; text-align:left;"
                                    "border:none; padding:0px 2px;")
                else:
                    b.setText(name)
                    b.setStyleSheet("color:#2c3e50; font-weight:bold; text-align:left;"
                                    "QPushButton:hover{color:#2980b9;} border:none; padding:0px 2px;")

            # Zeilen löschen
            while rows_layout.count() > 1:
                item = rows_layout.takeAt(0)
                if item.widget(): item.widget().deleteLater()

            def _make_row(symbol, d, idx):
                qty       = d['qty']
                cost_usd  = d['cost_usd']
                val_usd   = d['value_usd']
                price_usd = d['price_usd']
                avg_usd   = cost_usd / qty if qty > 0 else 0
                pnl_usd   = val_usd - cost_usd

                cost_chf  = d.get('cost_chf', 0)
                val_chf   = d.get('value_chf', 0)
                if cost_chf > 0 and val_chf > 0:
                    pnl_chf = val_chf - cost_chf
                    pnl_pct = pnl_chf / cost_chf * 100
                elif cost_usd > 0:
                    pnl_pct = pnl_usd / cost_usd * 100
                else:
                    pnl_pct = 0

                share_pct = val_usd / total_value_usd * 100 if total_value_usd > 0 else 0
                # Performance-Beitrag: Anteil dieses G&V am Gesamt-G&V
                perf_contrib = pnl_usd / total_cost_usd * 100 if total_cost_usd > 0 else 0
                s = fx
                c_pnl = "#27ae60" if pnl_pct >= 0 else "#c0392b"
                sign  = "+" if pnl_pct >= 0 else ""
                bg    = "#f8f9fa" if idx % 2 == 0 else "white"

                row = QWidget()
                row.setStyleSheet(f"background:{bg}; border-bottom:1px solid #ecf0f1;")
                row.setCursor(Qt.CursorShape.ArrowCursor)
                rl = QHBoxLayout(row)
                rl.setContentsMargins(8, 4, 8, 4)
                rl.setSpacing(0)

                def mk(txt, w, color=None, bold=False, right=False, emoji=False):
                    l = QLabel(txt)
                    l.setMinimumWidth(w); l.setMaximumWidth(w)
                    st = ""
                    if color: st += f"color:{color};"
                    if bold:  st += "font-weight:bold;"
                    if st:    l.setStyleSheet(st)
                    if right: l.setAlignment(Qt.AlignmentFlag.AlignRight|Qt.AlignmentFlag.AlignVCenter)
                    if emoji and _ov_emoji_font:
                        l.setFont(_ov_emoji_font)
                    return l

                _company = getattr(self, '_company_cache', {}).get(symbol, '')
                _tooltip = f"{_company}\n{TR('wl_click_hint')}" if _company else TR("wl_click_hint")
                sym_lbl = mk(f"<b>{symbol}</b>", 80, "#2980b9")
                sym_lbl.setToolTip(_tooltip)
                sym_lbl.setCursor(Qt.CursorShape.PointingHandCursor)
                rl.addWidget(sym_lbl)
                _qty_txt = f"{_fmt(qty, 4) if qty != int(qty) else str(int(qty))}"
                qty_lbl = mk(_qty_txt, 65, "#2471a3", right=True)
                qty_lbl.setCursor(Qt.CursorShape.PointingHandCursor)
                qty_lbl.setToolTip(TR("tip_click_tx_history"))
                def _make_qty_click(sym):
                    def _on_qty_click(ev):
                        self._show_transactions(sym)
                    return _on_qty_click
                qty_lbl.mousePressEvent = _make_qty_click(symbol)
                rl.addWidget(qty_lbl)
                rl.addWidget(mk(f"{_fmt(avg_usd*s)}",     105,  right=True))
                rl.addWidget(mk(f"{_fmt(cost_usd*s)}",    120,  right=True))

                # Kurs-Label mit Stop/Ziel-Indikator und Doppelklick-Dialog
                _lim = getattr(self, '_limits', {}).get(symbol, {})
                _stop   = _lim.get('stop')
                _target = _lim.get('target')
                _price_disp = price_usd * s if price_usd else 0
                # Indikator-Suffix: ▼ Stop, ▲ Ziel
                _ind = ""
                _ind_color = "#555"
                if _stop and _price_disp and _price_disp <= _stop:
                    _ind = " ▼"; _ind_color = "#c0392b"  # Stop gerissen
                elif _target and _price_disp and _price_disp >= _target:
                    _ind = " ▲"; _ind_color = "#27ae60"  # Ziel erreicht
                elif _stop:
                    _ind = " ▼"; _ind_color = "#aaa"
                elif _target:
                    _ind = " ▲"; _ind_color = "#aaa"
                _price_lbl = QLabel(f"{_fmt(_price_disp)}{_ind}")
                _price_lbl.setMinimumWidth(105); _price_lbl.setMaximumWidth(105)
                _price_lbl.setAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
                if _ov_emoji_font:
                    _price_lbl.setFont(_ov_emoji_font)
                if _ind:
                    _price_lbl.setStyleSheet(f"color:{_ind_color};")
                # Tooltip zeigt Stop/Ziel
                _tip_parts = [TR("tip_click_stoploss")]
                if _stop:   _tip_parts.append(f"Stop-Loss: {_fmt(_stop*s)}")
                if _target: _tip_parts.append(f"Eigener Zielkurs: {_fmt(_target*s)}")
                if _stop and _price_disp:
                    _dist_stop = (_price_disp - _stop*s) / (_stop*s) * 100
                    _tip_parts.append(f"Abstand Stop: {_dist_stop:+.1f}%")
                if _target and _price_disp:
                    _dist_tgt = (_target*s - _price_disp) / _price_disp * 100
                    _tip_parts.append(f"{TR('lbl_dist_to_target')}: {_dist_tgt:+.1f}%")
                _price_lbl.setToolTip("\n".join(_tip_parts))
                _price_lbl.setCursor(Qt.CursorShape.PointingHandCursor)

                def _make_limit_dblclick(sym, cur_price, cur_s, sym_cur='USD'):
                    def _on_dbl(ev):
                        from PyQt6.QtCore import Qt as _Qt
                        if ev.button() != _Qt.MouseButton.LeftButton:
                            return
                        _lim2 = getattr(self, '_limits', {}).get(sym, {})
                        dlg = QDialog(self)
                        dlg.setWindowTitle(f"{TR('title_stop_loss_target')} – {sym}")
                        dlg.setMinimumWidth(320)
                        _dl = QVBoxLayout(dlg)
                        _dl.setSpacing(10)
                        _dl.addWidget(QLabel(f"<b>{sym}</b>  –  {TR('lbl_cur_price_colon')} {_fmt(cur_price * cur_s)}"))
                        _form = QHBoxLayout()
                        _form.addWidget(QLabel(TR("lbl_stop_loss_short")))
                        _stop_inp = QLineEdit(str(round(_lim2.get('stop', '') or '', 4)) if _lim2.get('stop') else "")
                        _stop_inp.setPlaceholderText(TR("ph_example_price", cur=sym_cur))
                        _form.addWidget(_stop_inp)
                        _dl.addLayout(_form)
                        _form2 = QHBoxLayout()
                        _form2.addWidget(QLabel(TR("lbl_target_price_short")))
                        _tgt_inp = QLineEdit(str(round(_lim2.get('target', '') or '', 4)) if _lim2.get('target') else "")
                        _tgt_inp.setPlaceholderText(TR("ph_example_price_target", cur=sym_cur))
                        _form2.addWidget(_tgt_inp)
                        _dl.addLayout(_form2)
                        _note = QLabel(TR("lbl_orig_currency_note", cur=sym_cur))
                        _note.setWordWrap(True)
                        _dl.addWidget(_note)
                        _btns = QHBoxLayout()
                        _ok = QPushButton(TR("btn_save_plain")); _ok.setDefault(True)
                        _clr = QPushButton(TR("btn_delete"))
                        _cancel = QPushButton(TR("btn_cancel"))
                        _btns.addWidget(_ok); _btns.addWidget(_clr); _btns.addWidget(_cancel)
                        _dl.addLayout(_btns)
                        def _save():
                            try:
                                s_val = float(_stop_inp.text().replace(',', '.')) if _stop_inp.text().strip() else None
                            except ValueError:
                                s_val = None
                            try:
                                t_val = float(_tgt_inp.text().replace(',', '.')) if _tgt_inp.text().strip() else None
                            except ValueError:
                                t_val = None
                            if s_val or t_val:
                                self._limits[sym] = {'stop': s_val, 'target': t_val}
                            else:
                                self._limits.pop(sym, None)
                            self._save_limits()
                            dlg.accept()
                            QTimer.singleShot(100, self.show_overview)
                        def _clear():
                            self._limits.pop(sym, None)
                            self._save_limits()
                            dlg.accept()
                            QTimer.singleShot(100, self.show_overview)
                        _ok.clicked.connect(_save)
                        _clr.clicked.connect(_clear)
                        _cancel.clicked.connect(dlg.reject)
                        dlg.exec()
                    return _on_dbl
                _price_lbl.mousePressEvent = _make_limit_dblclick(symbol, price_usd or 0, s, d.get('cur', 'USD'))
                rl.addWidget(_price_lbl)
                rl.addWidget(mk(f"{_fmt(val_usd*s)}",     120,  right=True))
                rl.addWidget(mk(f"{sign}{_fmt(abs(pnl_usd*s))}", 115, c_pnl, True, True))
                _pnl_pct_lbl = mk(f"{sign}{pnl_pct:.1f}%", 80, c_pnl, True, True)
                _ri = (pnl_pct / share_pct) if share_pct > 0 else 0
                _ri_icon = "✅" if _ri >= 1 else "⚠️"
                _pnl_pct_lbl.setToolTip(TR("tip_ri_factor",
                    share=share_pct, pnl_pct=pnl_pct, ri=_ri, icon=_ri_icon))
                rl.addWidget(_pnl_pct_lbl)
                rl.addWidget(mk(f"{share_pct:.1f}%",      75,  right=True))
                # Performance-Beitrag Spalte
                _pc_sign  = "+" if perf_contrib >= 0 else ""
                _pc_color = "#27ae60" if perf_contrib >= 0 else "#c0392b"
                _pc_tip   = (f"{TR('tip_perf_contrib_label')}:\n"
                             f"G&V {symbol}: {_pc_sign}{pnl_usd*s:,.0f}\n"
                             f"{TR('lbl_total_cost_portfolio')}: {total_cost_usd*s:,.0f}\n"
                             f"= {_pc_sign}{perf_contrib:.2f}%")
                _pc_lbl = mk(f"{_pc_sign}{perf_contrib:.1f}%", 100, _pc_color, bold=True, right=True)
                _pc_lbl.setToolTip(_pc_tip)
                rl.addWidget(_pc_lbl)

                # Sektor-Beitrag Spalte
                if _is_crypto(symbol) or _is_commodity(symbol):
                    _sc_lbl = mk("–", 105, "#aaa", right=True)
                    _sc_lbl.setToolTip(TR("tip_crypto_no_sector"))
                else:
                    _sc_canon = _get_sector_canon(symbol)
                    _sc_total = _sector_totals.get(_sc_canon, 0)
                    _sc_sign  = "+" if _sc_total >= 0 else ""
                    _sc_color = "#27ae60" if _sc_total >= 0 else "#922b21"
                    # Anzahl Aktien im selben Sektor
                    _sc_count = sum(1 for s2, _ in stocks_data if _get_sector_canon(s2) == _sc_canon)
                    _sc_tip = TR("tip_perf_contrib_sector", n=_sc_count, sector=_sc_canon, sign=_sc_sign, val=abs(_sc_total))
                    _sc_lbl = mk(f"{_sc_sign}{_sc_total:.1f}%", 105, _sc_color, bold=True, right=True)
                    _sc_lbl.setToolTip(_sc_tip)
                rl.addWidget(_sc_lbl)

                # 52W-Hoch / 52W-Tief Spalten
                _w52h_raw = d.get('w52_high')
                _w52l_raw = d.get('w52_low')
                if _is_crypto(symbol) or _is_commodity(symbol) or price_usd is None or _w52h_raw is None:
                    _w52h_lbl = mk("–", 70, "#aaa", right=True)
                    _w52l_lbl = mk("–", 70, "#aaa", right=True)
                else:
                    # Werte in Anzeigewährung umrechnen
                    _w52h = float(_w52h_raw) * s
                    _w52l = float(_w52l_raw) * s
                    _cur_disp = price_usd * s
                    # Farbe: aktueller Kurs nahe Jahreshoch → orange; nahe Jahrestief → rot
                    _pct_from_high = (_cur_disp - _w52h) / _w52h * 100 if _w52h > 0 else 0
                    _pct_from_low  = (_cur_disp - _w52l) / _w52l * 100 if _w52l  > 0 else 0
                    _h_color = "#e67e22" if _pct_from_high > -5 else "#555"
                    _l_color = "#c0392b" if _pct_from_low  <  10 else "#27ae60"
                    _w52h_lbl = mk(f"{_fmt(_w52h)}", 70, _h_color, right=True)
                    _w52l_lbl = mk(f"{_fmt(_w52l)}", 70, _l_color, right=True)
                    _w52h_lbl.setToolTip(
                        f"{TR('col_w52h')}: {_fmt(_w52h)}\n"
                        f"{TR('lbl_dist_from_high')}: {_pct_from_high:+.1f}%\n"
                        f"{TR('lbl_near_52w_high') if _pct_from_high > -5 else ''}"
                    )
                    _w52l_lbl.setToolTip(
                        f"{TR('col_w52l')}: {_fmt(_w52l)}\n"
                        f"{TR('lbl_dist_from_low')}: +{_pct_from_low:.1f}%\n"
                        f"{TR('lbl_near_52w_low') if _pct_from_low < 10 else ''}"
                    )
                rl.addWidget(_w52h_lbl)
                rl.addWidget(_w52l_lbl)

                _spacer = QWidget(); _spacer.setFixedWidth(28)
                rl.addWidget(_spacer)

                if _is_crypto(symbol) or _is_commodity(symbol):
                    _display_txt = ''
                    _tooltip_txt = ''
                else:
                    _raw_sector   = getattr(self, '_sector_cache',  {}).get(symbol, '')
                    _raw_industry = getattr(self, '_industry_cache', {}).get(symbol, '')
                    _company_name = getattr(self, '_company_cache',  {}).get(symbol, '')
                    if not _raw_sector or _raw_sector in ('Unknown', ''):
                        _display_txt = '–'
                        _tooltip_txt = ''
                    else:
                        _sector_canon, _ind_group, _industry_disp, _sub_industry = \
                            _gics_lookup(_raw_sector, _raw_industry)
                        if _sub_industry and _sub_industry != _sector_canon:
                            _display_txt = f"{_sector_canon}  ›  {_sub_industry}"
                        else:
                            _display_txt = _sector_canon
                        _tt = []
                        if _company_name:
                            _tt.append(_company_name); _tt.append("")
                        _tt.append(f"Sector:          {_sector_canon}")
                        if _ind_group:    _tt.append(f"Industry Group:  {_ind_group}")
                        if _industry_disp: _tt.append(f"Industry:        {_industry_disp}")
                        if _sub_industry and _sub_industry != _industry_disp:
                            _tt.append(f"Sub-Industry:    {_sub_industry}")
                        _tooltip_txt = "\n".join(_tt)

                sector_lbl = mk(_display_txt, 300, "#555")
                sector_lbl.setMinimumWidth(160)
                sector_lbl.setMaximumWidth(400)
                sector_lbl.setContentsMargins(12, 0, 0, 0)
                if _tooltip_txt:
                    sector_lbl.setToolTip(_tooltip_txt)
                rl.addWidget(sector_lbl)
                rl.addStretch()

                def make_click(sym):
                    def on_click(ev):
                        main_win = self.parent()
                        while main_win and not isinstance(main_win, QMainWindow):
                            p = main_win.parent() if hasattr(main_win, 'parent') else None
                            if p is None: break
                            main_win = p
                        chart_win = QDialog(main_win)
                        chart_win.setWindowTitle(f"📈 {sym}")
                        chart_win.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose, True)
                        chart_win.setWindowModality(Qt.WindowModality.NonModal)
                        layout_cw = QVBoxLayout(chart_win)
                        layout_cw.setContentsMargins(4, 4, 4, 4)
                        close_btn = QPushButton(TR("btn_close"))
                        close_btn.setMaximumWidth(160)
                        self._ef(close_btn)
                        close_btn.clicked.connect(chart_win.close)
                        layout_cw.addWidget(close_btn, alignment=Qt.AlignmentFlag.AlignLeft)
                        chart_widget = StockChartWidget(sym, zoom_mode=True,
                            avg_buy_price=avg_usd if price_usd else None)
                        _sym_lim = getattr(self, '_limits', {}).get(sym, {})
                        chart_widget.own_stop    = _sym_lim.get('stop')
                        chart_widget.own_target  = _sym_lim.get('target')
                        chart_widget._portfolio_ref = self  # für direkte Persistenz
                        chart_widget.maximize_requested.connect(lambda cw: chart_win.showMaximized())
                        layout_cw.addWidget(chart_widget)
                        if not hasattr(self, '_chart_windows'):
                            self._chart_windows = []
                        self._chart_windows.append(chart_win)
                        def _remove(cw=chart_win):
                            if cw in self._chart_windows: self._chart_windows.remove(cw)
                        chart_win.finished.connect(_remove)
                        chart_win.showMaximized()
                    return on_click
                sym_lbl.mousePressEvent = make_click(symbol)
                return row

            # ── Aktien/ETF-Zeilen ──────────────────────────────────────────
            for idx, (symbol, d) in enumerate(stocks_data):
                rows_layout.insertWidget(rows_layout.count()-1, _make_row(symbol, d, idx))

            # ── Trennbalken Krypto ─────────────────────────────────────────
            if crypto_data:
                sep = QWidget()
                sep.setFixedHeight(28)
                sep.setStyleSheet("background: #2c3e50;")
                sep_lbl = QLabel(TR("lbl_crypto_section"))
                sep_lbl.setStyleSheet(
                    "color: white; font-weight: bold; font-size: 11px; "
                    "background: #2c3e50; padding: 4px 8px;"
                )
                if _ov_emoji_font:
                    sep_lbl.setFont(_ov_emoji_font)
                sep_layout = QHBoxLayout(sep)
                sep_layout.setContentsMargins(0, 0, 0, 0)
                sep_layout.addWidget(sep_lbl)
                sep_layout.addStretch()
                rows_layout.insertWidget(rows_layout.count()-1, sep)

                for idx, (symbol, d) in enumerate(crypto_data):
                    rows_layout.insertWidget(rows_layout.count()-1, _make_row(symbol, d, idx))

            # ── Trennbalken Rohstoffe ──────────────────────────────────────
            if commodity_data:
                sep_c = QWidget()
                sep_c.setFixedHeight(28)
                sep_c.setStyleSheet("background: #7d6608;")
                sep_c_lbl = QLabel(TR("lbl_commodity_section"))
                sep_c_lbl.setStyleSheet(
                    "color: white; font-weight: bold; font-size: 11px; "
                    "background: #7d6608; padding: 4px 8px;"
                )
                if _ov_emoji_font:
                    sep_c_lbl.setFont(_ov_emoji_font)
                sep_c_layout = QHBoxLayout(sep_c)
                sep_c_layout.setContentsMargins(0, 0, 0, 0)
                sep_c_layout.addWidget(sep_c_lbl)
                sep_c_layout.addStretch()
                rows_layout.insertWidget(rows_layout.count()-1, sep_c)

                for idx, (symbol, d) in enumerate(commodity_data):
                    rows_layout.insertWidget(rows_layout.count()-1, _make_row(symbol, d, idx))

            # ── Summenzeile: Gesamt | Aktien/ETFs | Krypto ────────────────
            def _group_totals(group):
                v_usd = sum(d['value_usd'] for _, d in group)
                c_usd = sum(d['cost_usd']  for _, d in group)
                v_chf = sum(d.get('value_chf', 0) for _, d in group)
                c_chf = sum(d.get('cost_chf',  0) for _, d in group)
                pnl   = v_usd - c_usd
                if c_chf > 0 and v_chf > 0:
                    pct = (v_chf - c_chf) / c_chf * 100
                else:
                    pct = pnl / c_usd * 100 if c_usd > 0 else 0
                return v_usd, c_usd, pnl, pct

            cur_sym = {"USD":"$","CHF":"Fr.","EUR":"€","GBP":"£"}.get(cur, cur)

            # Gesamt
            total_pnl = total_value_usd - total_cost_usd
            if total_cost_chf > 0 and total_value_chf > 0:
                total_pct = (total_value_chf - total_cost_chf) / total_cost_chf * 100
            else:
                total_pct = total_pnl / total_cost_usd * 100 if total_cost_usd > 0 else 0
            c_t   = "#27ae60" if total_pct >= 0 else "#c0392b"
            sgn_t = "+" if total_pct >= 0 else ""

            # Tagesverlust/-gewinn berechnen
            day_pnl_usd = 0.0
            day_base_usd = 0.0
            for _, d in data:
                pc = d.get('prev_close_usd')
                if pc and pc > 0:
                    qty_d = d.get('qty', 0)
                    day_pnl_usd  += (d['price_usd'] - pc) * qty_d
                    day_base_usd += pc * qty_d
            day_pct = (day_pnl_usd / day_base_usd * 100) if day_base_usd > 0 else 0
            c_day   = "#27ae60" if day_pct >= 0 else "#c0392b"
            sgn_day = "+" if day_pct >= 0 else ""

            parts = [
                f"<b>Total ({cur}):</b>  "
                f"Inv: <b>{cur_sym} {_fmt(total_cost_usd*fx, 0)}</b>  "
                f"Akt: <b>{cur_sym} {_fmt(total_value_usd*fx, 0)}</b>  "
                f"G&amp;V: <b><span style='color:{c_t}'>{sgn_t}{cur_sym} {_fmt(abs(total_pnl*fx), 0)} ({sgn_t}{total_pct:.1f}%)</span></b>"
                + (f"  &nbsp;&nbsp;│&nbsp;&nbsp; <b>{TR('lbl_today')}:</b> <b><span style='color:{c_day}'>{sgn_day}{cur_sym} {_fmt(abs(day_pnl_usd*fx), 0)} ({sgn_day}{day_pct:.1f}%)</span></b>"
                   if day_base_usd > 0 else "")
            ]

            # Aktien/ETFs
            if stocks_data:
                sv, sc, sp, spct = _group_totals(stocks_data)
                c_s   = "#27ae60" if spct >= 0 else "#c0392b"
                sgn_s = "+" if spct >= 0 else ""
                parts.append(
                    f"&nbsp;&nbsp;│&nbsp;&nbsp;<b>{TR('lbl_stocks_etf_footer')}</b>  "
                    f"Inv: <b>{cur_sym} {_fmt(sc*fx, 0)}</b>  "
                    f"Akt: <b>{cur_sym} {_fmt(sv*fx, 0)}</b>  "
                    f"G&amp;V: <b><span style='color:{c_s}'>{sgn_s}{cur_sym} {_fmt(abs(sp*fx), 0)} ({sgn_s}{spct:.1f}%)</span></b>"
                )

            # Krypto
            if crypto_data:
                cv, cc_val, cp, cpct = _group_totals(crypto_data)
                c_c   = "#27ae60" if cpct >= 0 else "#c0392b"
                sgn_c = "+" if cpct >= 0 else ""
                parts.append(
                    f"&nbsp;&nbsp;│&nbsp;&nbsp;<b>🪙 {TR('lbl_krypto_row')}:</b>  "
                    f"Inv: <b>{cur_sym} {_fmt(cc_val*fx, 0)}</b>  "
                    f"Akt: <b>{cur_sym} {_fmt(cv*fx, 0)}</b>  "
                    f"G&amp;V: <b><span style='color:{c_c}'>{sgn_c}{cur_sym} {_fmt(abs(cp*fx), 0)} ({sgn_c}{cpct:.1f}%)</span></b>"
                )

            # Rohstoffe
            if commodity_data:
                cmv, cmc, cmp, cmpct = _group_totals(commodity_data)
                c_m   = "#27ae60" if cmpct >= 0 else "#c0392b"
                sgn_m = "+" if cmpct >= 0 else ""
                parts.append(
                    f"&nbsp;&nbsp;│&nbsp;&nbsp;<b>🥇 {TR('lbl_commodities')}:</b>  "
                    f"Inv: <b>{cur_sym} {_fmt(cmc*fx, 0)}</b>  "
                    f"Akt: <b>{cur_sym} {_fmt(cmv*fx, 0)}</b>  "
                    f"G&amp;V: <b><span style='color:{c_m}'>{sgn_m}{cur_sym} {_fmt(abs(cmp*fx), 0)} ({sgn_m}{cmpct:.1f}%)</span></b>"
                )

            if sum_label2 is not None:
                # Full HD: beide Zeilen als HTML-Tabelle mit fixer Spaltenbreite
                # Spalte 1 (td[0]): "Total … │ Heute …" – gleiche Breite in Zeile 1+2
                # Spalte 2 (td[1]): "│ Aktien/ETFs …" / "│ Krypto … │ Rohstoffe …"
                # QLabel rendert HTML-Tabellen → Spaltenbreite wird automatisch angeglichen
                # parts: [0]=Total(+Heute), [1]=Aktien/ETFs, [2]=Krypto, [3]=Rohstoffe
                # parts[1..] beginnen bereits mit "&nbsp;&nbsp;│&nbsp;&nbsp;"
                # left1 = Total+Heute (ohne abschliessenden │)
                # right1/right2 = Aktien/Krypto/Rohstoffe (behalten ihr führendes │)
                left1  = parts[0] if parts else ""
                right1 = parts[1] if len(parts) > 1 else ""
                right2 = "  ".join(parts[2:]) if len(parts) > 2 else ""

                # Beide Zeilen in einer HTML-Tabelle → linke Spalte exakt gleich breit
                html = (
                    "<table style='border-collapse:collapse;white-space:nowrap;'>"
                    f"<tr><td>{left1}</td><td>{right1}</td></tr>"
                    f"<tr><td></td><td>{right2}</td></tr>"
                    "</table>"
                )
                sum_label.setText(html)
                sum_label2.setVisible(False)   # wird nicht mehr benötigt
            else:
                sum_label.setText("  ".join(parts))

        # Header-Buttons: Sortierung umschalten
        for key, (b, _) in hdr_btns.items():
            def make_sort(k):
                def on_sort():
                    if sort_state['col'] == k:
                        sort_state['asc'] = not sort_state['asc']
                    else:
                        sort_state['col'] = k
                        sort_state['asc'] = (k == 'sym')
                    build_rows()
                return on_sort
            b.clicked.connect(make_sort(key))

        # Währungs-Buttons
        def on_cur(c):
            self._ov_currency = c
            for cc, bb in cur_btns.items():
                bb.setChecked(cc == c)
            try:
                _app_config.save_config({'portfolio_currency': c})
            except Exception:
                pass
            # GBP live nachladen falls noch nicht im FX-Cache
            if c == 'GBP' and self._ov_fx.get('GBP', 1.0) == 1.0:
                try:
                    import yfinance as yf
                    r = float(yf.Ticker('GBPUSD=X').fast_info.last_price)
                    if r > 0:
                        self._ov_fx['GBP'] = 1.0 / r
                except Exception:
                    pass
            build_rows()
        for c, b in cur_btns.items():
            b.clicked.connect(lambda _, cc=c: on_cur(cc))

        # Referenz für do_clear_all
        self._ov_build_rows = build_rows

        # ── Worker ──────────────────────────────────────────────────────────
        class OverviewWorker(QThread):
            progress   = pyqtSignal(int, int, str)
            data_ready = pyqtSignal(dict)
            _FX = {
                'JPY': ('JPY=X',    True),
                'KRW': ('KRW=X',    True),
                'HKD': ('HKD=X',    True),
                'EUR': ('EURUSD=X', False),
                'CHF': ('CHFUSD=X', False),
                'GBP': ('GBPUSD=X', False),
                'GBp': ('GBPUSD=X', False),
                'CAD': ('CADUSD=X', False),
                'AUD': ('AUDUSD=X', False),
                'SEK': ('SEKUSD=X', False),
                'SGD': ('SGDUSD=X', False),
                'TWD': ('TWD=X', True),
            }
            def __init__(self, pdata, parent=None):
                super().__init__(parent)
                self._data = pdata
            def _fx(self, cur, cache):
                if cur in ('USD', ''): return 1.0
                if cur in cache:       return cache[cur]
                entry = self._FX.get(cur)
                if not entry:
                    cache[cur] = 1.0; return 1.0
                pair, inv = entry
                try:
                    import yfinance as yf
                    r = float(yf.Ticker(pair).fast_info.last_price)
                    if inv: r = 1.0/r if r > 0 else 1.0
                    if cur == 'GBp': r /= 100
                    cache[cur] = r
                except Exception:
                    cache[cur] = 1.0
                return cache[cur]
            def _fx_to_chf(self, cur, cache):
                """Gibt zurück: wie viele CHF pro 1 Einheit 'cur' (heute)."""
                if cur in ('CHF', ''):
                    return 1.0
                ck = f"{cur}_CHF"
                if ck in cache:
                    return cache[ck]
                try:
                    import yfinance as yf
                    ticker = f"{cur}CHF=X"
                    rate = float(yf.Ticker(ticker).fast_info.last_price)
                    if cur == 'GBp':
                        rate /= 100
                    cache[ck] = rate
                    return rate
                except Exception:
                    cache[ck] = 1.0
                    return 1.0

            def run(self):
                import yfinance as yf
                fx_cache = {}
                results  = {}
                syms     = list(self._data.keys())
                total    = len(syms)
                # Display-FX vorladen (für USD/CHF/EUR Umschaltung in der Tabelle)
                fx_disp = {}
                for dc in ['USD','CHF','EUR','GBP']:
                    r = self._fx(dc, fx_cache)
                    fx_disp[dc] = 1.0/r if r > 0 else 1.0
                fx_disp['USD'] = 1.0
                results['__fx__'] = fx_disp
                for i, sym in enumerate(syms):
                    self.progress.emit(i+1, total, sym)
                    positions = self._data[sym]
                    if '=' in sym:
                        results[sym] = {'skip': True, 'qty':0,'cur':'FX','price_usd':None,'cost_usd':0,'value_usd':0}
                        continue
                    # ── Rohstoffe (XAU/XAG) ──────────────────────────────
                    if _is_commodity(sym):
                        primary, fallback = _COMMODITY_YAHOO.get(sym.upper(), ('XAUUSD=X', 'GC=F'))
                        price = None
                        for ticker_sym in (primary, fallback):
                            try:
                                t = yf.Ticker(ticker_sym)
                                fi = t.fast_info
                                for attr in ('last_price', 'lastPrice', 'regularMarketPrice'):
                                    v = getattr(fi, attr, None)
                                    if v is None and hasattr(fi, 'get'):
                                        v = fi.get(attr)
                                    if v and float(v) > 0:
                                        price = float(v); break
                                if price and price > 0:
                                    break
                                h = t.history(period='2d')
                                if not h.empty:
                                    price = float(h['Close'].iloc[-1]); break
                            except Exception:
                                continue
                        qty = sum(p['quantity'] for p in positions)
                        if price and price > 0:
                            cost_usd = sum(p['buy_price']*p['quantity'] for p in positions)
                            val_usd  = price * qty
                            results[sym] = {
                                'qty': qty, 'cur': 'USD', 'price_usd': price,
                                'cost_usd': cost_usd, 'value_usd': val_usd,
                                'cost_chf': cost_usd * self._fx_to_chf('USD', fx_cache),
                                'value_chf': val_usd * self._fx_to_chf('USD', fx_cache),
                                'w52_high': None, 'w52_low': None,
                            }
                        else:
                            results[sym] = {'qty': qty, 'cur': 'USD', 'price_usd': None,
                                            'cost_usd': 0, 'value_usd': 0,
                                            'cost_chf': 0, 'value_chf': 0}
                        continue
                    try:
                        info  = yf.Ticker(sym).fast_info
                        price = float(info.last_price)
                        cur   = getattr(info, 'currency', 'USD') or 'USD'
                        fx_to_usd  = self._fx(cur, fx_cache)       # instrument → USD
                        fx_to_chf  = self._fx_to_chf(cur, fx_cache)  # instrument → CHF (heute)
                        pusd       = price * fx_to_usd
                        qty        = sum(p['quantity'] for p in positions)
                        val_usd    = pusd * qty
                        val_chf    = price * fx_to_chf * qty

                        # Einstandswert in CHF: buy_price × qty × hist_fx_to_chf (zum Kaufdatum)
                        # Fallback: buy_price × qty × fx_to_chf_today (wenn kein hist_fx)
                        cost_chf = 0.0
                        for p in positions:
                            hfx = p.get('hist_fx_to_chf')
                            if hfx is not None and hfx > 0:
                                cost_chf += p['buy_price'] * p['quantity'] * hfx
                            else:
                                # Fallback: heute's FX (weniger genau, aber besser als 0)
                                cost_chf += p['buy_price'] * p['quantity'] * fx_to_chf

                        # USD-Einstand für Tabellenspalte "Kauf∅"
                        cost_usd = sum(p['buy_price']*p['quantity'] for p in positions) * fx_to_usd

                        # 52W aus History berechnen (zuverlässiger als fast_info Attribute)
                        w52h = None; w52l = None
                        try:
                            import math as _math
                            _hist = yf.Ticker(sym).history(period='1y')
                            if not _hist.empty and 'High' in _hist.columns and 'Low' in _hist.columns:
                                _hv = float(_hist['High'].max())
                                _lv = float(_hist['Low'].min())
                                if not _math.isnan(_hv): w52h = _hv
                                if not _math.isnan(_lv): w52l = _lv
                        except Exception:
                            pass

                        results[sym] = {
                            'qty':      qty,
                            'cur':      cur,
                            'price_usd': pusd,
                            'cost_usd': cost_usd,
                            'value_usd': val_usd,
                            'cost_chf': cost_chf,   # historisch gewichtet
                            'value_chf': val_chf,   # aktuell in CHF
                            'w52_high': w52h,
                            'w52_low':  w52l,
                        }
                    except Exception:
                        results[sym] = {'qty': sum(p['quantity'] for p in positions),
                                        'cur': '', 'price_usd': None,
                                        'cost_usd': 0, 'value_usd': 0,
                                        'cost_chf': 0, 'value_chf': 0}
                self.data_ready.emit(results)

        worker = OverviewWorker(self.portfolio_data, parent=self)
        self._overview_worker = worker

        def on_progress(cur, tot, sym):
            try:
                status_label.setText(TR("status_loading_sym", sym=sym, cur=cur, tot=tot))
            except RuntimeError:
                pass

        def on_data(results):
            import datetime as _dt
            _ts = _dt.datetime.now().strftime("%H:%M")
            try:
                status_label.setText(TR("lbl_updated_at", ts=_ts))
            except RuntimeError:
                pass
            self._overview_cache    = results
            self._overview_cache_ts = self._time.time()
            self._ov_data = results
            self._ov_fx   = results.get('__fx__', {'USD':1.0,'CHF':1.0,'EUR':1.0,'GBP':1.0})
            build_rows()

        now_ts = self._time.time()
        ov_age = now_ts - self._overview_cache_ts
        if self._overview_cache and ov_age < self._OVERVIEW_CACHE_TTL:
            # Cache vorhanden: sofort anzeigen
            self._ov_data = self._overview_cache
            self._ov_fx   = self._overview_cache.get('__fx__', {'USD':1.0,'CHF':1.0,'EUR':1.0,'GBP':1.0})
            try:
                status_label.setText(TR("status_from_cache"))
            except RuntimeError:
                pass
            build_rows()
            # Stilles Hintergrund-Update wenn > 60s
            if ov_age > 60:
                worker.progress.connect(on_progress, Qt.ConnectionType.QueuedConnection)
                worker.data_ready.connect(on_data, Qt.ConnectionType.QueuedConnection)
                worker.start()
        else:
            worker.progress.connect(on_progress, Qt.ConnectionType.QueuedConnection)
            worker.data_ready.connect(on_data,    Qt.ConnectionType.QueuedConnection)
            worker.start()
        # Fenster bereits oben konfiguriert


