        _worker_ref = [None]

        def build_portfolio_summary():
            """Baut einen kompakten Portfolio-Text für den API-Prompt."""
            price_cache  = self._price_cache or {}
            sector_cache = self._sector_cache or {}
            CRYPTO_SFXS  = ('-USD','-EUR','-CHF','-BTC')
            def is_crypto(s): return any(s.upper().endswith(x) for x in CRYPTO_SFXS)

            lines = []
            total_val  = 0.0
            total_cost = 0.0
            positions  = []

            for sym, pos_list in self.portfolio_data.items():
                d = price_cache.get(sym, {})
                if not isinstance(d, dict): continue
                val  = d.get('value_usd', 0)
                cost = d.get('cost_usd', 0)
                if val <= 0: continue
                pct    = (val - cost) / cost * 100 if cost > 0 else 0.0
                sector = sector_cache.get(sym, 'Unbekannt')
                is_cr  = is_crypto(sym)
                total_val  += val
                total_cost += cost
                positions.append((sym, val, cost, pct, sector, is_cr))

            positions.sort(key=lambda x: x[1], reverse=True)

            total_pct = (total_val - total_cost) / total_cost * 100 if total_cost > 0 else 0.0
            lines.append(f"Gesamtportfolio: Investiert ${total_cost:,.0f} | Aktuell ${total_val:,.0f} | G&V {total_pct:+.1f}%")
            lines.append(f"Anzahl Positionen: {len(positions)}")
            lines.append("")
            lines.append("Positionen (sortiert nach aktuellem Wert):")

            for sym, val, cost, pct, sector, is_cr in positions:
                weight = val / total_val * 100 if total_val > 0 else 0
                asset_type = TR("lbl_krypto_row") if is_cr else TR("lbl_aktie_etf")
                lines.append(f"  {sym:<12} {asset_type:<12} Sektor: {sector:<22} "
                              f"Wert: ${val:>9,.0f} ({weight:.1f}%)  G&V: {pct:+.1f}%")

            # Sektorverteilung
            sector_vals = {}
            for sym, val, cost, pct, sector, is_cr in positions:
                if not is_cr:
                    sector_vals[sector] = sector_vals.get(sector, 0) + val
            lines.append("")
            lines.append(TR("chart_sector_dist"))
            stock_val = sum(v for _, v in sector_vals.items())
            for sec, v in sorted(sector_vals.items(), key=lambda x: x[1], reverse=True):
                lines.append(f"  {sec:<28} {v/stock_val*100:.1f}%" if stock_val > 0 else f"  {sec}")

            # Top 5 Gewinner / Verlierer
            sorted_pct = sorted(positions, key=lambda x: x[2])
            top5_win = sorted(positions, key=lambda x: x[3], reverse=True)[:5]
            top5_los = sorted(positions, key=lambda x: x[3])[:5]
            lines.append("")
            lines.append(TR("chart_top5_winners") + ": " + ", ".join(f"{s[0]} ({s[3]:+.1f}%)" for s in top5_win))
            lines.append(TR("chart_top5_losers") + ": " + ", ".join(f"{s[0]} ({s[3]:+.1f}%)" for s in top5_los))

            return "\n".join(lines)

        def do_analyse():
            focus = focus_combo.currentText()
            refresh_btn.setEnabled(False)
            focus_combo.setEnabled(False)
            text_area.setHtml(
                TR("ki_analysing"))
            QApplication.processEvents()

            summary = build_portfolio_summary()

            focus_prompts = {
                TR("ki_focus_overview"):  TR("ki_prompt_overview"),
                TR("ki_focus_risk"):      TR("ki_prompt_risk"),
                TR("ki_focus_strengths"): TR("ki_prompt_strengths"),
                TR("ki_focus_sectors"):   TR("ki_prompt_sectors"),
                TR("ki_focus_optimize"):  TR("ki_prompt_optimize"),
            }

            system_prompt = TR("ki_system_prompt")

            _focus_key_map = {
                TR("ki_focus_overview"):  "Gesamtübersicht",
                TR("ki_focus_risk"):      "Risiko & Diversifikation",
                TR("ki_focus_strengths"): "Stärken & Schwächen",
                TR("ki_focus_sectors"):   "Sektoren & Klumpenrisiken",
                TR("ki_focus_optimize"):  "Optimierungsvorschläge",
            }
            user_prompt = (
                f"Portfolio data:\n\n{summary}\n\n"
                f"Task: {focus_prompts.get(_focus_key_map.get(focus, focus), list(focus_prompts.values())[0])}"
            )

            class KIWorker(QThread):
                done  = pyqtSignal(str)

                def __init__(self, system, user, api_key):
                    super().__init__()
                    self._sys  = system
                    self._user = user
                    self._key  = api_key

                def run(self):
                    try:
                        import urllib.request, urllib.error, json
                        # Gemini API: system + user als kombinierter Prompt
                        combined = f"{self._sys}\n\n{self._user}"
                        payload = {
                            "contents": [{"parts": [{"text": combined}]}],
                            "generationConfig": {"maxOutputTokens": 4000, "temperature": 0.7}
                        }
                        url = (f"https://generativelanguage.googleapis.com/v1beta/models"
                               f"/gemini-2.5-flash:generateContent?key={self._key}")
                        req = urllib.request.Request(
                            url,
                            data=json.dumps(payload).encode(),
                            headers={"Content-Type": "application/json"},
                            method="POST"
                        )
                        try:
                            with urllib.request.urlopen(req, timeout=30) as resp:
                                data = json.loads(resp.read())
                            text = (data.get("candidates", [{}])[0]
                                       .get("content", {})
                                       .get("parts", [{}])[0]
                                       .get("text", "Keine Antwort erhalten."))
                            self.done.emit(text)
                        except urllib.error.HTTPError as e:
                            body = e.read().decode('utf-8', errors='replace')
                            self.done.emit(f"<i>HTTP {e.code}: {body}</i>")
                    except Exception as ex:
                        self.done.emit(f"<i>{TR("lbl_error_generic", e=ex)}</i>")

            def on_done(text):
                try:
                    refresh_btn.setEnabled(True)
                    focus_combo.setEnabled(True)
                    # Markdown → HTML konvertieren
                    import re
                    html = text
                    # **fett** → <b>fett</b>
                    html = re.sub(r'\*\*(.+?)\*\*', r'<b>\1</b>', html)
                    # ### Überschrift → <h3>
                    html = re.sub(r'^### (.+)$', r'<h3>\1</h3>', html, flags=re.MULTILINE)
                    html = re.sub(r'^## (.+)$',  r'<h3>\1</h3>', html, flags=re.MULTILINE)
                    html = re.sub(r'^# (.+)$',   r'<h3>\1</h3>', html, flags=re.MULTILINE)
                    # Zeilenumbrüche
                    html = re.sub(r'\n\n', '<br><br>', html)
                    html = re.sub(r'\n',   '<br>',     html)
                    # Bullet points
                    html = re.sub(r'<br>•', '<br>&bull;', html)
                    text_area.setHtml(
                        f"<div style='font-family:Arial,sans-serif; font-size:14px; "
                        f"line-height:1.7; color:#2c3e50;'>{html}</div>")
                    _ki_export_data[0] = {
                        'title': TR("export_title_ki_analysis", focus=focus),
                        'headers': [TR("export_col_ki_header")],
                        'rows': [[line] for line in text.split('\n') if line.strip()],
                        'fig': None,
                    }
                except RuntimeError:
                    pass  # Dialog wurde geschlossen bevor Worker fertig war

            w = KIWorker(system_prompt, user_prompt, api_key)
            _worker_ref[0] = w
            w.finished.connect(w.deleteLater)  # GC-safe thread cleanup
            w.done.connect(on_done, Qt.ConnectionType.QueuedConnection)
            w.start()

        refresh_btn.clicked.connect(do_analyse)
        focus_combo.currentIndexChanged.connect(do_analyse)
        QTimer.singleShot(200, do_analyse)
        import sys as _sys_ai
        if _sys_ai.platform == 'win32':
            dialog.finished.connect(lambda: (self.raise_(), self.activateWindow()))
        dialog.exec()


