        hdr_row.addWidget(_hdr("Analyst",         85))
        hdr_row.addWidget(_hdr("News",            70))
        hdr_row.addWidget(_hdr(TR("col_score"),           65))
        hdr_row.addWidget(_hdr(f"{TR('lbl_actual_value_usd').replace('USD', _disp_cur)}", 120))
