        def draw_indices_chart(items, period_label):
            """items: [(name, pct, is_portfolio), ...]"""
            import math as _m
            _last_items_ref[0] = (items, period_label)
            show_pf = pf_cb.isChecked() and _has_portfolio
            # Portfolio-Eintrag herausfiltern wenn Checkbox aus
            display = [(n, p, ip) for n, p, ip in items
                       if _m.isfinite(p) and (not ip or show_pf)]
            if not display:
                fig.clear(); canvas.draw()
                return
            display.sort(key=lambda x: x[1], reverse=True)
            labels   = [i[0] for i in display]
            values   = [i[1] for i in display]
            is_pf    = [i[2] for i in display]
            n = len(labels)

            w_in = max(fig_w, n * 0.52)
            fig.set_size_inches(w_in, fig_h)
            px_w = int(w_in * 96)
            canvas.setMinimumWidth(px_w)
            canvas.setMaximumWidth(16777215)
            canvas.resize(px_w, int(fig_h * 96))

            fig.clear()
            ax = fig.add_subplot(111)
            ax.set_facecolor('#f9f9f9')
            fig.patch.set_facecolor('#f9f9f9')

            # Portfolio-Balken: leuchtendes Blau; Indizes: grün/rot
            colors = []
            for val, pf in zip(values, is_pf):
                if pf:
                    colors.append('#1a7fc4')   # Portfolio: Blau
                elif val >= 0:
                    colors.append('#2ecc71')   # Plus: Grün
                else:
                    colors.append('#e74c3c')   # Minus: Rot

            x_pos = range(n)
            bars  = ax.bar(x_pos, values, color=colors, width=0.6, zorder=2)

            # Wert-Labels auf Balken
            for bar, val, pf in zip(bars, values, is_pf):
                yoff = 0.3 if val >= 0 else -0.8
                lbl_color = '#0d4f8a' if pf else ('#1a7a3a' if val >= 0 else '#c0392b')
                ax.text(bar.get_x() + bar.get_width() / 2,
                        val + yoff,
                        f"{val:+.1f}%",
                        ha='center', va='bottom' if val >= 0 else 'top',
                        fontsize=8.5, fontweight='bold',
                        color=lbl_color)

            ax.set_xticks(list(x_pos))
            # Portfolio-Label fett markieren
            xlbls = ax.set_xticklabels(labels, rotation=45, ha='right', fontsize=9)
            for lbl_obj, pf in zip(xlbls, is_pf):
                if pf:
                    lbl_obj.set_fontweight('bold')
                    lbl_obj.set_color('#1a7fc4')

            ax.axhline(0, color='#888', linewidth=0.8, linestyle='--', zorder=1)
            ax.set_ylabel(TR("chart_ylabel_perf"), fontsize=10)
            ax.set_title(TR("chart_title_indices", period=period_label),
                         fontsize=12, fontweight='bold', pad=10)
            ax.yaxis.grid(True, linestyle='--', alpha=0.5, zorder=0)
            ax.set_axisbelow(True)
            for spine in ax.spines.values():
                spine.set_visible(False)

            fig.tight_layout(pad=1.5)
            fig.subplots_adjust(bottom=0.28)
            canvas.draw()

            # Hover-Tooltip
            _annot = ax.annotate("", xy=(0,0),
                                 xytext=(10, 10), textcoords="offset points",
                                 bbox=dict(boxstyle="round,pad=0.4", fc="#ffffcc", ec="#888", lw=1),
                                 fontsize=9, zorder=10)
            _annot.set_visible(False)

            def _on_hover(event):
                if event.inaxes != ax:
                    _annot.set_visible(False); canvas.draw_idle(); return
                for i, (bar, lbl, val) in enumerate(zip(bars, labels, values)):
                    if bar.contains(event)[0]:
                        _annot.xy = (bar.get_x() + bar.get_width()/2, val)
                        full = FULL_DESCRIPTIONS.get(lbl, lbl)
                        _annot.set_text(f"{full}\n{val:+.2f}%")
                        # Rechtes Viertel: Tooltip nach links spiegeln
                        if i >= len(bars) * 0.75:
                            _annot.xyann = (-10, 10)
                            _annot.set_ha('right')
                        else:
                            _annot.xyann = (10, 10)
                            _annot.set_ha('left')
                        _annot.set_visible(True); canvas.draw_idle(); return
                _annot.set_visible(False); canvas.draw_idle()

            canvas.mpl_connect('motion_notify_event', _on_hover)

