def _make_flag_btn(b64, tooltip, lang_code=None):
    """Erstellt einen Button mit eingebetteter farbiger Flagge.
    lang_code: wenn gesetzt, wird beim Klick auf diese Sprache umgeschaltet.
    Die aktive Sprache wird hervorgehoben, alle anderen gedimmt.
    """
    from PyQt6.QtGui import QPixmap, QIcon
    from PyQt6.QtCore import QByteArray, QSize
    import base64 as _b64
    btn = QPushButton()
    px = QPixmap()
    px.loadFromData(QByteArray(_b64.b64decode(b64)))
    btn.setIcon(QIcon(px))
    btn.setIconSize(QSize(48, 29))
    btn.setFixedWidth(42); btn.setFixedHeight(26)
    btn.setToolTip(tooltip)

    if lang_code is None:
        # Legacy: kein Klick möglich
        btn.setStyleSheet("QPushButton{border:1px solid #ccc;border-radius:3px;background:#f0f0f0;}"
                          "QPushButton:hover{background:#f0f0f0;border-color:#ccc;}")
        btn.setCursor(Qt.CursorShape.ForbiddenCursor)
    else:
        # Aktive Sprache = Rahmen hervorgehoben, inaktive = gedimmt
        try:
            current = _translations.get_language()
        except Exception:
            current = "DE"
        if lang_code == current:
            btn.setStyleSheet("QPushButton{border:2px solid #3498db;border-radius:3px;"
                              "background:transparent;}"
                              "QPushButton:hover{border:2px solid #3498db;background:transparent;}")
            btn.setCursor(Qt.CursorShape.ArrowCursor)
            btn.setToolTip(tooltip + " ✓ (aktiv / active)")
            # Nicht deaktivieren (würde Icon ausgrauen) – Click einfach ignorieren
            btn.clicked.connect(lambda: None)
        else:
            btn.setStyleSheet("QPushButton{border:1px solid #ccc;border-radius:3px;"
                              "background:#f0f0f0;opacity:0.7;}"
                              "QPushButton:hover{background:#e0e0e0;border-color:#aaa;}")
            btn.setCursor(Qt.CursorShape.PointingHandCursor)

        def _switch(checked=False, lc=lang_code):
            try:
                _app_config.save_config({"language": lc})
            except Exception:
                pass
            _s_target = _translations.STRINGS.get(lc, {})
            reply = QMessageBox.question(
                None,
                _s_target.get("lang_switch_title", TR("lang_switch_title")),
                _s_target.get("lang_switch_msg",   TR("lang_switch_msg")),
                QMessageBox.StandardButton.Ok | QMessageBox.StandardButton.Cancel
            )
            if reply == QMessageBox.StandardButton.Ok:
                import os, sys
                # Session speichern (globaler Zeitraum, MA-Checkboxen, Charts) vor Neustart
                try:
                    # activeWindow() gibt ggf. den Dialog zurück — alle Fenster durchsuchen
                    _main_win = None
                    for _w in QApplication.instance().topLevelWidgets():
                        if hasattr(_w, 'save_config') and hasattr(_w, 'global_timeframe'):
                            _main_win = _w
                            break
                    if _main_win:
                        _main_win.save_config()
                except Exception:
                    pass
                os.execv(sys.executable, [sys.executable] + sys.argv)

        if lang_code != current:
            btn.clicked.connect(_switch)
    return btn

class StockMonitorApp(QMainWindow):
    """Hauptfenster mit 4 oder 6 Charts"""
    
    def __init__(self):
        super().__init__()
        
        self.charts = []
        self.fullscreen_widget = None
        self.saved_states = []
        self.config_file = os.path.join(_DATA_HOME, ".stock_monitor_config.pkl")
        self.favorites_file = os.path.join(_DATA_HOME, ".stock_monitor_favorites.json")
        self._dollar_anim = None
        self.is_loading = True
        self._app_limits = self._load_limits_app()  # Stop-Loss/Zielkurs für Haupt-Charts
        
        # Zeige Loading Dialog (kein Parent → erscheint zentriert auf dem Bildschirm)
        self.loading_dialog = LoadingDialog()
        self.loading_dialog.show()
        
        # Echten animierten Progress-Timer starten
        self._startup_progress = 5.0
        self._startup_target = 10.0
        self._startup_timer = QTimer()
        self._startup_timer.setInterval(50)  # 50ms = flüssige Animation
        self._startup_timer.timeout.connect(self._animate_startup_progress)
        self._startup_timer.start()
        
        # Initialisierung verzögert starten damit Dialog gerendert wird
        QTimer.singleShot(150, self._deferred_init)
    
    def _animate_startup_progress(self):
        """Animiert den Progress-Balken während des Ladens - läuft immer flüssig"""
        target = self._startup_target
        if self._startup_progress < target:
            # Verlangsame gegen Ende für realistischeren Effekt
            step = max(0.3, (target - self._startup_progress) * 0.04)
            self._startup_progress = min(target, self._startup_progress + step)
            self.loading_dialog.progress.setValue(int(self._startup_progress))
    
    def _deferred_init(self):
        """Schritt 1: Favoriten laden"""
        self._startup_target = 22.0
        self.loading_dialog.update_progress(10, TR("lbl_loading_dialog"))
        self.favorites = self.load_favorites()
        QTimer.singleShot(80, self._init_step2)

    def _init_step2(self):
        """Schritt 2: UI erstellen"""
        self._startup_target = 48.0
        self.loading_dialog.update_progress(28, TR("status_creating_ui"))
        self.setup_ui()
        QTimer.singleShot(80, self._init_step3)

    def _init_step3(self):
        """Schritt 3: Config laden"""
        self._startup_target = 72.0
        self.loading_dialog.update_progress(50, TR("status_loading_line2"))
        self.load_config()
        QTimer.singleShot(80, self._init_step4)

    def _init_step4(self):
        """Schritt 4: Standard-Charts erstellen falls nötig"""
        if not self.charts:
            self._startup_target = 88.0
            self.loading_dialog.update_progress(65, TR("status_creating_charts"))
            _sw = QApplication.primaryScreen().size().width() if QApplication.primaryScreen() else 1920
            _default_charts = 16 if _sw >= 3840 else 12
            self.create_charts(_default_charts)
        QTimer.singleShot(80, self._init_step5)

    def _init_step5(self):
        """Schritt 5: Finalisieren"""
        self._startup_target = 99.0
        self.loading_dialog.update_progress(90, TR("status_finalizing"))
        self.is_loading = False
        self.setup_timer()
        QTimer.singleShot(200, self._init_finish)

    def _init_finish(self):
        """Abschluss: Fenster anzeigen, Dialog schliessen"""
        self._startup_timer.stop()
        self.loading_dialog.update_progress(100, TR("status_ready"))
        self.showMaximized()
        self.raise_()
        self.activateWindow()
        self._ready = True  # Ab jetzt: Custom-Zeitraum-Dialog erlaubt
        QTimer.singleShot(500, self.loading_dialog.close)
        # Kurz WindowStaysOnTopHint setzen damit das Fenster nach Update-Neustart
        # zuverlässig im Vordergrund erscheint (Windows Focus-Stealing-Prevention umgehen)
        QTimer.singleShot(600, self._force_to_front)
        # Update-Checks im Hintergrund – erst nach 5 s starten damit die UI fertig ist
        QTimer.singleShot(5000, self._startup_update_checks)

    def _force_to_front(self):
        self.raise_()
        self.activateWindow()
        if sys.platform == "win32":
            try:
                import ctypes
                hwnd = int(self.winId())
                ctypes.windll.user32.ShowWindow(hwnd, 9)   # SW_RESTORE
                ctypes.windll.user32.SetForegroundWindow(hwnd)
                ctypes.windll.user32.BringWindowToTop(hwnd)
            except Exception:
                pass
        # Fallback: WindowStaysOnTopHint kurz setzen
        self.setWindowFlag(Qt.WindowType.WindowStaysOnTopHint, True)
        self.show()
        QTimer.singleShot(1500, self._unflag_on_top)

    def _unflag_on_top(self):
        self.setWindowFlag(Qt.WindowType.WindowStaysOnTopHint, False)
        self.show()

    def closeEvent(self, event):
        QApplication.instance().quit()
        event.accept()

    def setup_ui(self):
        """UI initialisieren"""
        self.setWindowTitle(TR("title_app"))
        
        # Hole Bildschirmgröße (für spätere Berechnungen)
        screen = QApplication.primaryScreen().geometry()
        max_width = screen.width()
        max_height = screen.height()
        
        # Kein setMaximumSize mehr – maximiertes Fenster passt sich selbst an
        # Minimalgröße damit Charts noch lesbar sind
        self.setMinimumSize(800, 600)
        
        # QStackedWidget: Seite 0 = App-Inhalt, Seite 1 = Portfolio-Übersicht
        self._app_stack = QStackedWidget()
