    # ── Limits für Haupt-Charts (unabhängig vom PortfolioDialog) ─────────────

    def _limits_file_app(self) -> str:
        """Feste, portfoliounabhängige Limits-Datei für die Haupt-Charts der App."""
        return os.path.join(_DATA_HOME, ".stock_monitor_chart_limits.json")

    def _load_limits_app(self) -> dict:
        """Lädt Stop-Loss/Zielkurse für Haupt-Charts (portfoliospezifisch)."""
        try:
            lpath = self._limits_file_app()
            if os.path.exists(lpath):
                with open(lpath, 'r') as f:
                    return json.load(f)
        except Exception:
            pass
        return {}

    def _save_limit_app(self, sym: str, stop, target):
        """Speichert einen Alarm aus dem Haupt-Chart (portfoliospezifisch)."""
        if stop or target:
            self._app_limits[sym] = {'stop': stop, 'target': target}
        else:
            self._app_limits.pop(sym, None)
        try:
            with open(self._limits_file_app(), 'w') as f:
                json.dump(self._app_limits, f, indent=2)
        except Exception:
            pass

    def open_portfolio_dialog(self):
        """Portfolio öffnen – Übersicht ersetzt App-Inhalt im Hauptfenster"""

        # ── Sofort Lade-Bildschirm im Hauptfenster zeigen ──────────────────
        # Damit der User sofort Feedback bekommt, auch bevor Daten geladen sind
        def _show_loading_screen():
            loading = QWidget()
            loading.setStyleSheet("background-color: #f0f8ff;")
            lay = QVBoxLayout(loading)
            lay.setAlignment(Qt.AlignmentFlag.AlignCenter)
            lay.setSpacing(16)
            from PyQt6.QtGui import QFontDatabase
            _fams = QFontDatabase.families()
            _efont = ("Segoe UI Emoji" if "Segoe UI Emoji" in _fams else
                      "Noto Color Emoji" if "Noto Color Emoji" in _fams else "Arial")
            ico = QLabel("💵")
            ico.setFont(QFont(_efont, 64))
            ico.setAlignment(Qt.AlignmentFlag.AlignCenter)
            lay.addWidget(ico)
            lbl = QLabel(TR("lbl_loading_portfolio"))
            lbl.setFont(QFont("Arial", 14, QFont.Weight.Bold))
            lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
            lbl.setStyleSheet("color: #2c3e50;")
            lay.addWidget(lbl)
            sub = QLabel(TR("lbl_yahoo_data_source"))
            sub.setFont(QFont("Arial", 10))
            sub.setAlignment(Qt.AlignmentFlag.AlignCenter)
            sub.setStyleSheet("color: #7f8c8d;")
            lay.addWidget(sub)
            # In _app_stack einbetten
            if self._app_stack.count() > 1:
                old = self._app_stack.widget(1)
                self._app_stack.removeWidget(old)
                old.deleteLater()
            self._app_stack.addWidget(loading)
            self._app_stack.setCurrentIndex(1)
            # Labels auf self (StockMonitorApp) speichern
            self._loading_screen_sub = sub
            self._loading_screen_lbl = lbl
            return loading, sub, lbl

        # ── Embed-Callback: ersetzt Lade-Screen durch echtes Portfolio ─────
        def _embed_overview(overview_widget):
            if self._app_stack.count() > 1:
                old = self._app_stack.widget(1)
                self._app_stack.removeWidget(old)
                old.deleteLater()
            self._app_stack.addWidget(overview_widget)
            self._app_stack.setCurrentIndex(1)

        # ── Bestehenden Dialog wiederverwenden (Cache!) ─────────────────────
        if hasattr(self, '_portfolio_dialog') and self._portfolio_dialog is not None:
            try:
                _ = self._portfolio_dialog.isVisible()
                self._portfolio_dialog._embed_callback = _embed_overview
                self._portfolio_dialog._open_overview_on_load = True
                import time as _t
                cache_age = _t.time() - self._portfolio_dialog._price_cache_ts
                if self._portfolio_dialog._price_cache and cache_age < 300:
                    # Cache frisch → sofort Übersicht, kein Lade-Screen nötig
                    QTimer.singleShot(50, self._portfolio_dialog.show_overview)
                else:
                    # Cache alt → Lade-Screen zeigen, dann laden
                    _, _sub2, _lbl2 = _show_loading_screen()
                    self._portfolio_dialog._main_loading_sub = _sub2
                    self._portfolio_dialog._main_loading_lbl = _lbl2
                    self._portfolio_dialog._master_load()
                return
            except RuntimeError:
                self._portfolio_dialog = None

        # ── Neuen Dialog erstellen (erster Aufruf) ──────────────────────────
        _, _sub, _lbl = _show_loading_screen()
        self._portfolio_dialog = PortfolioDialog(self.charts, self)
        self._portfolio_dialog.setWindowModality(Qt.WindowModality.NonModal)
        self._portfolio_dialog._embed_callback = _embed_overview
        self._portfolio_dialog._open_overview_on_load = True
        self._portfolio_dialog._hide_after_load = True
        # Labels direkt auf PortfolioDialog speichern damit _update_portfolio_loading
        # sie ohne parent()-Umweg beschreiben kann
        self._portfolio_dialog._main_loading_sub = _sub
        self._portfolio_dialog._main_loading_lbl = _lbl
        # QTimer in __init__ startet _master_load nach 80ms automatisch

    def open_favorites_dialog(self):
        """Öffne Favoriten-Dialog"""
        print(f">>> open_favorites_dialog aufgerufen, {len(self.favorites)} Favoriten")
        try:
            dialog = FavoritesDialog(self.favorites, self)
            print(f">>> Dialog erstellt, öffne jetzt...")
            
            # Stelle sicher dass Dialog im Vordergrund ist
            dialog.setWindowModality(Qt.WindowModality.ApplicationModal)
            dialog.show()
            dialog.raise_()
            dialog.activateWindow()
            
            result = dialog.exec()
            print(f">>> Dialog geschlossen mit result={result}")
            if result == QDialog.DialogCode.Accepted:
                new_favorites = dialog.get_favorites()
                if new_favorites is not None:
                    self.favorites = new_favorites
                    self.save_favorites()
                    print(f">>> Favoriten gespeichert: {self.favorites}")
                    # Aktualisiere alle Chart-Dropdowns
                    for chart in self.charts:
                        chart.update_favorites_list(self.favorites)
        except Exception as e:
            print(f"!!! Fehler im Favoriten-Dialog: {e}")
            import traceback
            traceback.print_exc()
    
    def showEvent(self, event):
        super().showEvent(event)
        if hasattr(self, '_about_btn_hd') and hasattr(self, '_r2_end_spacer'):
            from PyQt6.QtCore import QTimer
            # Mehrfach feuern bis Layout stabil ist
            QTimer.singleShot(50,  self._align_r2_to_about)
            QTimer.singleShot(200, self._align_r2_to_about)

    def _align_r2_to_about(self):
        if not hasattr(self, '_about_btn_hd') or not hasattr(self, '_r2_end_spacer'):
            return
        btn = self._about_btn_hd
        spacer = self._r2_end_spacer
        # Rechter Rand von ℹ️Über in globalen Koordinaten
        btn_global_right = btn.mapToGlobal(btn.rect().topRight()).x()
        # Rechter Rand des Spacers in globalen Koordinaten
        spacer_global_right = spacer.mapToGlobal(spacer.rect().topRight()).x()
        diff = btn_global_right - spacer_global_right
        if abs(diff) > 1:
            spacer.setFixedWidth(max(0, spacer.width() + diff))

    def resizeEvent(self, event):
        super().resizeEvent(event)

    def closeEvent(self, event):
        """Wird beim Schließen der App aufgerufen"""
        # Speichere automatisch die letzte Session
        self.save_config()

        # ── Alle laufenden Hintergrund-Worker sauber stoppen ─────────────
        # Verhindert Qt-ABORT wenn Threads noch laufen während Widgets
        # bereits zerstört werden (Signal 6 / SIGABRT)

        # 1. Auto-Refresh Timer stoppen
        try:
            if hasattr(self, 'timer') and self.timer is not None:
                self.timer.stop()
        except Exception:
            pass

        # 2. Portfolio Master-Worker stoppen
        for attr in ('_master_worker', '_overview_worker'):
            try:
                w = getattr(self, attr, None)
                if w is not None and w.isRunning():
                    w.quit()
                    w.wait(1500)
            except Exception:
                pass

        # 3. Alle Chart-Fetch-Worker aus der globalen Registry stoppen
        registry = list(StockChartWidget._worker_registry)
        for w in registry:
            try:
                if w.isRunning():
                    # Signals trennen damit keine Callbacks auf gelöschte Widgets kommen
                    try: w.data_ready.disconnect()
                    except Exception: pass
                    try: w.error.disconnect()
                    except Exception: pass
                    try: w.finished.disconnect()
                    except Exception: pass
                    w.quit()
            except Exception:
                pass
        # Kurz warten bis alle beendet sind (max. 2 Sekunden)
        for w in registry:
            try:
                if w.isRunning():
                    w.wait(2000)
            except Exception:
                pass
        StockChartWidget._worker_registry.clear()

        event.accept()
        
    def refresh_all(self):
        """Alle Charts aktualisieren – mit 5-Sekunden-Cooldown gegen Yahoo-Rate-Limiting."""
        # ── Cooldown: Button für 5 Sekunden deaktivieren ──────────────────
        COOLDOWN_MS = 5000
        btns = getattr(self, '_refresh_all_btns', [])
        for btn in btns:
            try:
                btn.setEnabled(False)
                btn.setText("🔄 Alle (5s…)")
            except RuntimeError:
                pass

        _remaining = [COOLDOWN_MS // 1000]
        _cd_timer = QTimer(self)
        _cd_timer.setInterval(1000)

        def _tick():
            _remaining[0] -= 1
            for b in btns:
                try:
                    if _remaining[0] > 0:
                        b.setText(f"🔄 Alle ({_remaining[0]}s…)")
                    else:
                        _cd_timer.stop()
                        b.setEnabled(True)
                        b.setText("🔄 Alle")
                except RuntimeError:
                    _cd_timer.stop()

        _cd_timer.timeout.connect(_tick)
        _cd_timer.start()

        # ── Eigentliche Aktualisierung ─────────────────────────────────────
        for chart in self.charts:
            chart.update_chart()
    
