    def show_help(self, anchor: str = None, parent_widget=None):
        """Zeige Hilfe-Dialog mit Inhaltsverzeichnis und Sprachumschalter"""
        from PyQt6.QtWidgets import (
            QTextBrowser, QVBoxLayout, QListWidget, QSplitter,
            QLineEdit as _QLE_help, QHBoxLayout as _QHL_help,
            QWidget as _QW_search, QLabel as _QL_search,
            QWidget as _QW_help, QVBoxLayout as _QVL_help,
            QComboBox as _QCB_lang,
        )
        from PyQt6.QtCore import Qt
        from PyQt6.QtGui import QFontDatabase as _QFDB_help, QFont as _QFontToc, QColor as _QColorToc
        from help_texts import get_help
        from config import save_config, get_language

        # ── Current language & help data ──────────────────────────────────
        _current_lang = [get_language()]   # list so closure can mutate it

        def _load_help():
            return get_help(_current_lang[0])

        # Parent: aufrufendes Fenster bevorzugt (bleibt darüber), sonst Hauptfenster
        _dlg_parent = parent_widget if parent_widget is not None else self
        dialog = QDialog(_dlg_parent)
        dialog.setWindowTitle(_load_help()["window_title"])
        # Hilfe-Fenster bleibt immer über dem aufrufenden Fenster
        dialog.setWindowFlags(
            dialog.windowFlags() | Qt.WindowType.WindowStaysOnTopHint
        )
        dialog.setMinimumSize(1000, 720)
        screen = QApplication.primaryScreen().availableGeometry()
        dlg_w = int(screen.width()  * 0.78)
        dlg_h = int(screen.height() * 0.84)
        dialog.resize(dlg_w, dlg_h)
        dialog.move(
            screen.x() + (screen.width()  - dlg_w) // 2,
            screen.y() + (screen.height() - dlg_h) // 2,
        )

        layout = QHBoxLayout()
        splitter = QSplitter(Qt.Orientation.Horizontal)

        # ── Emoji-font detection (same logic as toolbar) ──────────────────
        _ef_help = None
        _available_fonts = _QFDB_help.families()
        for _fc in ['Segoe UI Emoji', 'Noto Color Emoji', 'Apple Color Emoji']:
            if _fc in _available_fonts:
                _ef_help = QFont(_fc, 11)
                break

        # ── Language switcher (top of left panel) ─────────────────────────
        lang_row   = _QW_search()
        lang_row.setMaximumHeight(30)
        lang_hl    = _QHL_help(lang_row)
        lang_hl.setContentsMargins(4, 0, 4, 0)
        lang_hl.setSpacing(4)

        lang_lbl   = _QL_search(_load_help()["lang_label"])
        lang_lbl.setStyleSheet("color:#555; font-size:11px; border:none;")
        lang_combo = _QCB_lang()
        lang_combo.addItem("DE")
        lang_combo.addItem("EN")
        lang_combo.setCurrentText(_current_lang[0])
        lang_combo.setMaximumWidth(60)
        lang_combo.setStyleSheet("font-size:11px;")
        lang_hl.addWidget(lang_lbl)
        lang_hl.addWidget(lang_combo)
        lang_hl.addStretch()

        # ── Search field ──────────────────────────────────────────────────
        _search_row = _QW_search()
        _search_row.setMaximumHeight(32)
        _search_row.setStyleSheet(
            "QWidget { border:1px solid #bbb; border-radius:4px; background:#fff; }"
            "QWidget:focus-within { border-color:#3498db; }"
        )
        _search_hl = _QHL_help(_search_row)
        _search_hl.setContentsMargins(5, 0, 5, 0)
        _search_hl.setSpacing(3)

        _lupe_lbl = _QL_search("🔍")
        _lupe_lbl.setStyleSheet("border:none; background:transparent;")
        if _ef_help:
            _lupe_lbl.setFont(_ef_help)
        _search_hl.addWidget(_lupe_lbl)

        search_box = _QLE_help()
        search_box.setPlaceholderText(_load_help()["search_placeholder"])
        search_box.setStyleSheet(
            "QLineEdit { border:none; background:transparent; font-size:12px; padding:2px 0; }"
        )
        _search_hl.addWidget(search_box, stretch=1)

        # ── TOC list ──────────────────────────────────────────────────────
        toc = QListWidget()

        def _populate_toc(toc_items):
            """Fill (or refill) the TOC widget."""
            toc.clear()
            from PyQt6.QtWidgets import QListWidgetItem as _QLWI
            if _ef_help and _ef_help.family():
                _toc_base_font = _QFontToc(_ef_help.family(), 10)
                toc.setFont(_toc_base_font)
            for _ti in toc_items:
                _item = _QLWI(_ti)
                if _ti.startswith("──"):
                    _item.setFlags(Qt.ItemFlag.NoItemFlags)
                    if _ef_help and _ef_help.family():
                        _fsep = _QFontToc(_ef_help.family(), 8)
                    else:
                        _fsep = _QFontToc()
                        _fsep.setPointSize(8)
                    _fsep.setBold(True)
                    _item.setFont(_fsep)
                    _item.setForeground(_QColorToc("#2c3e50"))
                    _item.setBackground(_QColorToc("#dce8f5"))
                toc.addItem(_item)

        _populate_toc(_load_help()["toc_items"])
        toc.setMaximumWidth(220)

        # ── Search: filter TOC ────────────────────────────────────────────
        def _on_search(text):
            q = text.strip().lower()
            for i in range(toc.count()):
                item = toc.item(i)
                label = item.text()
                is_sep = label.startswith("──")
                if not q:
                    item.setHidden(False)
                elif is_sep:
                    item.setHidden(False)
                else:
                    item.setHidden(q not in label.lower())
            if q:
                last_sep = None
                for i in range(toc.count()):
                    item = toc.item(i)
                    if item.text().startswith("──"):
                        last_sep = item
                        last_sep.setHidden(True)
                    elif not item.isHidden():
                        if last_sep:
                            last_sep.setHidden(False)
                            last_sep = None

        search_box.textChanged.connect(_on_search)

        def _on_search_enter():
            q = search_box.text().strip().lower()
            if not q:
                return
            for i in range(toc.count()):
                item = toc.item(i)
                if not item.isHidden() and not item.text().startswith("──"):
                    toc.setCurrentItem(item)
                    jump_to_section(item)
                    search_box.clearFocus()
                    break

        search_box.returnPressed.connect(_on_search_enter)

        # ── Help text browser ─────────────────────────────────────────────
        help_text = QTextBrowser()
        help_text.setOpenExternalLinks(True)
        help_text.setHtml(_load_help()["html"])

        # ── Jump to anchor ────────────────────────────────────────────────
        def jump_to_section(item):
            raw = item.text()
            if raw.startswith("──"):
                return
            label = raw.strip().lower()
            if not label:
                return
            anchor_map = _load_help()["anchor_map"]
            section = anchor_map.get(label)
            if not section:
                section = (
                    label.replace(" ", "_").replace("(", "").replace(")", "")
                         .replace("&", "").replace("/", "").replace(".", "")
                         .replace(",", "").replace("'", "").replace("→", "")
                )
            help_text.scrollToAnchor(section)

        toc.itemClicked.connect(jump_to_section)

        # ── Language switch handler ───────────────────────────────────────
        def _on_lang_changed(new_lang: str):
            _current_lang[0] = new_lang
            save_config({"language": new_lang})   # persist to ~/.stock_monitor_config.json
            h = _load_help()
            dialog.setWindowTitle(h["window_title"])
            lang_lbl.setText(h["lang_label"])
            search_box.setPlaceholderText(h["search_placeholder"])
            help_text.setHtml(h["html"])
            _populate_toc(h["toc_items"])
            search_box.clear()

        lang_combo.currentTextChanged.connect(_on_lang_changed)

        # ── Assemble left panel ───────────────────────────────────────────
        left_panel = _QW_help()
        left_panel.setMaximumWidth(220)
        left_layout = _QVL_help(left_panel)
        left_layout.setContentsMargins(0, 0, 0, 0)
        left_layout.setSpacing(4)
        left_layout.addWidget(lang_row)
        left_layout.addWidget(_search_row)
        left_layout.addWidget(toc)
        splitter.addWidget(left_panel)
        splitter.addWidget(help_text)

        splitter.setSizes([220, 780])
        layout.addWidget(splitter)
        dialog.setLayout(layout)

        close_btn = QPushButton(TR("btn_close_plain"))
        close_btn.setDefault(False)
        close_btn.setAutoDefault(False)
        close_btn.clicked.connect(dialog.close)
        layout.addWidget(close_btn)

        import sys as _sys_hlp
        if _sys_hlp.platform == 'win32':
            dialog.finished.connect(lambda: (self.raise_(), self.activateWindow()))

        # ── Scroll to anchor if requested ─────────────────────────────────
        if anchor:
            from PyQt6.QtCore import QTimer as _QTimer_help
            _QTimer_help.singleShot(120, lambda: help_text.scrollToAnchor(anchor))

        dialog.exec()

    # ── Update-Prüfung ────────────────────────────────────────────────────────

    def _start_update_worker(self, fn_check, fn_result):
        """Hilfsmethode: startet einen QThread für fn_check(), ruft fn_result(result) im UI-Thread."""
        from PyQt6.QtCore import QThread, pyqtSignal as _sig

        class _W(QThread):
            done = _sig(object)
            def run(self):
                try:
                    self.done.emit(fn_check())
                except Exception:
                    _log.exception("Update-Worker run() fehlgeschlagen")

        worker = _W(self)
        worker.done.connect(fn_result, Qt.ConnectionType.QueuedConnection)
        worker.done.connect(worker.deleteLater)
        if not hasattr(self, '_update_workers'):
            self._update_workers = []
        self._update_workers.append(worker)
        worker.finished.connect(lambda: self._update_workers.remove(worker)
                                if worker in self._update_workers else None)
        worker.start()

    def check_for_updates(self, status_label=None, update_btn=None):
        """Prüft auf neue App-Versionen via GitHub Releases API.
        Wenn status_label/update_btn übergeben → Update im About-Dialog anzeigen.
        Ohne Parameter → eigenständigen Update-Dialog öffnen.
        """
        if status_label:
            status_label.setText(TR("lbl_update_checking_app"))

        def _do_check():
            try:
                import urllib.request, json as _json, ssl
                url = f"https://api.github.com/repos/{GITHUB_REPO}/releases/latest"
                req = urllib.request.Request(url, headers={"User-Agent": "StockMonitor"})
                try:
                    import certifi
                    ctx = ssl.create_default_context(cafile=certifi.where())
                except Exception:
                    ctx = ssl.create_default_context()
                with urllib.request.urlopen(req, timeout=8, context=ctx) as resp:
                    data = _json.loads(resp.read().decode())
                latest = data.get("tag_name", "").lstrip("v")
                if not latest:
                    return "error", APP_VERSION, "", "", ""
                zip_url = ""
                flatpak_url = ""
                for asset in data.get("assets", []):
                    name = asset.get("name", "").lower()
                    dl = asset.get("browser_download_url", "")
                    if name == "stock_monitor.zip":
                        zip_url = dl
                    elif name.endswith(".flatpak"):
                        flatpak_url = dl
                def _vtuple(v):
                    try: return tuple(int(x) for x in v.split("."))
                    except: return (0,)
                if _vtuple(latest) > _vtuple(APP_VERSION):
                    return ("update_available", latest,
                            data.get("html_url") or "",
                            data.get("body") or "",
                            zip_url, flatpak_url)
                return "current", APP_VERSION, "", "", "", ""
            except Exception:
                return "error", APP_VERSION, "", "", "", ""

        def _on_result(result):
            try:
                status, version, url, notes, zip_url, flatpak_url = result
                if status == "update_available":
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#e67e00;'>"
                            + TR("lbl_app_update_available", version=version)
                            + "</span>"
                        )
                    if update_btn:
                        update_btn.setText(f"⬇️ v{version}")
                        update_btn.setEnabled(True)
                        update_btn.setStyleSheet(
                            "QPushButton { background-color: #e67e00; color: white; "
                            "font-weight: bold; border-radius: 6px; padding: 4px 10px; }"
                            "QPushButton:hover { background-color: #cf6d00; }"
                        )
                        try:
                            update_btn.clicked.disconnect()
                        except Exception:
                            pass
                        def _open_release(checked=False, _url=url, _v=version, _n=notes, _z=zip_url, _fz=flatpak_url):
                            self._show_app_update_dialog(_v, _url, _n, _z, _fz)
                        update_btn.clicked.connect(_open_release)
                    # Eigenständiger Dialog (kein status_label von aussen)
                    if not status_label:
                        self._show_app_update_dialog(version, url, notes, zip_url, flatpak_url)
                elif status == "current":
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#27ae60;'>"
                            + TR("lbl_app_update_current", version=version)
                            + "</span>"
                        )
                    if update_btn:
                        update_btn.setEnabled(False)
                else:  # error
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#888;'>{TR('lbl_app_update_error')}</span>"
                        )
            except Exception:
                _log.exception("Update-Check _on_result fehlgeschlagen")

        self._start_update_worker(_do_check, _on_result)

    def _show_app_update_dialog(self, version, url, notes, zip_url="", flatpak_url=""):
        """Zeigt einen Nicht-Blocking-Dialog wenn eine neue App-Version verfügbar ist."""
        dlg = QDialog(self)
        dlg.setWindowTitle(TR("title_update_check"))
        dlg.setFixedWidth(540)
        lay = QVBoxLayout(dlg)
        lay.setSpacing(10)
        lay.setContentsMargins(20, 16, 20, 14)

        title_lbl = QLabel(TR("lbl_app_update_available", version=version))
        title_lbl.setWordWrap(True)
        title_lbl.setStyleSheet("font-size:14px;")
        lay.addWidget(title_lbl)

        if notes and notes.strip():
            notes_hdr = QLabel(f"<b>{TR('lbl_release_notes')}</b>")
            lay.addWidget(notes_hdr)
            from PyQt6.QtWidgets import QScrollArea, QTextEdit
            te = QTextEdit()
            te.setReadOnly(True)
            te.setPlainText(notes.strip())
            te.setMaximumHeight(200)
            lay.addWidget(te)

        _in_flatpak = os.path.exists('/.flatpak-info')
        _is_exe_win = getattr(sys, 'frozen', False) and sys.platform == "win32"

        if _in_flatpak:
            hint_lbl = QLabel(TR("lbl_app_update_flatpak_hint"))
            hint_lbl.setWordWrap(True)
            hint_lbl.setStyleSheet(
                "background:#fff3cd;color:#856404;border:1px solid #ffc107;"
                "border-radius:6px;padding:8px;"
            )
            lay.addWidget(hint_lbl)

        btn_row = QHBoxLayout()
        btn_row.addStretch()
        if _is_exe_win and zip_url:
            auto_btn = QPushButton(TR("btn_auto_update"))
            auto_btn.setStyleSheet(
                "QPushButton{background:#27ae60;color:white;font-weight:bold;"
                "border-radius:6px;padding:4px 14px;}"
                "QPushButton:hover{background:#1e8449;}"
            )
            def _do_auto(checked=False, _v=version, _z=zip_url):
                dlg.close()
                self._do_self_update(_v, _z)
            auto_btn.clicked.connect(_do_auto)
            btn_row.addWidget(auto_btn)
        if _in_flatpak and flatpak_url:
            install_btn = QPushButton(TR("btn_flatpak_install"))
            install_btn.setStyleSheet(
                "QPushButton{background:#27ae60;color:white;font-weight:bold;"
                "border-radius:6px;padding:4px 14px;}"
                "QPushButton:hover{background:#1e8449;}"
            )
            def _do_flatpak(checked=False, _v=version, _fz=flatpak_url):
                dlg.close()
                self._do_flatpak_install(_v, _fz)
            install_btn.clicked.connect(_do_flatpak)
            btn_row.addWidget(install_btn)
        if url:
            open_btn = QPushButton(TR("btn_open_release_page"))
            open_btn.setStyleSheet(
                "QPushButton{background:#1a73e8;color:white;font-weight:bold;"
                "border-radius:6px;padding:4px 14px;}"
                "QPushButton:hover{background:#1557b0;}"
            )
            def _open(checked=False, _url=url):
                import webbrowser; webbrowser.open(_url)
            open_btn.clicked.connect(_open)
            btn_row.addWidget(open_btn)
        countdown_lbl = QLabel()
        countdown_lbl.setStyleSheet("color: #999; font-size: 11px;")
        btn_row.addSpacing(8)
        btn_row.addWidget(countdown_lbl)

        close_btn = QPushButton(TR("btn_close_plain"))
        close_btn.clicked.connect(dlg.close)
        btn_row.addWidget(close_btn)
        lay.addLayout(btn_row)

        # Countdown-Timer: schließt automatisch nach 10 Sekunden
        _remaining = [10]
        def _tick():
            try:
                if not dlg.isVisible():
                    return
                countdown_lbl.setText(f"({_remaining[0]}s)")
                if _remaining[0] <= 0:
                    dlg.close()
                    return
                _remaining[0] -= 1
                QTimer.singleShot(1000, _tick)
            except RuntimeError:
                pass
        QTimer.singleShot(1000, _tick)

        dlg.setWindowModality(Qt.WindowModality.ApplicationModal)
        # Zentrieren: erst adjustSize damit Höhe bekannt, dann verschieben, dann anzeigen
        dlg.adjustSize()
        _screen = self.screen() or QApplication.primaryScreen()
        if _screen:
            _sg = _screen.availableGeometry()
            dlg.move(
                _sg.center().x() - dlg.width() // 2,
                _sg.center().y() - dlg.height() // 2
            )
        dlg.show()
        dlg.raise_()
        dlg.activateWindow()
        QApplication.setActiveWindow(dlg)

    def _do_flatpak_install(self, version, flatpak_url):
        """Lädt die .flatpak-Datei nach ~/Downloads und installiert sie direkt."""
        import subprocess, threading

        prog_dlg = QDialog(self)
        prog_dlg.setWindowTitle(TR("title_flatpak_install"))
        prog_dlg.setFixedWidth(420)
        prog_dlg.setWindowModality(Qt.WindowModality.ApplicationModal)
        lay = QVBoxLayout(prog_dlg)
        lay.setContentsMargins(20, 16, 20, 14)
        lay.setSpacing(10)
        msg_lbl = QLabel(TR("lbl_flatpak_downloading", version=version))
        msg_lbl.setWordWrap(True)
        lay.addWidget(msg_lbl)
        from PyQt6.QtWidgets import QProgressBar
        prog = QProgressBar()
        prog.setRange(0, 0)
        lay.addWidget(prog)
        prog_dlg.show()

        def _run():
            try:
                downloads = os.path.join(os.path.expanduser("~"), "Downloads")
                os.makedirs(downloads, exist_ok=True)
                fname = f"StockMonitor-{version}.flatpak"
                fpath = os.path.join(downloads, fname)
                # Download via host curl (umgeht Sandbox-SSL-Probleme)
                dl = subprocess.run(
                    ['flatpak-spawn', '--host', 'curl', '-L', '--fail',
                     '-o', fpath, flatpak_url],
                    capture_output=True, text=True, timeout=600
                )
                if dl.returncode != 0:
                    QTimer.singleShot(0, lambda e=(dl.stderr or dl.stdout or "curl error").strip(): _on_error(e))
                    return
                result = subprocess.run(
                    ['flatpak-spawn', '--host', 'flatpak', 'install',
                     '--user', '--bundle', '--assumeyes', '--noninteractive', fpath],
                    capture_output=True, text=True, timeout=300
                )
                if result.returncode == 0:
                    QTimer.singleShot(0, lambda: _on_success())
                else:
                    QTimer.singleShot(0, lambda: _on_error(
                        (result.stderr or result.stdout or "").strip()))
            except Exception as e:
                QTimer.singleShot(0, lambda e=str(e): _on_error(e))

        def _on_success():
            prog_dlg.close()
            from PyQt6.QtWidgets import QMessageBox
            mb = QMessageBox(self)
            mb.setWindowTitle(TR("title_flatpak_install"))
            mb.setText(TR("lbl_flatpak_install_done", version=version))
            mb.setIcon(QMessageBox.Icon.Information)
            mb.exec()

        def _on_error(err):
            prog_dlg.close()
            from PyQt6.QtWidgets import QMessageBox
            mb = QMessageBox(self)
            mb.setWindowTitle(TR("title_flatpak_install"))
            mb.setText(TR("lbl_flatpak_install_error") + f"\n\n{err}")
            mb.setIcon(QMessageBox.Icon.Warning)
            mb.exec()

        threading.Thread(target=_run, daemon=True).start()

    def _get_yfinance_installed_version(self) -> str:
        """Gibt die tatsächlich installierte yfinance-Version zurück.
        Im EXE-Modus: liest aus dist-info auf Disk (importlib.metadata ist eingefroren).
        """
        if getattr(sys, 'frozen', False):
            try:
                import glob as _glob
                _internal = os.path.dirname(os.path.abspath(yf.__file__))
                _internal = os.path.dirname(_internal)
                _best = (0,)
                _best_v = None
                for _di in _glob.glob(os.path.join(_internal, "yfinance-*.dist-info")):
                    _meta = os.path.join(_di, "METADATA")
                    if os.path.exists(_meta):
                        try:
                            with open(_meta, "r", encoding="utf-8", errors="ignore") as _f:
                                for _line in _f:
                                    if _line.startswith("Version:"):
                                        _v = _line.split(":", 1)[1].strip()
                                        _vt = tuple(int(x) for x in _v.split(".") if x.isdigit())
                                        if _vt > _best:
                                            _best = _vt
                                            _best_v = _v
                                        break
                        except Exception:
                            pass
                if _best_v:
                    return _best_v
            except Exception:
                pass
        try:
            return yf.__version__
        except Exception:
            return "?"

    def check_yfinance_update(self, status_label=None, silent=True):
        """Prüft ob eine neuere yfinance-Version auf PyPI verfügbar ist.
        silent=True → nur Toast-Notification bei Update; False → immer Statusmeldung.
        """
        if status_label:
            status_label.setText(TR("lbl_update_checking_yf"))

        def _do_check():
            try:
                installed = self._get_yfinance_installed_version()
            except Exception:
                return "error", "", "", ""
            try:
                import urllib.request, json as _json, ssl
                req = urllib.request.Request(
                    "https://pypi.org/pypi/yfinance/json",
                    headers={"User-Agent": "StockMonitor"})
                try:
                    import certifi
                    ctx = ssl.create_default_context(cafile=certifi.where())
                except Exception:
                    ctx = ssl.create_default_context()
                with urllib.request.urlopen(req, timeout=8, context=ctx) as resp:
                    data = _json.loads(resp.read().decode())
                latest = data.get("info", {}).get("version", "")
                if not latest:
                    return "error", installed, "", ""
                wheel_url = ""
                for pkg in data.get("urls", []):
                    if pkg.get("packagetype") == "bdist_wheel" and "none-any" in pkg.get("filename", ""):
                        wheel_url = pkg.get("url", "")
                        break
                # Versions-Vergleich: tuple-basiert damit "0.2.50" > "0.2.9" korrekt
                def _vtuple(v):
                    try:
                        return tuple(int(x) for x in v.split("."))
                    except Exception:
                        return (0,)
                if _vtuple(latest) > _vtuple(installed):
                    return "update_available", installed, latest, wheel_url
                return "current", installed, latest, ""
            except Exception:
                return "error", installed, "", ""

        def _on_result(result):
            try:
                status, installed, latest, wheel_url = result
                if status == "update_available":
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#e67e00;'>"
                            + TR("lbl_yf_update_available", latest=latest, installed=installed)
                            + "</span>"
                        )
                    elif silent:
                        # Toast-Notification (nicht-blockierend)
                        self._show_yfinance_toast(installed, latest, wheel_url)
                elif status == "current":
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#27ae60;'>"
                            + TR("lbl_yf_update_current", version=installed)
                            + "</span>"
                        )
                    elif not silent:
                        pass  # Keine Notification wenn alles aktuell ist
                else:  # error
                    if status_label:
                        status_label.setText(
                            f"<span style='color:#888;'>{TR('lbl_yf_update_error')}</span>"
                        )
            except Exception:
                _log.exception("yfinance Update-Check _on_result fehlgeschlagen")

        self._start_update_worker(_do_check, _on_result)

